INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Which of the following best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (2, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'Which option Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (3, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'What type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (4, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'Identify the best choice is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (5, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'Select the correct answer is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Choose the statement dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Pick the option practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (8, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'From the options below, which evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (9, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'In this scenario, which scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (10, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Among these, which Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (11, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'Which of the following should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (12, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'Which option capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (13, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'What feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (14, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Identify the best choice Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (15, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'Select the correct answer capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (16, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Choose the statement capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (17, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Pick the option feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (18, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'From the options below, which feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (19, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'In this scenario, which is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (20, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Among these, which Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (21, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Which of the following capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (22, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'Which option approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (23, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'What capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (24, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Identify the best choice practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (25, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Select the correct answer term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (26, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Choose the statement learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (27, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Pick the option split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (28, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'From the options below, which feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (29, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'In this scenario, which practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (30, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Among these, which service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (31, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which of the following capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (32, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'Which option approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (33, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'What term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (34, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'Identify the best choice tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (35, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Select the correct answer service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (36, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Choose the statement Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (37, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Pick the option policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (38, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'From the options below, which best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (39, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'In this scenario, which Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (40, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'Among these, which type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (41, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'Which of the following is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (42, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'Which option is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (43, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'What dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (44, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Identify the best choice practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (45, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'Select the correct answer evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (46, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Choose the statement scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (47, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Pick the option Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (48, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'From the options below, which should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (49, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'In this scenario, which capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (50, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'Among these, which feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (51, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Which of the following Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (52, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'Which option capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (53, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'What capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (54, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Identify the best choice feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (55, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Select the correct answer feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (56, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'Choose the statement is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (57, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Pick the option Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (58, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'From the options below, which capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (59, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'In this scenario, which approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (60, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Among these, which capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (61, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Which of the following practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (62, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Which option term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (63, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'What learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (64, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Identify the best choice split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (65, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Select the correct answer feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (66, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'Choose the statement practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (67, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Pick the option service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (68, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'From the options below, which capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (69, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'In this scenario, which approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (70, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Among these, which term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (71, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'Which of the following tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (72, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Which option service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (73, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'What Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (74, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Identify the best choice policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (75, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Select the correct answer best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (76, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'Choose the statement Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (77, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'Pick the option type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (78, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'From the options below, which is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (79, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'In this scenario, which is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (80, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Among these, which dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (81, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Which of the following practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (82, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'Which option evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (83, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'What scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (84, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Identify the best choice Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (85, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'Select the correct answer should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (86, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'Choose the statement capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (87, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'Pick the option feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (88, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'From the options below, which Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (89, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'In this scenario, which capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (90, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Among these, which capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (91, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which of the following feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (92, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Which option feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (93, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'What is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (94, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Identify the best choice Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (95, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Select the correct answer capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (96, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'Choose the statement approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (97, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Pick the option capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (98, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'From the options below, which practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (99, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'In this scenario, which term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (100, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Among these, which learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (101, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Which of the following split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (102, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Which option feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (103, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'What practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (104, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Identify the best choice service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (105, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Select the correct answer capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (106, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'Choose the statement approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (107, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Pick the option term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (108, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'From the options below, which tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (109, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'In this scenario, which service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (110, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Among these, which Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (111, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Which of the following policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (112, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Which option best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (113, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'What Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (114, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'Identify the best choice type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (115, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'Select the correct answer is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (116, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'Choose the statement is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (117, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Pick the option dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (118, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'From the options below, which practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (119, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'In this scenario, which evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (120, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Among these, which scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (121, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Which of the following Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (122, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'Which option should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (123, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'What capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (124, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'Identify the best choice feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (125, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Select the correct answer Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (126, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'Choose the statement capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (127, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Pick the option capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (128, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'From the options below, which feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (129, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'In this scenario, which feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (130, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'Among these, which is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (131, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Which of the following Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (132, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Which option capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (133, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'What approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (134, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Identify the best choice capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (135, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Select the correct answer practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (136, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Choose the statement term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (137, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Pick the option learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (138, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'From the options below, which split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (139, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'In this scenario, which feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (140, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'Among these, which practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (141, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which of the following service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (142, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which option capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (143, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'What approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (144, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Identify the best choice term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (145, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'Select the correct answer tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (146, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Choose the statement service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (147, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Pick the option Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (148, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'From the options below, which policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (149, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'In this scenario, which best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (150, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'Among these, which Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (151, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'Which of the following type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (152, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'Which option is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (153, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'What is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (154, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Identify the best choice dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (155, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Select the correct answer practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (156, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'Choose the statement evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (157, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Pick the option scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (158, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'From the options below, which Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (159, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'In this scenario, which should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (160, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'Among these, which capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (161, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'Which of the following feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (162, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Which option Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (163, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'What capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (164, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Identify the best choice capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (165, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Select the correct answer feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (166, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Choose the statement feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (167, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'Pick the option is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (168, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'From the options below, which Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (169, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'In this scenario, which capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (170, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'Among these, which approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (171, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which of the following capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (172, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Which option practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (173, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'What term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (174, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Identify the best choice learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (175, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Select the correct answer split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (176, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Choose the statement feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (177, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'Pick the option practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (178, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'From the options below, which service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (179, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'In this scenario, which capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (180, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'Among these, which approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (181, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Which of the following term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (182, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'Which option tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (183, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'What service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (184, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Identify the best choice Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (185, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Select the correct answer policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (186, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Choose the statement best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (187, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'Pick the option Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (188, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'From the options below, which type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (189, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'In this scenario, which is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (190, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'Among these, which is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (191, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Which of the following dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (192, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Which option practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (193, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'What evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (194, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Identify the best choice scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (195, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Select the correct answer Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (196, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'Choose the statement should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (197, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'Pick the option capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (198, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'From the options below, which feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (199, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'In this scenario, which Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (200, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'Among these, which capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (201, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which of the following capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (202, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which option feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (203, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'What feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (204, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'Identify the best choice is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (205, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Select the correct answer Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (206, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Choose the statement capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (207, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'Pick the option approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (208, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'From the options below, which capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (209, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'In this scenario, which practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (210, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Among these, which term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (211, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Which of the following learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (212, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Which option split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (213, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'What feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (214, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'Identify the best choice practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (215, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Select the correct answer service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (216, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Choose the statement capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (217, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'Pick the option approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (218, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'From the options below, which term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (219, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'In this scenario, which tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (220, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Among these, which service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (221, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Which of the following Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (222, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Which option policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (223, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'What best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (224, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'Identify the best choice Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (225, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'Select the correct answer type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (226, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'Choose the statement is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (227, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'Pick the option is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (228, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'From the options below, which dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (229, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'In this scenario, which practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (230, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'Among these, which evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (231, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Which of the following scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (232, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Which option Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (233, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'What should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (234, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'Identify the best choice capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (235, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'Select the correct answer feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (236, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Choose the statement Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (237, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'Pick the option capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (238, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'From the options below, which capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (239, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'In this scenario, which feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (240, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Among these, which feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (241, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'Which of the following is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (242, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Which option Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (243, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'What capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (244, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'Identify the best choice approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (245, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Select the correct answer capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (246, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Choose the statement practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (247, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Pick the option term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (248, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'From the options below, which learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (249, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'In this scenario, which split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (250, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Among these, which feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (251, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'Which of the following practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (252, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which option service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (253, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'What capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (254, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'Identify the best choice approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (255, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Select the correct answer term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (256, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'Choose the statement tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (257, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Pick the option service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (258, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'From the options below, which Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (259, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'In this scenario, which policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (260, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Among these, which best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (261, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'Which of the following Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (262, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'Which option type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (263, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'What is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (264, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'Identify the best choice is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (265, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Select the correct answer dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (266, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Choose the statement practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (267, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'Pick the option evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (268, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'From the options below, which scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (269, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'In this scenario, which Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (270, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'Among these, which should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (271, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'Which of the following capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (272, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'Which option feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (273, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'What Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (274, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'Identify the best choice capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (275, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Select the correct answer capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (276, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Choose the statement feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (277, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Pick the option feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (278, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'From the options below, which is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (279, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'In this scenario, which Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (280, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Among these, which capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (281, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'Which of the following approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (282, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which option capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (283, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'What practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (284, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Identify the best choice term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (285, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Select the correct answer learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (286, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Choose the statement split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (287, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Pick the option feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (288, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'From the options below, which practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (289, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'In this scenario, which service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (290, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Among these, which capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (291, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'Which of the following approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (292, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Which option term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (293, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'What tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (294, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Identify the best choice service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (295, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Select the correct answer Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (296, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Choose the statement policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (297, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Pick the option best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (298, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'From the options below, which Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (299, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'In this scenario, which type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (300, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'Among these, which is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (301, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'Which of the following is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (302, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Which option dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (303, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'What practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (304, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'Identify the best choice evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (305, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Select the correct answer scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (306, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Choose the statement Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (307, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'Pick the option should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (308, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'From the options below, which capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (309, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'In this scenario, which feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (310, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Among these, which Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (311, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'Which of the following capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (312, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Which option capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (313, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'What feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (314, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Identify the best choice feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (315, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'Select the correct answer is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (316, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Choose the statement Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (317, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Pick the option capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (318, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'From the options below, which approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (319, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'In this scenario, which capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (320, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Among these, which practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (321, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Which of the following term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (322, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Which option learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (323, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'What split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (324, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Identify the best choice feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (325, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'Select the correct answer practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (326, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Choose the statement service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (327, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Pick the option capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (328, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'From the options below, which approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (329, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'In this scenario, which term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (330, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'Among these, which tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (331, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Which of the following service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (332, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Which option Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (333, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'What policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (334, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Identify the best choice best describes supervised learning?', '["Learning from labeled examples to predict outcomes","Learning by trial and error via rewards","Discovering patterns in unlabeled data","Translating text between languages"]', '[0]', 'Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.', '{"correct":"Supervised learning uses labeled datasets to learn input-output mappings for classification or regression.","why_others_wrong":{"1":"Unsupervised learning finds structure without labels such as clusters.","2":"Translation is a task leveraging language models, not a learning paradigm.","3":"Translation is a task leveraging language models, not a learning paradigm."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (335, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'easy', 'Select the correct answer Responsible AI principle focuses on ensuring systems work as intended and can be trusted?', '["Fairness","Reliability and safety","Inclusiveness","Transparency"]', '[1]', 'Reliability and safety ensure AI systems perform as expected and fail gracefully.', '{"correct":"Reliability and safety ensure AI systems perform as expected and fail gracefully.","why_others_wrong":{"0":"Fairness addresses bias and equitable outcomes.","2":"Transparency emphasizes explainability and disclosure.","3":"Transparency emphasizes explainability and disclosure."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (336, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'easy', 'Choose the statement type of machine learning predicts a continuous value?', '["Classification","Regression","Clustering","Reinforcement learning"]', '[1]', 'Regression predicts continuous numeric values.', '{"correct":"Regression predicts continuous numeric values.","why_others_wrong":{"0":"Classification predicts discrete categories, not continuous values.","2":"Reinforcement learning optimizes actions via rewards.","3":"Reinforcement learning optimizes actions via rewards."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (337, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'medium', 'Pick the option is the primary benefit of Automated ML (AutoML) in Azure ML?', '["Building data lakes","Selecting algorithms and tuning hyperparameters","Deploying Kubernetes clusters","Designing user interfaces"]', '[1]', 'AutoML automates model selection and hyperparameter tuning for supported tasks.', '{"correct":"AutoML automates model selection and hyperparameter tuning for supported tasks.","why_others_wrong":{"0":"Data lakes concern storage architectures, not AutoML.","2":"UI design is unrelated to Azure ML.","3":"UI design is unrelated to Azure ML."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (338, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Operations', 'single', 'medium', 'From the options below, which is the main purpose of a compute cluster in Azure ML?', '["Serve as a data labeling tool","Provide scalable compute for training and batch inference","Host a website","Manage Azure DevOps pipelines"]', '[1]', 'Compute clusters scale nodes to run training and batch workloads efficiently.', '{"correct":"Compute clusters scale nodes to run training and batch workloads efficiently.","why_others_wrong":{"0":"Labeling tools are separate; clusters run workloads.","2":"DevOps pipelines are separate from Azure ML compute.","3":"DevOps pipelines are separate from Azure ML compute."}}', '{"title":"Compute targets in Azure ML","url":"https://learn.microsoft.com/azure/machine-learning/concept-compute-target"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (339, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'In this scenario, which dataset split helps tune models and prevent overfitting before final testing?', '["Training set","Validation set","Test set","Production logs"]', '[1]', 'Validation sets guide hyperparameter tuning prior to final test evaluation.', '{"correct":"Validation sets guide hyperparameter tuning prior to final test evaluation.","why_others_wrong":{"0":"The training set is used to fit parameters.","2":"Logs are operational, not for training.","3":"Logs are operational, not for training."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (340, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'single', 'medium', 'Among these, which practice helps reduce overfitting and improve generalization?', '["Using an excessively complex model","Applying regularization and cross-validation","Merging train and test sets","Training on noisy labels intentionally"]', '[1]', 'Regularization and cross-validation reduce overfitting and improve generalization.', '{"correct":"Regularization and cross-validation reduce overfitting and improve generalization.","why_others_wrong":{"0":"Increasing complexity often worsens overfitting.","2":"Noisy labels degrade model quality.","3":"Noisy labels degrade model quality."}}', '{"title":"Overfitting and model generalization","url":"https://learn.microsoft.com/azure/machine-learning/concept-model-generalization-overfitting"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (341, 'ai-900', 'ai-900-machine-learning', 'Azure Machine Learning', 'ML Concepts', 'multiple', 'difficult', 'Which of the following evaluation metrics are most appropriate to assess an imbalanced binary classifier? (Choose two)', '["Precision","Recall","Accuracy","RMSE"]', '[0,1]', 'Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.', '{"correct":"Precision and recall are robust for imbalance; accuracy can be misleading; RMSE is for regression.","why_others_wrong":{"2":"RMSE is not used for classification tasks.","3":"RMSE is not used for classification tasks."}}', '{"title":"Classification evaluation metrics","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml#classification-metrics"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (342, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Which option scenario best represents a typical machine learning prediction task?', '["Transcribing live speech to text","Grouping unlabeled customers by behavior","Predicting next month’s sales based on history","Translating text from English to Spanish"]', '[2]', 'Predicting a future numeric value based on historical data is a classical ML task.', '{"correct":"Predicting a future numeric value based on historical data is a classical ML task.","why_others_wrong":{"0":"Speech-to-text is a speech service capability.","1":"Clustering is unsupervised grouping without a predictive target.","3":"Translation is a language service capability."}}', '{"title":"What is Azure Machine Learning?","url":"https://learn.microsoft.com/azure/machine-learning/overview-what-is-azure-machine-learning"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (343, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'What Azure AI service extracts printed or handwritten text from images and documents?', '["Custom Vision","Read (OCR) in Computer Vision","Face API","Azure AI Search"]', '[1]', 'The Read OCR capability extracts text from images and PDFs.', '{"correct":"The Read OCR capability extracts text from images and PDFs.","why_others_wrong":{"0":"Custom Vision trains custom image classifiers/detectors, not OCR.","2":"Azure AI Search indexes content; it does not perform OCR.","3":"Azure AI Search indexes content; it does not perform OCR."}}', '{"title":"Read API (OCR) in Computer Vision","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/overview-ocr"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (344, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'medium', 'Identify the best choice should you choose Custom Vision over prebuilt Computer Vision models?', '["For generic object detection supported by prebuilt models","For domain-specific objects not covered by prebuilt models","For pure OCR tasks","For face verification only"]', '[1]', 'Custom Vision is for training domain-specific classifiers or detectors using labeled images.', '{"correct":"Custom Vision is for training domain-specific classifiers or detectors using labeled images.","why_others_wrong":{"0":"Prebuilt models often cover generic objects.","2":"Face verification is handled by Face API.","3":"Face verification is handled by Face API."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (345, 'ai-900', 'ai-900-computer-vision', 'Face API', 'Vision Services', 'single', 'medium', 'Select the correct answer capability is provided by Face API?', '["Pose estimation of full body","Face detection and attributes","3D object reconstruction","Optical character recognition"]', '[1]', 'Face API detects faces and can return attributes such as emotion and landmarks.', '{"correct":"Face API detects faces and can return attributes such as emotion and landmarks.","why_others_wrong":{"0":"Pose estimation is not the Face API’s focus at AI-900 level.","2":"OCR is a Computer Vision Read capability.","3":"OCR is a Computer Vision Read capability."}}', '{"title":"Face service overview","url":"https://learn.microsoft.com/azure/ai-services/face/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (346, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'medium', 'Choose the statement feature detects objects and returns bounding boxes and labels?', '["Image captioning","OCR","Object detection","Face identification"]', '[2]', 'Object detection returns coordinates and class labels for detected instances.', '{"correct":"Object detection returns coordinates and class labels for detected instances.","why_others_wrong":{"0":"Captioning describes an image, not bounding boxes.","1":"OCR extracts text.","3":"Face identification is face-specific, not general object detection."}}', '{"title":"Object detection with Custom Vision","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/object-detection-overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (347, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Pick the option Text Analytics feature identifies the overall tone of a document?', '["Key phrase extraction","Sentiment analysis","Entity recognition","Language detection"]', '[1]', 'Sentiment analysis classifies text as positive, negative, mixed, or neutral.', '{"correct":"Sentiment analysis classifies text as positive, negative, mixed, or neutral.","why_others_wrong":{"0":"Key phrases surface important terms, not sentiment.","2":"Language detection identifies the language, not sentiment.","3":"Language detection identifies the language, not sentiment."}}', '{"title":"Sentiment analysis overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/sentiment-opinion-mining/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (348, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'multiple', 'medium', 'From the options below, which capabilities are provided by Text Analytics? (Choose two)', '["Sentiment analysis","Entity recognition","Speech synthesis","Form recognition"]', '[0,1]', 'Text Analytics includes sentiment and NER among other capabilities.', '{"correct":"Text Analytics includes sentiment and NER among other capabilities.","why_others_wrong":{"2":"Form recognition belongs to Document Intelligence.","3":"Form recognition belongs to Document Intelligence."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (349, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'In this scenario, which capability extracts names of people, organizations, and locations from text?', '["Sentiment analysis","Entity recognition","Topic modeling","Key phrase extraction"]', '[1]', 'NER identifies and classifies named entities in text.', '{"correct":"NER identifies and classifies named entities in text.","why_others_wrong":{"0":"Sentiment focuses on polarity, not entities.","2":"Key phrases are important terms, not entities.","3":"Key phrases are important terms, not entities."}}', '{"title":"Named Entity Recognition","url":"https://learn.microsoft.com/azure/ai-services/language-service/named-entity-recognition/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (350, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Among these, which feature redacts sensitive information such as credit card numbers and phone numbers?', '["Key phrase extraction","PII detection","Entity linking","QnA Maker"]', '[1]', 'PII detection identifies and optionally redacts sensitive entities in text.', '{"correct":"PII detection identifies and optionally redacts sensitive entities in text.","why_others_wrong":{"0":"Key phrases extract salient terms, not necessarily sensitive data.","2":"QnA Maker is a question answering service (now part of Language Service).","3":"QnA Maker is a question answering service (now part of Language Service)."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (351, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'Which of the following feature identifies the language of a text document?', '["Sentiment analysis","Language detection","Entity recognition","Text summarization"]', '[1]', 'Language detection predicts the primary language of input text.', '{"correct":"Language detection predicts the primary language of input text.","why_others_wrong":{"0":"Sentiment predicts tone, not language.","2":"Summarization condenses content.","3":"Summarization condenses content."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (352, 'ai-900', 'ai-900-nlp', 'Language Studio', 'Language Services', 'single', 'easy', 'Which option is Language Studio primarily used for?', '["Building and testing language capabilities via a web portal","Managing AKS clusters","Authoring Power Apps","Monitoring virtual machines"]', '[0]', 'Language Studio is a web portal for trying and evaluating language features.', '{"correct":"Language Studio is a web portal for trying and evaluating language features.","why_others_wrong":{"1":"Power Apps is a low-code platform.","2":"VM monitoring uses Azure Monitor.","3":"VM monitoring uses Azure Monitor."}}', '{"title":"Language Studio","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-studio"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (353, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'What Speech service feature converts spoken audio to text in real time?', '["Speech synthesis","Speech translation","Speech-to-text (recognition)","Custom neural voice"]', '[2]', 'Speech-to-text converts audio into text in near real time.', '{"correct":"Speech-to-text converts audio into text in near real time.","why_others_wrong":{"0":"Synthesis converts text to speech.","1":"Translation converts speech between languages, not just transcription.","3":"Custom Neural Voice is for TTS voice creation."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (354, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'medium', 'Identify the best choice capability converts text to natural-sounding speech?', '["Speech-to-text","Speech translation","Text-to-speech (synthesis)","Entity recognition"]', '[2]', 'Text-to-speech converts text to audio using neural voices.', '{"correct":"Text-to-speech converts text to audio using neural voices.","why_others_wrong":{"0":"Speech-to-text transcribes audio to text.","1":"Translation converts across languages.","3":"NER is an NLP text capability."}}', '{"title":"Text to speech","url":"https://learn.microsoft.com/azure/ai-services/speech-service/text-to-speech"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (355, 'ai-900', 'ai-900-nlp', 'Speech Services', 'Speech', 'single', 'difficult', 'Select the correct answer approach lowers latency for real-time transcription?', '["Batch transcription","Streaming speech-to-text using WebSockets","Asynchronous job submission","Emailing audio files"]', '[1]', 'Streaming APIs deliver partial and final results with low latency.', '{"correct":"Streaming APIs deliver partial and final results with low latency.","why_others_wrong":{"0":"Batch is for offline processing.","2":"Email is not a valid interface for transcription.","3":"Email is not a valid interface for transcription."}}', '{"title":"Speech to text","url":"https://learn.microsoft.com/azure/ai-services/speech-service/speech-to-text"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (356, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Choose the statement capability condenses long documents into concise summaries?', '["Language detection","Text summarization","Key phrase extraction","Entity recognition"]', '[1]', 'Summarization condenses content to a shorter form preserving key ideas.', '{"correct":"Summarization condenses content to a shorter form preserving key ideas.","why_others_wrong":{"0":"Language detection identifies language, not content reduction.","2":"NER extracts entities, not summaries.","3":"NER extracts entities, not summaries."}}', '{"title":"Text summarization","url":"https://learn.microsoft.com/azure/ai-services/language-service/summarization/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (357, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Pick the option practice helps mitigate bias in training data?', '["Collect data from a single demographic","Audit datasets for representation and labeling quality","Randomly drop records without analysis","Merge training and test datasets"]', '[1]', 'Bias mitigation starts with representative, well-labeled datasets audited for quality.', '{"correct":"Bias mitigation starts with representative, well-labeled datasets audited for quality.","why_others_wrong":{"0":"Single-demographic data increases bias risk.","2":"Merging sets causes leakage and invalid evaluation.","3":"Merging sets causes leakage and invalid evaluation."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (358, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'From the options below, which term describes the input variables used by a model to make predictions?', '["Label","Feature","Inference","Endpoint"]', '[1]', 'Features are the input variables; labels are the target outputs in supervised learning.', '{"correct":"Features are the input variables; labels are the target outputs in supervised learning.","why_others_wrong":{"0":"Label is the target output.","2":"Endpoint is a deployment artifact.","3":"Endpoint is a deployment artifact."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (359, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'In this scenario, which learning paradigm optimizes actions through rewards and penalties?', '["Supervised learning","Unsupervised learning","Reinforcement learning","Transfer learning"]', '[2]', 'Reinforcement learning trains agents via reward signals to learn optimal policies.', '{"correct":"Reinforcement learning trains agents via reward signals to learn optimal policies.","why_others_wrong":{"0":"Supervised uses labeled examples.","1":"Unsupervised discovers patterns without labels.","3":"Transfer learning reuses knowledge from related tasks."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (360, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'Among these, which split is used for the final unbiased evaluation of a trained model?', '["Training set","Validation set","Test set","Exploratory set"]', '[2]', 'The test set is strictly held out for final performance estimation.', '{"correct":"The test set is strictly held out for final performance estimation.","why_others_wrong":{"0":"Training is used for fitting the model.","1":"Validation is used for tuning.","3":"Exploratory set is not a standard split."}}', '{"title":"Train/validate/test split","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-validate-test"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (361, 'ai-900', 'ai-900-computer-vision', 'Computer Vision', 'Vision Services', 'single', 'easy', 'Which of the following feature generates a natural-language description of an image?', '["OCR","Image captioning","Face identification","Brand detection"]', '[1]', 'Image captioning describes images in natural language.', '{"correct":"Image captioning describes images in natural language.","why_others_wrong":{"0":"OCR extracts text from images.","2":"Brand detection recognizes logos/brands.","3":"Brand detection recognizes logos/brands."}}', '{"title":"Image analysis","url":"https://learn.microsoft.com/azure/ai-services/computer-vision/concept-image-analysis"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (362, 'ai-900', 'ai-900-computer-vision', 'Custom Vision', 'Vision Services', 'single', 'difficult', 'Which option practice improves a Custom Vision classifier’s generalization?', '["Use only images with the same background","Collect varied images per class across lighting and backgrounds","Train with as few images as possible","Use only synthetic images"]', '[1]', 'Diverse, representative images per class improve robustness and reduce overfitting.', '{"correct":"Diverse, representative images per class improve robustness and reduce overfitting.","why_others_wrong":{"0":"Uniform backgrounds reduce generalization.","2":"Synthetic data helps but should complement real data.","3":"Synthetic data helps but should complement real data."}}', '{"title":"Custom Vision overview","url":"https://learn.microsoft.com/azure/ai-services/custom-vision-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (363, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'What service would you choose to detect and redact sensitive information in documents?', '["Azure OpenAI","PII detection in Text Analytics","Custom Vision","Face API"]', '[1]', 'PII detection identifies sensitive entities such as credit card numbers or phone numbers.', '{"correct":"PII detection identifies sensitive entities such as credit card numbers or phone numbers.","why_others_wrong":{"0":"Azure OpenAI provides generative models but not built-in PII detection for text analytics pipelines.","2":"Face API is for faces in images and video.","3":"Face API is for faces in images and video."}}', '{"title":"PII detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (364, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'medium', 'Identify the best choice capability identifies the key topics or important terms within a document?', '["Key phrase extraction","Language detection","Entity recognition","Speech recognition"]', '[0]', 'Key phrase extraction surfaces important terms.', '{"correct":"Key phrase extraction surfaces important terms.","why_others_wrong":{"1":"NER extracts named entities, not arbitrary key phrases.","2":"Speech recognition is speech-to-text, not text analytics.","3":"Speech recognition is speech-to-text, not text analytics."}}', '{"title":"Text Analytics overview","url":"https://learn.microsoft.com/azure/ai-services/language-service/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (365, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'difficult', 'Select the correct answer approach best supports transparency for an AI system making eligibility decisions?', '["Do not disclose model details","Provide user-facing explanations and documentation of limitations","Enable black-box optimization","Collect less data"]', '[1]', 'Transparency requires communicating how decisions are made, limitations, and user recourse.', '{"correct":"Transparency requires communicating how decisions are made, limitations, and user recourse.","why_others_wrong":{"0":"Withholding details reduces transparency.","2":"Data minimization is privacy-related, not transparency.","3":"Data minimization is privacy-related, not transparency."}}', '{"title":"Microsoft Responsible AI principles","url":"https://learn.microsoft.com/azure/architecture/guide/responsible-innovation/responsible-ai"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (366, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'easy', 'Choose the statement term describes the target value the model is trained to predict?', '["Label","Feature","Noise","Baseline"]', '[0]', 'The label is the ground truth output in supervised learning.', '{"correct":"The label is the ground truth output in supervised learning.","why_others_wrong":{"1":"Noise refers to random variation in data.","2":"Baseline is a simple reference model.","3":"Baseline is a simple reference model."}}', '{"title":"Supervised vs unsupervised learning","url":"https://learn.microsoft.com/training/modules/fundamentals-machine-learning/"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (367, 'ai-900', 'ai-900-machine-learning', 'Automated ML', 'Azure ML', 'single', 'difficult', 'Pick the option tasks are supported by Azure Automated ML?', '["Classification, regression, and time-series forecasting","Clustering and dimensionality reduction","Reinforcement learning","Neural architecture search for NLP"]', '[0]', 'AutoML supports supervised tasks and forecasting.', '{"correct":"AutoML supports supervised tasks and forecasting.","why_others_wrong":{"1":"Reinforcement learning is not supported by Azure AutoML.","2":"NAS for NLP is not an AutoML capability.","3":"NAS for NLP is not an AutoML capability."}}', '{"title":"What is automated ML?","url":"https://learn.microsoft.com/azure/machine-learning/concept-automated-ml"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (368, 'ai-900', 'ai-900-nlp', 'Text Analytics', 'Language Services', 'single', 'easy', 'From the options below, which service would you use to determine the language of a short chat message?', '["Language detection","Entity recognition","Sentiment analysis","Speech-to-text"]', '[0]', 'Language detection predicts the language of a text sample.', '{"correct":"Language detection predicts the language of a text sample.","why_others_wrong":{"1":"Sentiment predicts tone, not language.","2":"Speech-to-text transcribes audio.","3":"Speech-to-text transcribes audio."}}', '{"title":"Language detection","url":"https://learn.microsoft.com/azure/ai-services/language-service/language-detection/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (369, 'ai-900', 'ai-900-ai-workloads', 'AI Concepts', 'AI Fundamentals', 'single', 'medium', 'In this scenario, which Azure service provides access to GPT family models for text generation and chat?', '["Azure OpenAI Service","Text Analytics","Language Understanding (LUIS)","Custom Vision"]', '[0]', 'Azure OpenAI provides access to large language models such as GPT and embeddings.', '{"correct":"Azure OpenAI provides access to large language models such as GPT and embeddings.","why_others_wrong":{"1":"LUIS is retired and replaced by Conversational Language Understanding.","2":"Custom Vision is for images, not text generation.","3":"Custom Vision is for images, not text generation."}}', '{"title":"What is Azure OpenAI Service?","url":"https://learn.microsoft.com/azure/ai-services/openai/overview"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (370, 'ai-900', 'ai-900-ai-workloads', 'Responsible AI', 'Responsible AI', 'single', 'medium', 'Among these, which policy helps prevent harmful content when using Azure OpenAI models?', '["Disable logging","Content filtering and safety system messages","Increase token limit","Use larger model size only"]', '[1]', 'Content filters, safety parameters, and guidance mitigate harmful outputs.', '{"correct":"Content filters, safety parameters, and guidance mitigate harmful outputs.","why_others_wrong":{"0":"Disabling logs does not improve safety.","2":"Model size alone does not ensure safety.","3":"Model size alone does not ensure safety."}}', '{"title":"Azure AI content safety and filters","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/content-filter"}', '2025-08-17T02:46:23.955769+00:00', '2025-08-17T02:46:23.955769+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1001, 'ai-102', NULL, 'Azure OpenAI', 'Azure OpenAI', 'single', 'medium', 'You need to prevent a generative model from returning unsafe outputs while building a chat app in East US. Which capability should you enable?', '["Temperature = 0","Rate limiting","Stop sequences","Content filtering with Azure AI Content Safety"]', '[3]', 'Azure AI Content Safety provides input and output filtering for harmful content. Tuning temperature or stop sequences does not guarantee safety.', '{"correct":"Content Safety is designed to detect and block unsafe categories, aligning with Responsible AI requirements.","why_others_wrong":{"0":"Reduces randomness but cannot enforce safety policies.","1":"Controls throughput but not safety categories.","2":"Stops generation at tokens but does not classify or block harmful content."}}', '{"title":"Azure AI Content Safety overview","url":"https://learn.microsoft.com/azure/ai-services/content-safety/overview"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1002, 'ai-102', NULL, 'Azure OpenAI', 'Azure OpenAI', 'multiple', 'difficult', 'You are designing retrieval-augmented generation (RAG) for app-marketing-1001. Which approaches improve grounding and reduce hallucinations? (Select two)', '["Use a deterministic temperature of 1.2","Add citations to the prompt format and require sources","Disable system prompt to allow free-form answers","Increase max tokens without retrieval","Use embeddings with a vector store for semantic search"]', '[1,4]', 'Semantic retrieval with embeddings grounds the model in enterprise data; prompting for citations improves traceability.', '{"correct":"RAG pairs relevant context with prompts; requiring citations encourages grounded outputs and improves reviewability.","why_others_wrong":{"0":"Temperature > 1 increases randomness and does not ground answers.","2":"Removes guardrails and increases hallucination likelihood.","3":"Larger context without relevant sources does not ground answers."}}', '{"title":"RAG with Azure OpenAI","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/use-your-data"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1003, 'ai-102', NULL, 'SDKs', 'SDKs', 'single', 'easy', 'Your API app in West Europe must call Azure OpenAI without storing keys in code. What should you use?', '["Include key in request body","Hard-coded API key in environment variable","Managed identity with role assignment","Connection string in appsettings.json"]', '[2]', 'Managed identity enables Azure AD-based authentication without secrets in code.', '{"correct":"Managed identities remove the need for key management and integrate with RBAC.","why_others_wrong":{"0":"Insecure and not supported.","1":"Environment variables are still secrets to rotate and protect.","3":"Secrets in config can leak; not recommended."}}', '{"title":"Authenticate to Azure AI with managed identities","url":"https://learn.microsoft.com/azure/ai-services/authentication"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1004, 'ai-102', NULL, 'Content filters', 'Content filters', 'single', 'medium', 'You must log and review flagged prompts and completions for marketing. Which two signals are most relevant to capture for safety review?', '["HTTP User-Agent","Content Safety category and severity","Prompt token count only","Input and output hash with timestamps"]', '[1]', 'Capturing category/severity and hashed input/output with time helps audit and triage safety events.', '{"correct":"Safety category/severity indicates risk; hashes allow correlation without storing PII.","why_others_wrong":{"0":"Operational detail, not a safety signal.","2":"Not sufficient to assess safety risk.","3":"Useful, but without category/severity it lacks risk context."}}', '{"title":"Responsible AI—content filters and logging","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/safety"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1005, 'ai-102', NULL, 'Azure Machine Learning', 'Azure Machine Learning', 'single', 'medium', 'You need CI/CD for model training pipelines with lineage tracking. Which Azure service feature should you use?', '["Manual notebooks only","Azure Databricks jobs without tracking","Local scripts on developer machines","Azure ML pipelines with MLflow tracking"]', '[3]', 'Azure ML pipelines orchestrate training and log metrics and artifacts via MLflow, enabling lineage.', '{"correct":"Combines automation and tracking for reproducibility and governance.","why_others_wrong":{"0":"Not reproducible or governed for CI/CD.","1":"Lacks lineage and experiment tracking.","2":"Not scalable or auditable."}}', '{"title":"Track ML experiments in Azure Machine Learning","url":"https://learn.microsoft.com/azure/machine-learning/concept-train-mlflow"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1006, 'ai-102', NULL, 'Monitoring', 'Monitoring', 'single', 'easy', 'To capture prompt/response latency and tokens used across prod, where should you centralize telemetry?', '["Azure Advisor","Azure Monitor / Application Insights","Azure Policy","Azure Service Health"]', '[1]', 'Application Insights captures custom events/metrics for distributed tracing and cost monitoring.', '{"correct":"Provides performance, usage, and cost-related telemetry for AI calls.","why_others_wrong":{"0":"Provides recommendations, not tracing.","2":"Enforces governance, not telemetry.","3":"Reports service incidents, not app telemetry."}}', '{"title":"Application Insights for Node.js/REST clients","url":"https://learn.microsoft.com/azure/azure-monitor/app/app-insights-overview"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1007, 'ai-102', NULL, 'Language Studio', 'Language Studio', 'single', 'medium', 'You need PII detection and redaction before sending text to a model. Which capability should you use?', '["Sentiment analysis","PII entity recognition in Language Studio","Text Analytics for health (PHI only)","Key Phrase Extraction"]', '[1]', 'PII entity recognition identifies and can mask PII prior to processing.', '{"correct":"Pre-processing step ensures privacy compliance.","why_others_wrong":{"0":"Classifies sentiment, not PII.","2":"Focuses on healthcare PHI, not all PII.","3":"Identifies key phrases, not PII."}}', '{"title":"Recognize PII entities","url":"https://learn.microsoft.com/azure/cognitive-services/language-service/personally-identifiable-information/overview"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1009, 'ai-102', NULL, 'Azure OpenAI', 'Azure OpenAI', 'multiple', 'difficult', 'You are designing retrieval-augmented generation (RAG) for app-finance-1008. Which approaches improve grounding and reduce hallucinations? (Select two)', '["Use a deterministic temperature of 1.2","Use embeddings with a vector store for semantic search","Increase max tokens without retrieval","Disable system prompt to allow free-form answers","Add citations to the prompt format and require sources"]', '[1,4]', 'Semantic retrieval with embeddings grounds the model in enterprise data; prompting for citations improves traceability.', '{"correct":"RAG pairs relevant context with prompts; requiring citations encourages grounded outputs and improves reviewability.","why_others_wrong":{"0":"Temperature > 1 increases randomness and does not ground answers.","2":"Larger context without relevant sources does not ground answers.","3":"Removes guardrails and increases hallucination likelihood."}}', '{"title":"RAG with Azure OpenAI","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/use-your-data"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1011, 'ai-102', NULL, 'Content filters', 'Content filters', 'single', 'medium', 'You must log and review flagged prompts and completions for finance. Which two signals are most relevant to capture for safety review?', '["HTTP User-Agent","Input and output hash with timestamps","Prompt token count only","Content Safety category and severity"]', '[3]', 'Capturing category/severity and hashed input/output with time helps audit and triage safety events.', '{"correct":"Safety category/severity indicates risk; hashes allow correlation without storing PII.","why_others_wrong":{"0":"Operational detail, not a safety signal.","1":"Useful, but without category/severity it lacks risk context.","2":"Not sufficient to assess safety risk."}}', '{"title":"Responsible AI—content filters and logging","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/safety"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1013, 'ai-102', NULL, 'Monitoring', 'Monitoring', 'single', 'easy', 'To capture prompt/response latency and tokens used across dev, where should you centralize telemetry?', '["Azure Advisor","Azure Policy","Azure Monitor / Application Insights","Azure Service Health"]', '[2]', 'Application Insights captures custom events/metrics for distributed tracing and cost monitoring.', '{"correct":"Provides performance, usage, and cost-related telemetry for AI calls.","why_others_wrong":{"0":"Provides recommendations, not tracing.","1":"Enforces governance, not telemetry.","3":"Reports service incidents, not app telemetry."}}', '{"title":"Application Insights for Node.js/REST clients","url":"https://learn.microsoft.com/azure/azure-monitor/app/app-insights-overview"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
