INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (1996, 'ai-102', NULL, 'Azure OpenAI', 'Azure OpenAI', 'multiple', 'difficult', 'You are designing retrieval-augmented generation (RAG) for app-engineering-1995. Which approaches improve grounding and reduce hallucinations? (Select two)', '["Use a deterministic temperature of 1.2","Add citations to the prompt format and require sources","Increase max tokens without retrieval","Disable system prompt to allow free-form answers","Use embeddings with a vector store for semantic search"]', '[1,4]', 'Semantic retrieval with embeddings grounds the model in enterprise data; prompting for citations improves traceability.', '{"correct":"RAG pairs relevant context with prompts; requiring citations encourages grounded outputs and improves reviewability.","why_others_wrong":{"0":"Temperature > 1 increases randomness and does not ground answers.","2":"Larger context without relevant sources does not ground answers.","3":"Removes guardrails and increases hallucination likelihood."}}', '{"title":"RAG with Azure OpenAI","url":"https://learn.microsoft.com/azure/ai-services/openai/concepts/use-your-data"}', '2025-08-17T02:46:24.302011+00:00', '2025-08-17T02:46:24.302011+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (2001, 'az-900', 'az-900-cloud-concepts', 'Cloud benefits', 'Cloud benefits', 'single', 'easy', 'Which cloud characteristic helps you automatically scale resources for app-engineering-1000 during peak traffic in East US?', '["Elasticity","Latency","On-premises","CapEx"]', '[0]', 'Elasticity enables automatic scaling to match demand.', '{"correct":"Core cloud benefit is the ability to scale up/down dynamically.","why_others_wrong":{"1":"Latency is a metric, not a cloud characteristic.","2":"Opposite of cloud.","3":"Cloud is OpEx oriented; CapEx is not a cloud characteristic."}}', '{"title":"Describe cloud concepts","url":"https://learn.microsoft.com/azure/architecture/cloud-adoption/getting-started/benefits-of-the-cloud"}', '2025-08-17T02:46:24.524658+00:00', '2025-08-17T02:46:24.524658+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (2002, 'az-900', NULL, 'Compute', 'Compute', 'single', 'easy', 'Which Azure service is PaaS for hosting web apps with deployment slots?', '["Azure App Service","Azure Container Registry","Azure Virtual Machines","Azure Functions (Consumption)"]', '[0]', 'App Service is a PaaS web hosting platform with deployment slots.', '{"correct":"Provides managed runtime, scaling, and slots.","why_others_wrong":{"1":"Stores container images; not a hosting platform.","2":"IaaS, not PaaS.","3":"Serverless compute, not general web app PaaS."}}', '{"title":"What is Azure App Service?","url":"https://learn.microsoft.com/azure/app-service/overview"}', '2025-08-17T02:46:24.524658+00:00', '2025-08-17T02:46:24.524658+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (2003, 'az-900', NULL, 'Azure Policy', 'Azure Policy', 'single', 'medium', 'To enforce tagging for all resources in rg-engineering-prod-102, which tool should you use?', '["RBAC","Locks","Azure Policy","Azure Monitor"]', '[2]', 'Azure Policy evaluates and enforces compliance such as required tags.', '{"correct":"Policy is the governance tool for compliance at scale.","why_others_wrong":{"0":"Controls access, not compliance rules.","1":"Prevent changes or deletion but do not enforce tags.","3":"Observability, not enforcement."}}', '{"title":"Azure Policy overview","url":"https://learn.microsoft.com/azure/governance/policy/overview"}', '2025-08-17T02:46:24.524658+00:00', '2025-08-17T02:46:24.524658+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (2004, 'az-900', NULL, 'Pricing calculator', 'Pricing calculator', 'single', 'easy', 'Which tool estimates monthly costs for a planned solution in North Europe?', '["Cost Management + Billing reports","Azure Pricing calculator","Service Trust Portal","Azure Advisor"]', '[1]', 'Pricing calculator models estimated costs before deployment.', '{"correct":"Used during planning for TCO estimation.","why_others_wrong":{"0":"Reports actual/forecasted spend, not pre-deployment estimates.","2":"Compliance documentation.","3":"Provides optimization recommendations after deployment."}}', '{"title":"Pricing calculator","url":"https://azure.microsoft.com/pricing/calculator/"}', '2025-08-17T02:46:24.524658+00:00', '2025-08-17T02:46:24.524658+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (2005, 'az-900', NULL, 'Networking', 'Networking', 'single', 'medium', 'Which feature provides physical datacenter fault isolation within a region?', '["Availability Sets","Resource groups","Region pairs","Availability Zones"]', '[3]', 'Availability Zones are physically separate locations within an Azure region.', '{"correct":"Zone-level isolation increases resiliency.","why_others_wrong":{"0":"Protect against host failures, not datacenter-level.","1":"Logical grouping only.","2":"Cross-region pairing for recovery, not intra-region isolation."}}', '{"title":"Regions and Availability Zones","url":"https://learn.microsoft.com/azure/reliability/availability-zones-overview"}', '2025-08-17T02:46:24.524658+00:00', '2025-08-17T02:46:24.524658+00:00', TRUE) ON CONFLICT DO NOTHING;
