INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (2996, 'az-900', 'az-900-cloud-concepts', 'Cloud benefits', 'Cloud benefits', 'single', 'easy', 'Which cloud characteristic helps you automatically scale resources for app-engineering-1995 during peak traffic in East US 2?', '["On-premises","CapEx","Elasticity","Latency"]', '[2]', 'Elasticity enables automatic scaling to match demand.', '{"correct":"Core cloud benefit is the ability to scale up/down dynamically.","why_others_wrong":{"0":"Opposite of cloud.","1":"Cloud is OpEx oriented; CapEx is not a cloud characteristic.","3":"Latency is a metric, not a cloud characteristic."}}', '{"title":"Describe cloud concepts","url":"https://learn.microsoft.com/azure/architecture/cloud-adoption/getting-started/benefits-of-the-cloud"}', '2025-08-17T02:46:24.524658+00:00', '2025-08-17T02:46:24.524658+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (3001, 'az-204', 'az-204-develop-compute-solutions', 'Azure Functions', 'Azure Functions', 'single', 'medium', 'Which trigger is appropriate for processing messages from an Azure Storage queue?', '["HTTP trigger","Queue trigger","Timer trigger","Blob trigger"]', '[1]', 'Queue trigger automatically scales and processes messages from Storage queues.', '{"correct":"Designed for queue message processing with at-least-once semantics.","why_others_wrong":{"0":"Invoked via HTTP, not queue messages.","2":"Runs on schedule.","3":"Runs when a blob is created or updated."}}', '{"title":"Azure Functions triggers and bindings","url":"https://learn.microsoft.com/azure/azure-functions/functions-triggers-bindings"}', '2025-08-17T02:46:24.740573+00:00', '2025-08-17T02:46:24.740573+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (3002, 'az-204', 'az-204-develop-storage-solutions', 'Cosmos DB', 'Cosmos DB', 'multiple', 'difficult', 'For an IoT workload requiring low latency and global distribution, which Cosmos DB capabilities are relevant? (Select two)', '["Automatic partitioning with partition key","Time to Live (TTL)","Session consistency only","Fixed 10 RU/s per container","Multi-master writes"]', '[0,4]', 'Multi-master enables write-side global distribution; partitioning scales throughput horizontally.', '{"correct":"Both features enable scalability and low-latency writes across regions.","why_others_wrong":{"1":"Useful for retention but not for global write scalability.","2":"Stronger or weaker consistency may be needed; not a capability itself.","3":"RU/s is configurable and scalable."}}', '{"title":"Azure Cosmos DB global distribution","url":"https://learn.microsoft.com/azure/cosmos-db/distribute-data-globally"}', '2025-08-17T02:46:24.740573+00:00', '2025-08-17T02:46:24.740573+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (3003, 'az-204', 'az-204-implement-azure-security', 'Key Vault', 'Key Vault', 'single', 'medium', 'How should an App Service app access secrets from Key Vault without storing credentials?', '["Embed the secret in source code","Store the secret in appsettings.json","Pass the secret via query string","Use a system-assigned managed identity and Key Vault access policy/RBAC"]', '[3]', 'Managed identity allows the app to authenticate to Key Vault using Azure AD.', '{"correct":"Eliminates secret distribution while enabling least-privileged access.","why_others_wrong":{"0":"Never store secrets in code.","1":"Secrets in config are risky and require rotation.","2":"Insecure and logged in many places."}}', '{"title":"Managed identity with Key Vault","url":"https://learn.microsoft.com/azure/key-vault/general/managed-identity"}', '2025-08-17T02:46:24.740573+00:00', '2025-08-17T02:46:24.740573+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (3004, 'az-204', NULL, 'Service Bus', 'Service Bus', 'single', 'medium', 'You need ordered, transactional messaging with competing consumers. Which service should you choose?', '["Event Hubs","Event Grid","Azure Service Bus","Azure Storage Queues"]', '[2]', 'Service Bus supports sessions, transactions, and advanced messaging patterns.', '{"correct":"Designed for enterprise messaging semantics.","why_others_wrong":{"0":"Big data streaming ingestion, not work queues.","1":"Pub/sub for discrete events, not transactional messaging.","3":"Simple queueing without transactions/sessions."}}', '{"title":"Choose between messaging services","url":"https://learn.microsoft.com/azure/event-grid/compare-messaging-services"}', '2025-08-17T02:46:24.740573+00:00', '2025-08-17T02:46:24.740573+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (3005, 'az-204', NULL, 'Application Insights', 'Application Insights', 'single', 'easy', 'What feature helps you trace a request across microservices hosted on App Service and Functions?', '["Workbooks","Service Health","Availability tests","Distributed tracing (Application Map)"]', '[3]', 'Distributed tracing correlates telemetry across services.', '{"correct":"Enables end-to-end diagnostics and performance analysis.","why_others_wrong":{"0":"Dashboards; not automatic correlation.","1":"Platform incidents; not app traces.","2":"Ping tests; not end-to-end tracing."}}', '{"title":"Application Map","url":"https://learn.microsoft.com/azure/azure-monitor/app/app-map"}', '2025-08-17T02:46:24.740573+00:00', '2025-08-17T02:46:24.740573+00:00', TRUE) ON CONFLICT DO NOTHING;
