INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (4001, 'az-400', NULL, 'Azure Pipelines', 'Azure Pipelines', 'single', 'medium', 'You want pipeline-as-code with PR validation for app-engineering-1000. What should you use?', '["YAML pipelines with multi-stage","Classic Release pipelines","Manual deployments","ARM template deployment from Portal"]', '[0]', 'YAML pipelines enable pipeline-as-code, branch policies, and PR validation.', '{"correct":"Integrated with version control and supports multi-stage CI/CD.","why_others_wrong":{"1":"UI-based and not defined as code.","2":"Not automated or repeatable.","3":"One-off deployments; not CI/CD."}}', '{"title":"YAML pipelines","url":"https://learn.microsoft.com/azure/devops/pipelines/yaml-schema"}', '2025-08-17T02:46:25.071983+00:00', '2025-08-17T02:46:25.071983+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (4002, 'az-400', NULL, 'Deployment strategies', 'Deployment strategies', 'multiple', 'difficult', 'Which strategies minimize risk during production rollouts? (Select two)', '["Manual copy to VMs","Blue/green","FTP deploy","Canary","Big-bang"]', '[1,3]', 'Blue/green and canary allow progressive exposure and quick rollback.', '{"correct":"They reduce blast radius and support validation before full cutover.","why_others_wrong":{"0":"Error-prone and not observable.","2":"Bypasses governance and traceability.","4":"All-or-nothing increases risk."}}', '{"title":"Deployment strategies","url":"https://learn.microsoft.com/azure/architecture/framework/devops/release-engineering"}', '2025-08-17T02:46:25.071983+00:00', '2025-08-17T02:46:25.071983+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (4003, 'az-400', NULL, 'ARM/Bicep', 'ARM/Bicep', 'single', 'medium', 'Which approach improves readability and modularity for Azure resource templates?', '["Bash scripts for all resources","Bicep with modules","Monolithic ARM JSON","Manual Portal deployments"]', '[1]', 'Bicep is a higher-level language than ARM JSON with modules for reuse.', '{"correct":"Declarative, typed authoring with tooling improves maintainability.","why_others_wrong":{"0":"Imperative and error-prone.","2":"Hard to maintain and verbose.","3":"Not repeatable or versioned."}}', '{"title":"Bicep overview","url":"https://learn.microsoft.com/azure/azure-resource-manager/bicep/overview"}', '2025-08-17T02:46:25.071983+00:00', '2025-08-17T02:46:25.071983+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (4004, 'az-400', 'az-400-develop-security-compliance', 'Policies', 'Policies', 'single', 'medium', 'You must block secrets in PRs to main. What should you implement?', '["Branch policies with required build and secret scanning","Service connections","Manual code reviews only","Release approvals"]', '[0]', 'Branch policies with a validation pipeline and secret scanning prevent merging leaking secrets.', '{"correct":"Automated gate in PRs enforces compliance.","why_others_wrong":{"1":"Used for deployments; unrelated to scanning.","2":"Not reliable for secret detection.","3":"Apply post-build; does not prevent secret merge."}}', '{"title":"Branch policies","url":"https://learn.microsoft.com/azure/devops/repos/git/branch-policies"}', '2025-08-17T02:46:25.071983+00:00', '2025-08-17T02:46:25.071983+00:00', TRUE) ON CONFLICT DO NOTHING;
