INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (5001, 'az-500', 'az-500-manage-identity-access', 'Microsoft Entra ID', 'Microsoft Entra ID', 'single', 'medium', 'Which control enforces multi-factor authentication only when a sign-in risk is high?', '["Per-user MFA","Role assignment approval","Terms of use","Conditional Access with sign-in risk policy"]', '[3]', 'Conditional Access evaluates risk and enforces MFA dynamically.', '{"correct":"Risk-based CA policies provide adaptive access control.","why_others_wrong":{"0":"Applies regardless of risk.","1":"Relates to PIM, not sign-in risk.","2":"User acknowledgment; not MFA enforcement."}}', '{"title":"Conditional Access","url":"https://learn.microsoft.com/entra/identity/conditional-access/overview"}', '2025-08-17T02:46:25.306153+00:00', '2025-08-17T02:46:25.306153+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (5002, 'az-500', NULL, 'Azure Firewall', 'Azure Firewall', 'single', 'medium', 'You need outbound FQDN filtering and DNAT/SNAT for workloads in rg-hr-test-101. Which should you deploy?', '["Application Gateway WAF","NSG","Front Door","Azure Firewall"]', '[3]', 'Azure Firewall provides L3–L7 filtering, FQDN rules, and NAT.', '{"correct":"Centralized network security with full features for egress/ingress control.","why_others_wrong":{"0":"Inbound HTTP(S) protection; not egress.","1":"Stateful 5-tuple filtering; no FQDN or NAT.","2":"Global entry; not a VNet firewall."}}', '{"title":"Azure Firewall overview","url":"https://learn.microsoft.com/azure/firewall/overview"}', '2025-08-17T02:46:25.306153+00:00', '2025-08-17T02:46:25.306153+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (5003, 'az-500', NULL, 'Key Vault', 'Key Vault', 'single', 'easy', 'To restrict Key Vault access to private network only, which feature should you use?', '["Private endpoint","Service tags","Public endpoint with IP ACL only","Resource lock"]', '[0]', 'Private endpoints route traffic through a private IP in your VNet.', '{"correct":"Eliminates exposure to public internet while enabling secure access.","why_others_wrong":{"1":"Help with NSG rules but do not privatize the service.","2":"Still exposed on public internet.","3":"Prevents deletion; not network isolation."}}', '{"title":"Key Vault networking","url":"https://learn.microsoft.com/azure/key-vault/general/overview-vnet-service-endpoints#private-endpoints"}', '2025-08-17T02:46:25.306153+00:00', '2025-08-17T02:46:25.306153+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (5004, 'az-500', NULL, 'Defender for Cloud', 'Defender for Cloud', 'multiple', 'medium', 'Which Defender for Cloud capabilities help reduce attack surface? (Select two)', '["Azure Advisor cost tips","Resource tags","Availability tests","Security posture recommendations","Just-In-Time VM access"]', '[3,4]', 'Posture recommendations and JIT VM access reduce exposure and harden workloads.', '{"correct":"They are proactive controls and protections for resources.","why_others_wrong":{"0":"Optimization, not security.","1":"Metadata only.","2":"Not a security control."}}', '{"title":"Defender for Cloud","url":"https://learn.microsoft.com/azure/defender-for-cloud/defender-for-cloud-introduction"}', '2025-08-17T02:46:25.306153+00:00', '2025-08-17T02:46:25.306153+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (5005, 'az-500', NULL, 'DDoS Protection', 'DDoS Protection', 'single', 'medium', 'Which plan adds adaptive real-time DDoS mitigation for VNet resources?', '["WAF","Azure Firewall","Standard plan","Basic (always-on)"]', '[2]', 'DDoS Protection Standard provides adaptive tuning and mitigation.', '{"correct":"Protects public endpoints in a VNet at network edge.","why_others_wrong":{"0":"L7 HTTP(S) protection; not volumetric network DDoS.","1":"Firewall does not provide DDoS network scrubbing.","3":"Included baseline; no adaptive policies."}}', '{"title":"DDoS Protection Standard","url":"https://learn.microsoft.com/azure/ddos-protection/ddos-protection-overview"}', '2025-08-17T02:46:25.306153+00:00', '2025-08-17T02:46:25.306153+00:00', TRUE) ON CONFLICT DO NOTHING;
