INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6001, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Virtual Networks', 'single', 'medium', 'You are planning a virtual network that must support 2000 virtual machines across multiple subnets. You want to minimize IP address waste while ensuring room for growth. What address space should you choose?', '["10.0.0.0/21 (2046 addresses)","10.0.0.0/20 (4094 addresses)","10.0.0.0/19 (8190 addresses)","10.0.0.0/18 (16382 addresses)"]', '[2]', 'For 2000 VMs with room for growth, /19 provides 8190 usable addresses (8192 - 2 reserved). This allows for proper subnetting while minimizing waste. /20 would be too small (4094), while /18 would be excessive for the requirement.', '{"correct":"A /19 subnet provides 8190 usable IP addresses (2^13 - 2 reserved addresses). This gives enough capacity for 2000 VMs with significant room for growth (4x capacity) while still being efficient. It allows for proper subnet segmentation across multiple subnets within the address space.","why_others_wrong":{"0":"/21 provides only 2046 addresses, which is barely enough for 2000 VMs with no room for growth or subnet overhead.","1":"/20 provides 4094 addresses, which gives some growth but may be insufficient for long-term scaling and multiple subnet requirements.","3":"/18 provides 16382 addresses, which is excessive and wastes IP address space unnecessarily for the stated requirement."}}', '{"title":"Plan virtual networks - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-vnet-plan-design-arm"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6002, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Network Security Groups', 'single', 'easy', 'You have a web application with the following NSG rules:
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6003, 'az-104', 'az-104-configure-manage-networking', 'Load Balancing', 'Azure Load Balancer', 'multiple', 'difficult', 'You are configuring a Standard Load Balancer for a multi-tier application. Which of the following features are available with Standard Load Balancer? (Select all that apply)', '["Availability Zone support","Multiple frontend IPs","Health probes with HTTPS protocol","Port 0 rules for all ports","Outbound rules configuration"]', '[0,1,2,4]', 'Standard Load Balancer supports: Availability Zones, multiple frontend IPs, HTTPS health probes, and outbound rules configuration. Port 0 rules are not supported - you must specify explicit ports or port ranges.', '{"correct":"Standard Load Balancer is the premium SKU that provides zone redundancy across Availability Zones, supports multiple frontend IP configurations for different services, includes HTTPS health probes for application-layer health checking, and offers outbound rules for controlling egress traffic.","why_others_wrong":{"3":"Port 0 (wildcard for all ports) is not supported in Azure Load Balancer. You must explicitly specify individual ports or port ranges in load balancing rules. This is a security design choice to ensure explicit configuration."}}', '{"title":"Standard Load Balancer overview - Azure Load Balancer","url":"https://docs.microsoft.com/en-us/azure/load-balancer/load-balancer-standard-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6004, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'VPN Gateway', 'single', 'medium', 'Your organization needs to establish a Site-to-Site VPN connection to Azure. The on-premises VPN device supports:
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6005, 'az-104', 'az-104-configure-manage-networking', 'DNS', 'DNS', 'single', 'easy', 'You are configuring a custom domain for an Azure App Service. The domain is managed by Azure DNS. What is the correct sequence of steps?', '["1. Create CNAME record 2. Add custom domain to App Service 3. Create TXT record for verification","1. Add custom domain to App Service 2. Create TXT record for verification 3. Create CNAME record","1. Create TXT record for verification 2. Add custom domain to App Service 3. Create CNAME record","1. Create CNAME record 2. Create TXT record for verification 3. Add custom domain to App Service"]', '[2]', 'Correct sequence: 1) Create TXT record for domain verification 2) Add custom domain to App Service (verification will succeed) 3) Create CNAME record to point to App Service. The TXT record proves domain ownership before Azure allows the custom domain to be added.', '{"correct":"Azure requires domain ownership verification before allowing custom domains to be added to App Services. The TXT record (asuid.contoso.com) proves you own the domain. Only after creating this verification record can you successfully add the custom domain to the App Service. Finally, the CNAME record routes traffic from your custom domain to the App Service''s azurewebsites.net endpoint.","why_others_wrong":{"0":"Creating the CNAME record first doesn''t provide domain verification, and Azure will reject adding the custom domain without proof of ownership.","1":"Adding the custom domain first will fail because Azure cannot verify domain ownership without the TXT verification record.","3":"This sequence places domain addition last, but the CNAME record creation will fail if the custom domain hasn''t been added to the App Service first."}}', '{"title":"Map an existing custom DNS name to Azure App Service","url":"https://docs.microsoft.com/en-us/azure/app-service/app-service-web-tutorial-custom-domain"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6006, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Network Peering', 'multiple', 'difficult', 'You have configured VNet peering between VNet1 (10.1.0.0/16) and VNet2 (10.2.0.0/16). Which statements about VNet peering are correct? (Select all that apply)', '["Traffic between peered VNets is encrypted by default","Peering is not transitive - VNet1 cannot reach VNet3 through VNet2","Both VNets must be in the same Azure region","You can peer VNets across different Azure subscriptions","NSG rules apply to traffic between peered VNets"]', '[1,3,4]', 'Correct: VNet peering is not transitive, supports cross-subscription peering, and NSGs apply to peered traffic. Incorrect: Traffic is not encrypted (it''s private but not encrypted), and Global VNet peering allows cross-region peering.', '{"correct":"VNet peering creates direct network connections but is not transitive by design for security reasons. Cross-subscription peering is supported with proper permissions. NSG rules are evaluated and applied to traffic between peered VNets, allowing fine-grained security control. Global VNet peering enables cross-region connectivity, and traffic flows over Microsoft''s private backbone without encryption but with full isolation.","why_others_wrong":{"0":"Traffic between peered VNets travels over Microsoft''s private backbone and is isolated but not encrypted. If encryption is required, you need to implement it at the application layer or use VPN gateways.","2":"Global VNet peering allows peering between VNets in different Azure regions. Regional restrictions only apply to classic VNet peering which is being deprecated."}}', '{"title":"Virtual network peering - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-peering-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6007, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Azure Firewall', 'single', 'easy', 'You are configuring Azure Firewall for a hub-and-spoke topology. The firewall has these rule collections:
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6008, 'az-104', 'az-104-configure-manage-networking', 'Application Gateway', 'Application Gateway', 'multiple', 'easy', 'You are implementing Azure Application Gateway with Web Application Firewall (WAF) for a web application. Which routing methods are supported? (Select all that apply)', '["Path-based routing","Multi-site hosting","IP-based routing","URL rewrite","Header-based routing"]', '[0,1,3]', 'Application Gateway supports: Path-based routing (route by URL path), Multi-site hosting (route by hostname), and URL rewrite. IP-based routing and header-based routing are not standard Application Gateway features.', '{"correct":"Azure Application Gateway provides layer 7 load balancing with path-based routing (routing based on URL paths like /api/* to backend pool 1), multi-site hosting (routing based on host headers like contoso.com vs fabrikam.com), and URL rewrite capabilities (modifying URL paths before forwarding to backends). These features enable sophisticated traffic routing for complex web applications.","why_others_wrong":{"2":"IP-based routing is not a feature of Application Gateway. Application Gateway operates at layer 7 and routes based on HTTP/HTTPS attributes like hostname and URL path, not source IP addresses.","4":"While Application Gateway can inspect HTTP headers, header-based routing (routing decisions based on custom HTTP headers) is not a standard routing method. Routing is primarily based on hostname and URL path."}}', '{"title":"Application Gateway features - Azure Application Gateway","url":"https://docs.microsoft.com/en-us/azure/application-gateway/features"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6009, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'User Defined Routes', 'single', 'easy', 'You have a subnet with these routes:
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6010, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'ExpressRoute', 'single', 'easy', 'Your company has an ExpressRoute circuit with Microsoft peering configured. Which Azure services can be accessed through Microsoft peering?', '["Only virtual machines in virtual networks","Azure Storage, SQL Database, and Cosmos DB using public endpoints","Only services within the same region as the ExpressRoute circuit","All Azure services including those with private endpoints"]', '[1]', 'Microsoft peering provides access to Azure PaaS services (Storage, SQL Database, Cosmos DB, etc.) using their public IP addresses. Private peering is for VNet resources, and private endpoints require private peering, not Microsoft peering.', '{"correct":"Microsoft peering in ExpressRoute enables connectivity to Azure public services (PaaS) using their public IP address ranges. This includes services like Azure Storage, SQL Database, Cosmos DB, Office 365, and Dynamics 365. These services are accessed via their public endpoints but traffic flows over the private ExpressRoute connection instead of the public internet, providing better performance, reliability, and security.","why_others_wrong":{"0":"Virtual machines in virtual networks are accessed through Private peering, not Microsoft peering. Microsoft peering is specifically for Azure public services.","2":"Microsoft peering provides access to Azure public services globally, not just in the same region as the ExpressRoute circuit. The routing is based on BGP advertisements from Microsoft.","3":"Private endpoints are accessed through Private peering, not Microsoft peering. Microsoft peering only provides access to public endpoints of Azure services."}}', '{"title":"ExpressRoute routing requirements - Azure ExpressRoute","url":"https://docs.microsoft.com/en-us/azure/expressroute/expressroute-routing"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6011, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Application Security Groups', 'multiple', 'medium', 'You need to implement microsegmentation for a 3-tier application using Application Security Groups (ASGs). Which statements are correct? (Select all that apply)', '["ASGs can be used as source or destination in NSG rules","A VM can be a member of multiple ASGs","ASGs work across different virtual networks","ASGs reduce the number of NSG rules needed","ASGs can contain IP addresses from on-premises networks"]', '[0,1,3]', 'Correct: ASGs can be source/destination in NSG rules, VMs can belong to multiple ASGs, and they reduce NSG rule complexity. Incorrect: ASGs work only within a single VNet and cannot contain on-premises IPs.', '{"correct":"Application Security Groups (ASGs) enable microsegmentation by allowing you to group VMs logically and reference these groups in NSG rules instead of using specific IP addresses. A VM can belong to multiple ASGs (e.g., WebTier, DatabaseAccess), enabling flexible security policies. ASGs significantly reduce NSG rule complexity because you can create rules like ''Allow WebTier to DatabaseTier on port 1433'' instead of managing individual IP addresses.","why_others_wrong":{"2":"ASGs are scoped to a single virtual network. They cannot span across multiple VNets. For cross-VNet scenarios, you need to use IP addresses, service tags, or other methods.","4":"ASGs can only contain Azure VMs within the same VNet. They cannot contain on-premises IP addresses or resources outside of Azure."}}', '{"title":"Application security groups - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/application-security-groups"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6012, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Service Endpoints', 'single', 'medium', 'You have enabled Azure Storage service endpoints on a subnet. A VM in this subnet is trying to access a storage account that has firewall rules allowing only the subnet. The access is failing. What is the most likely cause?', '["Service endpoints are not enabled on the storage account","The storage account firewall is not configured to allow the virtual network","The VM needs a public IP address","NSG rules are blocking the traffic"]', '[1]', 'Enabling service endpoints on the subnet is only half the configuration. The storage account''s firewall must also be configured to allow access from the specific virtual network/subnet. Both sides of the configuration are required.', '{"correct":"Service endpoints require configuration on both sides: the subnet (enable service endpoint) and the Azure service (configure firewall rules). Enabling the service endpoint on the subnet redirects traffic to the Azure service over the Microsoft backbone, but the service''s firewall must explicitly allow the virtual network/subnet. Without both configurations, access will be denied even though the service endpoint is enabled.","why_others_wrong":{"0":"Service endpoints are enabled on subnets, not on the storage account itself. The storage account has firewall rules, not service endpoint settings.","2":"Service endpoints work with private IP addresses. VMs do not need public IP addresses to access Azure services through service endpoints - that''s the whole point of using service endpoints.","3":"While NSGs could block traffic, the scenario specifically mentions firewall rules on the storage account allowing only the subnet, suggesting the NSG configuration is not the primary issue."}}', '{"title":"Virtual Network service endpoints - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-service-endpoints-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6013, 'az-104', 'az-104-configure-manage-networking', 'Load Balancing', 'Traffic Manager', 'single', 'easy', 'You are configuring Azure Traffic Manager for a global application with endpoints in East US, West Europe, and Southeast Asia. Users should be directed to the closest healthy endpoint. Which routing method should you use?', '["Performance routing","Geographic routing","Weighted routing","Priority routing"]', '[0]', 'Performance routing directs users to the endpoint with the lowest network latency from the user''s location. This automatically routes users to the closest healthy endpoint based on network performance measurements.', '{"correct":"Performance routing in Azure Traffic Manager uses latency measurements to direct users to the endpoint that provides the best network performance from their location. Traffic Manager maintains a latency table showing response times from different Azure regions to various internet locations, and uses this data to route users to the endpoint with the lowest latency, which typically corresponds to the geographically closest healthy endpoint.","why_others_wrong":{"1":"Geographic routing routes users based on their geographic location to specific endpoints, but doesn''t automatically choose the closest one - you manually map regions to endpoints.","2":"Weighted routing distributes traffic based on assigned weights (percentages) across endpoints, regardless of user location or performance considerations.","3":"Priority routing uses a primary endpoint and fails over to secondary endpoints only when the primary becomes unhealthy, regardless of user location or performance."}}', '{"title":"Traffic Manager routing methods - Azure Traffic Manager","url":"https://docs.microsoft.com/en-us/azure/traffic-manager/traffic-manager-routing-methods"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7864, 'az-305', NULL, 'General', 'AZ-305 Fundamentals', 'single', 'medium', 'This is a sample AZ-305 question 5 for topic data-storage. Which option is correct?', '["Option A - First choice","Option B - Second choice","Option C - Third choice","Option D - Fourth choice"]', '[0]', 'This is a sample explanation for AZ-305 question 5.', '{"correct":"Option A is correct for this sample AZ-305 question.","why_others_wrong":{"1":"Option B is incorrect for demonstration purposes.","2":"Option C is incorrect for demonstration purposes.","3":"Option D is incorrect for demonstration purposes."}}', '{"title":"AZ-305 Reference","url":"https://learn.microsoft.com/en-us/credentials/certifications/resources/study-guides/az-305"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6014, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'Point-to-Site VPN', 'multiple', 'medium', 'You are configuring Point-to-Site VPN for remote workers. Which authentication methods are supported by Azure VPN Gateway? (Select all that apply)', '["Certificate-based authentication","Azure Active Directory authentication","RADIUS authentication","Username/password authentication","Smart card authentication"]', '[0,1,2]', 'Azure VPN Gateway supports: Certificate-based authentication (using client certificates), Azure AD authentication (for OpenVPN protocol), and RADIUS authentication (for external authentication servers). Direct username/password and smart card authentication are not supported.', '{"correct":"Azure VPN Gateway Point-to-Site connections support multiple authentication methods: Certificate-based authentication uses client certificates installed on user devices and is the most common method. Azure AD authentication integrates with OpenVPN protocol and leverages Azure AD for user authentication and conditional access policies. RADIUS authentication allows integration with external authentication servers for enterprise scenarios, enabling support for various authentication methods including multi-factor authentication.","why_others_wrong":{"3":"Direct username/password authentication is not supported by Azure VPN Gateway for Point-to-Site connections. You need to use Azure AD authentication or RADIUS for credential-based authentication.","4":"Smart card authentication is not directly supported by Azure VPN Gateway. While smart cards might be used as part of a RADIUS authentication setup, they are not a native authentication method for P2S VPN."}}', '{"title":"About Point-to-Site VPN - Azure VPN Gateway","url":"https://docs.microsoft.com/en-us/azure/vpn-gateway/point-to-site-about"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6015, 'az-104', 'az-104-configure-manage-networking', 'DNS', 'Private DNS Zones', 'single', 'easy', 'You have created a private DNS zone ''contoso.local'' and linked it to VNet1 with auto-registration enabled. When you create a VM in VNet1, it doesn''t appear in the DNS zone. What is the most likely cause?', '["The VM was created with a static private IP address","Auto-registration is only enabled, but resolution is disabled","The private DNS zone name conflicts with a public DNS zone","The VM is in a subnet that doesn''t support auto-registration"]', '[1]', 'For auto-registration to work, the VNet link must have both ''Enable auto registration'' AND ''Enable DNS resolution'' enabled. If only auto-registration is enabled without DNS resolution, VMs won''t register their records.', '{"correct":"Azure Private DNS zones require both auto-registration and DNS resolution to be enabled on the virtual network link for VMs to automatically register their DNS records. Auto-registration allows VMs to register their records, while DNS resolution allows the private DNS zone to resolve queries from the VNet. Both settings work together - auto-registration without DNS resolution will not function properly.","why_others_wrong":{"0":"The IP address assignment method (static vs dynamic) doesn''t affect auto-registration. Both static and dynamic IP addresses can be auto-registered in private DNS zones.","2":"Private DNS zone names can use any domain name, including ones that might exist publicly. The private zone takes precedence for resources within the linked VNet.","3":"Auto-registration works for all subnets within a linked VNet. There are no subnet-specific restrictions for auto-registration functionality."}}', '{"title":"Azure Private DNS zones - Azure DNS","url":"https://docs.microsoft.com/en-us/azure/dns/private-dns-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6016, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'DDoS Protection', 'single', 'difficult', 'Your public-facing application is experiencing a DDoS attack. You have DDoS Protection Standard enabled. What should you do to get detailed attack metrics and mitigation reports?', '["Configure DDoS diagnostic logs in Azure Monitor","Enable NSG flow logs","Configure Azure Security Center","Enable Azure Firewall logs"]', '[0]', 'DDoS Protection Standard provides detailed telemetry through DDoS diagnostic logs in Azure Monitor. These logs include attack metrics, mitigation reports, and flow information during DDoS attacks.', '{"correct":"DDoS Protection Standard includes comprehensive telemetry and monitoring capabilities through Azure Monitor. DDoS diagnostic logs provide detailed information about attacks including attack vectors, mitigation actions taken, traffic patterns, and attack duration. These logs are essential for understanding attack patterns and improving defense strategies. The logs include DDoSProtectionNotifications, DDoSMitigationFlowLogs, and DDoSMitigationReports.","why_others_wrong":{"1":"NSG flow logs show network traffic patterns but don''t provide DDoS-specific attack metrics or mitigation details that DDoS Protection Standard generates.","2":"Azure Security Center provides security recommendations and alerts but doesn''t provide the detailed DDoS attack telemetry that''s available through DDoS diagnostic logs.","3":"Azure Firewall logs show firewall rule processing and traffic patterns but don''t contain DDoS attack metrics or mitigation reports specific to DDoS Protection Standard."}}', '{"title":"Azure DDoS Protection Standard - Azure DDoS Protection","url":"https://docs.microsoft.com/en-us/azure/ddos-protection/ddos-protection-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6017, 'az-104', 'az-104-configure-manage-networking', 'Application Gateway', 'SSL/TLS', 'single', 'medium', 'You need to configure SSL termination on Application Gateway and re-encrypt traffic to backend servers. The backend servers have different SSL certificates. What should you configure?', '["SSL passthrough","End-to-end SSL encryption with multiple backend HTTP settings","SSL termination only","HTTP to HTTPS redirect"]', '[1]', 'End-to-end SSL encryption allows SSL termination at Application Gateway and re-encryption to backends. Multiple backend HTTP settings are needed when backend servers have different certificates, each pointing to appropriate backend pools.', '{"correct":"End-to-end SSL encryption with Application Gateway involves SSL termination at the gateway (decrypting client traffic) and then re-encrypting traffic to backend servers. When backend servers have different SSL certificates, you need multiple backend HTTP settings - each configured with the appropriate certificate details for its respective backend pool. This allows the Application Gateway to validate different backend certificates and establish secure connections to each backend server group.","why_others_wrong":{"0":"SSL passthrough doesn''t allow SSL termination at Application Gateway - traffic passes through encrypted end-to-end, preventing the gateway from inspecting or modifying traffic.","2":"SSL termination only decrypts traffic at the Application Gateway but sends unencrypted HTTP traffic to backends, which doesn''t meet the requirement for re-encryption.","3":"HTTP to HTTPS redirect is a redirection feature and doesn''t address the SSL termination and re-encryption requirements."}}', '{"title":"Application Gateway SSL termination and end-to-end SSL","url":"https://docs.microsoft.com/en-us/azure/application-gateway/ssl-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6018, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Network Virtual Appliances', 'single', 'difficult', 'You deployed a network virtual appliance (NVA) in a hub VNet to inspect traffic between spoke VNets. Traffic is not flowing through the NVA. What configuration is missing?', '["IP forwarding must be enabled on the NVA''s network interface","The NVA must have a public IP address","Route tables with custom routes directing traffic to the NVA","Both A and C are required"]', '[3]', 'For an NVA to work: 1) IP forwarding must be enabled on the NVA''s network interface to allow it to forward packets not destined for itself, and 2) Route tables with custom routes must direct traffic to the NVA.', '{"correct":"Network Virtual Appliances require two critical configurations: First, IP forwarding must be enabled on the NVA''s network interface because by default, Azure drops packets not destined for the VM''s IP address. Second, custom route tables must be configured to direct traffic to the NVA - without these routes, traffic will follow default Azure routing and bypass the NVA entirely. Both configurations are mandatory for NVA functionality.","why_others_wrong":{"0":"While IP forwarding is necessary, it alone is insufficient - route tables are also required to direct traffic to the NVA.","1":"A public IP address is not required for an NVA to inspect inter-VNet traffic. NVAs can operate entirely with private IP addresses in hub-and-spoke architectures.","2":"While route tables are necessary, they alone are insufficient - IP forwarding must also be enabled for the NVA to process and forward traffic."}}', '{"title":"Network virtual appliances in Azure","url":"https://docs.microsoft.com/en-us/azure/architecture/reference-architectures/dmz/nva-ha"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6019, 'az-104', 'az-104-configure-manage-networking', 'Load Balancing', 'Cross-region Load Balancer', 'single', 'medium', 'You need to load balance traffic across Azure regions for a critical application. Which solution provides the fastest failover with health checking?', '["Azure Traffic Manager","Azure Front Door","Cross-region Load Balancer","Application Gateway v2"]', '[1]', 'Azure Front Door provides the fastest failover (typically under 30 seconds) with built-in health probes and anycast networking. Traffic Manager uses DNS-based routing which has slower failover due to DNS caching.', '{"correct":"Azure Front Door uses anycast networking and operates at the edge of Microsoft''s global network, providing sub-30-second failover times. It continuously monitors backend health and can instantly redirect traffic to healthy endpoints. The anycast architecture ensures users connect to the nearest point of presence, minimizing latency and enabling rapid failover.","why_others_wrong":{"0":"Azure Traffic Manager uses DNS-based routing with TTL values, typically resulting in 60-120 second failover times due to DNS caching. While reliable, it''s slower than Front Door for critical applications requiring rapid failover.","2":"Cross-region Load Balancer is primarily for load balancing within Azure regions, not for global traffic distribution and failover across multiple regions.","3":"Application Gateway v2 operates within a single region and doesn''t provide cross-region load balancing or global failover capabilities."}}', '{"title":"Azure Front Door overview","url":"https://docs.microsoft.com/en-us/azure/frontdoor/front-door-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6020, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'ExpressRoute Global Reach', 'single', 'difficult', 'Your company has ExpressRoute circuits in East US and West Europe. You want to enable direct communication between on-premises locations through Azure''s backbone. What should you configure?', '["ExpressRoute Premium on both circuits","ExpressRoute Global Reach","VNet peering between the regions","Site-to-Site VPN between the circuits"]', '[1]', 'ExpressRoute Global Reach enables direct connectivity between on-premises networks through Microsoft''s global backbone, bypassing the public internet and virtual networks.', '{"correct":"ExpressRoute Global Reach allows you to connect ExpressRoute circuits together to create a private network between your on-premises networks. Traffic flows directly through Microsoft''s global backbone network without traversing the public internet or requiring virtual networks. This provides high bandwidth, low latency connectivity between geographically distributed on-premises locations.","why_others_wrong":{"0":"ExpressRoute Premium provides access to global Azure services and increased route limits, but doesn''t enable direct on-premises to on-premises connectivity between circuits.","2":"VNet peering connects virtual networks in Azure but doesn''t provide direct on-premises to on-premises connectivity - traffic would need to route through Azure VNets.","3":"Site-to-Site VPN would route traffic over the public internet, not through Microsoft''s private backbone, and wouldn''t provide the performance and reliability of ExpressRoute."}}', '{"title":"ExpressRoute Global Reach overview","url":"https://docs.microsoft.com/en-us/azure/expressroute/expressroute-global-reach"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6021, 'az-104', 'az-104-implement-manage-storage', 'Storage Accounts', 'Storage Accounts', 'single', 'easy', 'You need to create a storage account that provides the highest durability for critical business data and allows read access from a secondary region. Which replication option should you choose?', '["Locally Redundant Storage (LRS)","Zone-Redundant Storage (ZRS)","Geo-Redundant Storage (GRS)","Read-Access Geo-Redundant Storage (RA-GRS)"]', '[3]', 'RA-GRS provides the highest durability by replicating data to a secondary region (like GRS) and additionally allows read access to the secondary region during normal operations, providing business continuity options.', '{"correct":"RA-GRS provides 16 nines of durability (99.99999999999999%) by maintaining 6 copies of data: 3 in the primary region across fault domains and 3 in a geographically distant secondary region. Unlike GRS, RA-GRS allows read access to the secondary region during normal operations, enabling applications to read from the secondary region for load distribution and disaster recovery testing.","why_others_wrong":{"0":"LRS only maintains 3 copies within a single datacenter in the primary region, providing 11 nines durability but no protection against datacenter or regional failures.","1":"ZRS maintains 3 copies across availability zones in the primary region, providing 12 nines durability but no protection against regional disasters and no secondary region access.","2":"GRS provides the same 16 nines durability as RA-GRS but doesn''t allow read access to the secondary region during normal operations, limiting business continuity options."}}', '{"title":"Azure Storage redundancy - Azure Storage","url":"https://docs.microsoft.com/en-us/azure/storage/common/storage-redundancy"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6022, 'az-104', 'az-104-implement-manage-storage', 'Blob Storage', 'Lifecycle Management', 'multiple', 'easy', 'You are configuring lifecycle management for blob storage to optimize costs. Which actions can be performed automatically? (Select all that apply)', '["Move blobs to Cool tier after 30 days","Move blobs to Archive tier after 90 days","Delete blobs after 365 days","Move blob snapshots to different tiers","Compress blobs automatically"]', '[0,1,2,3]', 'Lifecycle management can automatically: transition blobs between access tiers (Hot → Cool → Archive), delete blobs after specified periods, and manage blob snapshots. Automatic compression is not a lifecycle management feature.', '{"correct":"Azure Blob Storage lifecycle management provides automated policy-based rules to transition blobs between access tiers (Hot, Cool, Archive) based on age or last access time, delete blobs after specified retention periods, and manage blob versions and snapshots. These policies help optimize storage costs by automatically moving data to more cost-effective tiers as it ages and becomes less frequently accessed.","why_others_wrong":{"4":"Automatic compression is not a feature of Azure Blob Storage lifecycle management. Compression must be handled at the application level before uploading blobs to storage."}}', '{"title":"Manage the Azure Blob storage lifecycle","url":"https://docs.microsoft.com/en-us/azure/storage/blobs/storage-lifecycle-management-concepts"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6023, 'az-104', 'az-104-implement-manage-storage', 'Storage Security', 'SAS Tokens', 'single', 'easy', 'You need to provide a partner company temporary access to specific blobs in your storage account. The access should be limited to read operations for 7 days. What type of SAS should you create?', '["Account SAS with full permissions","Service SAS with read permissions on blob service","User delegation SAS with read permissions","Stored access policy with service SAS"]', '[2]', 'User delegation SAS is the most secure option as it uses Azure AD credentials instead of storage account keys. It provides fine-grained control and is recommended for external access scenarios.', '{"correct":"User delegation SAS is the most secure form of SAS because it''s secured with Azure AD credentials rather than the storage account key. This provides better security governance, supports Azure AD authentication and authorization, enables audit trails, and allows for more granular permission control. It''s specifically recommended for scenarios involving external access to storage resources.","why_others_wrong":{"0":"Account SAS with full permissions grants excessive access beyond the requirement and uses storage account keys which are less secure than Azure AD credentials.","1":"Service SAS uses storage account keys which are less secure than Azure AD credentials, and while it can be scoped to blob service, user delegation SAS is more secure for external access.","3":"Stored access policies provide centralized management but still rely on storage account keys rather than Azure AD credentials, making them less secure for external scenarios."}}', '{"title":"Create a user delegation SAS for a blob with .NET","url":"https://docs.microsoft.com/en-us/azure/storage/blobs/storage-blob-user-delegation-sas-create-dotnet"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6024, 'az-104', 'az-104-deploy-manage-compute', 'Virtual Machines', 'Availability', 'single', 'easy', 'You need to deploy VMs that can tolerate a complete datacenter failure within an Azure region. The VMs should be distributed across physical locations. What should you configure?', '["Availability Set with 3 fault domains","Availability Zones across zones 1, 2, and 3","Virtual Machine Scale Set with zone balancing","Both B and C provide the required protection"]', '[3]', 'Both Availability Zones and VMSS with zone balancing protect against datacenter failures. Availability Zones distribute VMs across physically separate datacenters, and VMSS with zone balancing automatically distributes instances across zones.', '{"correct":"Both Availability Zones and Virtual Machine Scale Sets with zone balancing provide protection against complete datacenter failures within a region. Availability Zones are physically separate datacenters with independent power, cooling, and networking. VMSS with zone balancing automatically distributes VM instances across multiple zones, providing the same datacenter-level fault tolerance with added scaling capabilities.","why_others_wrong":{"0":"Availability Sets only protect against hardware failures within a single datacenter (fault domains and update domains) but don''t protect against complete datacenter failures.","1":"While this provides the required protection, it''s not the complete answer since VMSS with zone balancing also provides the same protection.","2":"While this provides the required protection, it''s not the complete answer since individual VMs in Availability Zones also provide the same protection."}}', '{"title":"Availability options for Azure Virtual Machines","url":"https://docs.microsoft.com/en-us/azure/virtual-machines/availability"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6025, 'az-104', 'az-104-deploy-manage-compute', 'VM Extensions', 'Custom Script Extension', 'single', 'easy', 'You need to automatically install software on Windows VMs after deployment. The installation requires a reboot. Which approach should you use?', '["Custom Script Extension with a single script","PowerShell DSC Extension","Custom Script Extension with restart handling in the script","Both B and C can handle reboots properly"]', '[3]', 'Both PowerShell DSC Extension and Custom Script Extension with proper restart handling can manage reboots. DSC is designed for configuration management and handles reboots gracefully, while Custom Script Extension can include restart logic.', '{"correct":"PowerShell DSC Extension is specifically designed for configuration management and includes built-in capabilities to handle reboots during configuration application. Custom Script Extension can also handle reboots when the script includes proper restart logic using commands like ''Restart-Computer -Force'' and continuation mechanisms. Both approaches can successfully manage post-deployment software installation requiring reboots.","why_others_wrong":{"0":"A single script in Custom Script Extension without restart handling cannot properly manage installations requiring reboots, as the extension execution will terminate when the VM restarts.","1":"While PowerShell DSC Extension can handle reboots, this is not the complete answer since Custom Script Extension with restart handling can also manage reboots.","2":"While Custom Script Extension with restart handling can manage reboots, this is not the complete answer since PowerShell DSC Extension also provides this capability."}}', '{"title":"Virtual machine extensions and features for Windows","url":"https://docs.microsoft.com/en-us/azure/virtual-machines/extensions/features-windows"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6026, 'az-104', NULL, 'Azure AD', 'Self-Service Password Reset', 'multiple', 'easy', 'You are configuring Self-Service Password Reset (SSPR) for your organization. Which authentication methods are supported? (Select all that apply)', '["Mobile phone (SMS or voice call)","Email address","Security questions","Microsoft Authenticator app","Hardware security key"]', '[0,1,2,3]', 'SSPR supports: mobile phone (SMS/voice), email, security questions, and authenticator apps including Microsoft Authenticator. Hardware security keys (FIDO2) are not supported for SSPR, only for sign-in.', '{"correct":"Azure AD Self-Service Password Reset supports multiple authentication methods to verify user identity: mobile phone verification via SMS or voice call, alternate email address verification, security questions (customizable by organization), and authenticator apps including Microsoft Authenticator that can generate verification codes or send push notifications. These methods provide users with flexible options to reset their passwords securely.","why_others_wrong":{"4":"Hardware security keys (FIDO2) are supported for passwordless sign-in to Azure AD but are not supported as an authentication method for Self-Service Password Reset. SSPR requires methods that can be used when users have forgotten their passwords."}}', '{"title":"Authentication methods for Azure AD SSPR","url":"https://docs.microsoft.com/en-us/azure/active-directory/authentication/concept-authentication-methods"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6027, 'az-104', NULL, 'RBAC', 'Custom Roles', 'single', 'easy', 'You need to create a custom role that allows users to start/stop VMs but not create, delete, or modify VM configurations. Which permissions should be included?', '["Microsoft.Compute/virtualMachines/* (all VM actions)","Microsoft.Compute/virtualMachines/start/action and Microsoft.Compute/virtualMachines/powerOff/action","Microsoft.Compute/virtualMachines/read, */start/action, */powerOff/action, and */restart/action","Virtual Machine Contributor role permissions"]', '[2]', 'The custom role needs: read permission to view VMs, and specific action permissions for start, powerOff, and restart. Using /* would grant too many permissions including create/delete/modify capabilities.', '{"correct":"A properly scoped custom role for VM power management requires: Microsoft.Compute/virtualMachines/read (to view VMs in the portal and get their status), Microsoft.Compute/virtualMachines/start/action (to start stopped VMs), Microsoft.Compute/virtualMachines/powerOff/action (to power off running VMs), and Microsoft.Compute/virtualMachines/restart/action (to restart VMs). This follows the principle of least privilege by granting only the minimum permissions required.","why_others_wrong":{"0":"Using Microsoft.Compute/virtualMachines/* grants all VM permissions including create, delete, modify configurations, and manage disks - far more than required and violating least privilege principle.","1":"This lacks the read permission needed to view VMs in the portal and the restart action. Users wouldn''t be able to see VM status or restart VMs.","3":"Virtual Machine Contributor role includes full VM management permissions including create, delete, and modify operations - much more than the requirement for just power management."}}', '{"title":"Azure custom roles - Azure RBAC","url":"https://docs.microsoft.com/en-us/azure/role-based-access-control/custom-roles"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6028, 'az-104', NULL, 'Azure Monitor', 'Alerts', 'single', 'easy', 'You need to create an alert that triggers when VM CPU usage exceeds 80% for more than 5 minutes, but only during business hours (9 AM - 5 PM). How should you configure this?', '["Create a metric alert with time-based condition","Create a metric alert and use action groups with suppression rules","Create a log search alert with time-based KQL query","Create a metric alert and configure alert processing rules for time-based suppression"]', '[3]', 'Create a standard metric alert for CPU > 80% for 5 minutes, then use alert processing rules to suppress notifications outside business hours. This provides the most flexible and manageable approach.', '{"correct":"Alert processing rules provide the most flexible and maintainable approach for time-based alert suppression. You create a standard metric alert for the CPU condition, then apply alert processing rules to suppress notifications outside business hours. This separation of concerns allows easy modification of notification schedules without changing the core alert logic, and supports complex scheduling scenarios including holidays and maintenance windows.","why_others_wrong":{"0":"Metric alerts don''t have built-in time-based conditions for suppressing notifications based on business hours. They evaluate continuously based on metric thresholds.","1":"Action groups with suppression rules don''t provide time-based suppression capabilities. Suppression rules are designed for different scenarios like maintenance windows, not recurring time-based schedules.","2":"While KQL queries can include time-based logic, this adds unnecessary complexity to the alert condition when the requirement is simply to suppress notifications during specific hours, not to change when the alert evaluates."}}', '{"title":"Alert processing rules in Azure Monitor","url":"https://docs.microsoft.com/en-us/azure/azure-monitor/alerts/alerts-processing-rules"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6029, 'az-104', NULL, 'Backup', 'VM Backup', 'single', 'easy', 'You need to backup VMs that have both OS and data disks, with the ability to restore individual files and perform application-consistent backups. What should you configure?', '["Azure Backup with snapshot-only policy","Azure Backup with file-system consistent backup","Azure Backup with application-consistent backup and install VM agent","Azure Site Recovery for continuous replication"]', '[2]', 'Azure Backup with application-consistent backup and VM agent provides: full VM backup including all disks, application-consistent snapshots (using VSS), and file-level restore capabilities through the agent.', '{"correct":"Azure Backup with application-consistent backup and VM agent provides comprehensive protection: it backs up both OS and data disks, uses Volume Shadow Copy Service (VSS) to ensure application-consistent snapshots where applications flush their buffers and quiesce I/O operations, and the VM agent enables file-level restore capabilities allowing recovery of individual files without restoring the entire VM. This combination meets all requirements in the question.","why_others_wrong":{"0":"Snapshot-only policy doesn''t provide application consistency or file-level restore capabilities. It creates crash-consistent point-in-time snapshots but lacks the VM agent integration needed for file recovery.","1":"File-system consistent backup ensures file system consistency but doesn''t provide application-level consistency (applications may have uncommitted transactions) and may not include file-level restore capabilities.","3":"Azure Site Recovery is designed for disaster recovery and business continuity with continuous replication, but it''s not primarily a backup solution and doesn''t provide the file-level restore capabilities described in the requirements."}}', '{"title":"Azure VM backup overview","url":"https://docs.microsoft.com/en-us/azure/backup/backup-azure-vms-introduction"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6030, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'NAT Gateway', 'single', 'easy', 'You have multiple VMs in a subnet that need outbound internet access with a consistent public IP address. The VMs should not be directly accessible from the internet. What should you implement?', '["Assign public IP addresses to each VM","Use Azure Load Balancer with outbound rules","Deploy Azure NAT Gateway and associate it with the subnet","Use Azure Firewall for outbound traffic"]', '[2]', 'Azure NAT Gateway provides outbound internet connectivity with consistent public IP addresses while keeping VMs private. It''s the most cost-effective solution for this scenario compared to Azure Firewall or Load Balancer outbound rules.', '{"correct":"Azure NAT Gateway is specifically designed for outbound internet connectivity scenarios. It provides a consistent public IP address for all outbound traffic from the subnet while keeping VMs completely private (no inbound access from internet). It''s zone-redundant, supports up to 64,000 concurrent connections, and offers predictable performance. For simple outbound internet access requirements, it''s more cost-effective than Azure Firewall and simpler to configure than Load Balancer outbound rules.","why_others_wrong":{"0":"Assigning public IP addresses to each VM makes them directly accessible from the internet, violating the requirement for private VMs. It also doesn''t provide a consistent IP address for outbound traffic.","1":"Azure Load Balancer with outbound rules can provide consistent outbound IP addresses, but it''s more complex to configure and typically more expensive than NAT Gateway for simple outbound-only scenarios.","3":"Azure Firewall can provide outbound connectivity with consistent IP addresses, but it''s significantly more expensive than NAT Gateway and includes many features (like application-layer filtering) that aren''t needed for simple outbound internet access."}}', '{"title":"Azure NAT Gateway overview","url":"https://docs.microsoft.com/en-us/azure/virtual-network/nat-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6031, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Subnetting', 'single', 'medium', 'You need to create subnets in a VNet with address space 10.0.0.0/16. You require 4 subnets with the following requirements:
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6032, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Azure Firewall', 'multiple', 'easy', 'You are implementing Azure Firewall in a hub-spoke topology. Which features are available with Azure Firewall Premium? (Select all that apply)', '["TLS inspection","IDPS (Intrusion Detection and Prevention)","URL filtering","Web categories filtering","File reputation filtering"]', '[0,1,2,3]', 'Azure Firewall Premium includes TLS inspection, IDPS, URL filtering, and web categories filtering. File reputation filtering is not a standard feature.', '{"correct":"Azure Firewall Premium provides advanced security features including TLS inspection for encrypted traffic analysis, IDPS for threat detection and prevention, URL filtering for blocking specific URLs, and web categories filtering for blocking entire categories of websites. These features provide comprehensive network protection.","why_others_wrong":{"4":"File reputation filtering is not a standard feature of Azure Firewall Premium. While it has threat intelligence capabilities, specific file reputation filtering is not included in the standard feature set."}}', '{"title":"Azure Firewall Premium features","url":"https://docs.microsoft.com/en-us/azure/firewall/premium-features"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6033, 'az-104', 'az-104-configure-manage-networking', 'Load Balancing', 'Application Gateway', 'single', 'difficult', 'You need to configure Application Gateway to route traffic based on the following requirements:
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6034, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'ExpressRoute', 'single', 'easy', 'Your company has an ExpressRoute circuit with both private and Microsoft peering configured. You need to access Azure Storage and Office 365 services. Which peering should be used for each service?', '["Both services use private peering","Storage uses private peering, Office 365 uses Microsoft peering","Storage uses Microsoft peering, Office 365 uses private peering","Both services use Microsoft peering"]', '[3]', 'Both Azure Storage (when accessed via public endpoints) and Office 365 services are accessed through Microsoft peering. Private peering is for Azure VNet resources.', '{"correct":"Microsoft peering provides connectivity to Microsoft cloud services that use public IP addresses, including Azure Storage (when using public endpoints), Office 365, Dynamics 365, and other Microsoft PaaS services. These services are not deployed within your virtual networks, so they require Microsoft peering rather than private peering.","why_others_wrong":{"0":"Private peering is only for Azure resources deployed in virtual networks (VNets), not for Microsoft cloud services with public endpoints.","1":"Azure Storage (public endpoints) requires Microsoft peering, not private peering, unless you''re using private endpoints within a VNet.","2":"Office 365 requires Microsoft peering, not private peering, as it''s a cloud service with public endpoints."}}', '{"title":"ExpressRoute peering requirements","url":"https://docs.microsoft.com/en-us/azure/expressroute/expressroute-circuit-peerings"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6035, 'az-104', 'az-104-configure-manage-networking', 'DNS', 'Private DNS Zones', 'multiple', 'medium', 'You are configuring Azure Private DNS zones for your virtual networks. Which statements are correct? (Select all that apply)', '["A private DNS zone can be linked to multiple virtual networks","Auto-registration automatically creates DNS records for VMs","Private DNS zones can resolve public DNS queries","Cross-region virtual network links are supported","Private DNS zones require a dedicated DNS server"]', '[0,1,3]', 'Private DNS zones support multiple VNet links, auto-registration for VMs, and cross-region links. They don''t resolve public DNS and don''t require dedicated servers.', '{"correct":"Azure Private DNS zones can be linked to multiple virtual networks across different regions, automatically register VM DNS records when auto-registration is enabled, and support cross-region virtual network links. The service is fully managed by Azure.","why_others_wrong":{"2":"Private DNS zones are designed for private name resolution within linked virtual networks, not for resolving public DNS queries.","4":"Private DNS zones are a fully managed Azure service and don''t require you to deploy or manage dedicated DNS servers."}}', '{"title":"Azure Private DNS zones overview","url":"https://docs.microsoft.com/en-us/azure/dns/private-dns-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6036, 'az-104', 'az-104-implement-manage-storage', 'Blob Storage', 'Access Tiers', 'single', 'medium', 'Your application generates log files that are frequently accessed for the first 30 days, occasionally accessed for the next 90 days, and rarely accessed after that. What is the most cost-effective storage strategy?', '["Store all data in Hot tier permanently","Use lifecycle management to move data: Hot → Cool after 30 days → Archive after 120 days","Store all data in Cool tier permanently","Use lifecycle management to move data: Hot → Archive after 30 days"]', '[1]', 'Lifecycle management allows automatic transition between tiers based on access patterns. Hot for first 30 days (frequent access), Cool for next 90 days (occasional access), then Archive for long-term retention.', '{"correct":"Lifecycle management policies can automatically transition blobs between access tiers based on last modified time or last access time. For the described pattern, Hot tier provides optimal performance for frequent access in the first 30 days, Cool tier offers a balance of cost and performance for occasional access (30-120 days), and Archive tier provides the lowest cost for rarely accessed data after 120 days.","why_others_wrong":{"0":"Storing all data permanently in Hot tier is the most expensive option and doesn''t optimize costs for data that becomes less frequently accessed over time.","2":"Cool tier permanently doesn''t optimize for the frequent access in the first 30 days and is more expensive than Archive for rarely accessed data.","3":"Moving directly to Archive after 30 days doesn''t account for the occasional access needed between 30-120 days, which would incur retrieval costs and latency."}}', '{"title":"Azure Blob storage lifecycle management","url":"https://docs.microsoft.com/en-us/azure/storage/blobs/storage-lifecycle-management-concepts"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6037, 'az-104', 'az-104-deploy-manage-compute', 'Virtual Machines', 'VM Sizing', 'single', 'medium', 'You need to deploy VMs for a database workload that requires high memory, consistent performance, and low network latency between VMs. Which VM series should you choose?', '["B-series (Burstable)","D-series (General purpose)","E-series (Memory optimized)","F-series (Compute optimized)"]', '[2]', 'E-series VMs are memory optimized, ideal for database workloads requiring high memory-to-CPU ratios. They provide consistent performance and can be deployed with accelerated networking for low latency.', '{"correct":"E-series VMs are specifically designed for memory-intensive workloads like databases, in-memory analytics, and caching applications. They offer high memory-to-CPU ratios, consistent performance without CPU credits, and support for accelerated networking which provides low latency and high throughput networking.","why_others_wrong":{"0":"B-series VMs are burstable and designed for workloads with variable CPU usage. They use CPU credits and don''t provide the consistent performance required for database workloads.","1":"D-series VMs are general purpose but don''t provide the high memory-to-CPU ratio specifically needed for database workloads.","3":"F-series VMs are compute optimized with high CPU-to-memory ratios, which is the opposite of what''s needed for memory-intensive database workloads."}}', '{"title":"Azure VM sizes - Memory optimized","url":"https://docs.microsoft.com/en-us/azure/virtual-machines/sizes-memory"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6038, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Network Security Groups', 'multiple', 'medium', 'You are configuring NSG rules for a web application. Which rule configurations are valid? (Select all that apply)', '["Allow inbound HTTP from Internet with priority 100","Deny all inbound traffic with priority 1000","Allow outbound HTTPS to Internet with priority 65000","Allow inbound SSH from specific IP with priority 200","Deny outbound traffic to specific IP with priority 4096"]', '[0,1,3,4]', 'Valid NSG rule priorities range from 100-4096. Priority 65000 is outside this range and invalid for custom rules.', '{"correct":"NSG rules must have priorities between 100-4096 for custom rules. Rules are processed in priority order (lower numbers first). All the listed rules except option 2 have valid priorities within this range and represent common security configurations.","why_others_wrong":{"2":"Priority 65000 is outside the valid range for custom NSG rules. Priorities must be between 100-4096. Priority 65000 is reserved for default rules."}}', '{"title":"Network security group rules","url":"https://docs.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6039, 'az-104', 'az-104-configure-manage-networking', 'Load Balancing', 'Azure Load Balancer', 'single', 'easy', 'You have a Standard Load Balancer with backend VMs in different Availability Zones. One zone becomes unavailable. What happens to the load balancer?', '["The entire load balancer becomes unavailable","Only the frontend IP becomes unavailable","Traffic is automatically redistributed to healthy zones","Manual intervention is required to redirect traffic"]', '[2]', 'Standard Load Balancer is zone-redundant by default. When a zone becomes unavailable, traffic is automatically redistributed to healthy VMs in available zones without impacting the load balancer service.', '{"correct":"Standard Load Balancer provides zone redundancy across Availability Zones. The service itself is zone-redundant, meaning it can survive zone failures. When backend VMs in one zone become unavailable, the load balancer''s health probes detect the failures and automatically stop sending traffic to those VMs, redistributing traffic to healthy VMs in other zones.","why_others_wrong":{"0":"Standard Load Balancer is zone-redundant and continues operating even when entire zones fail.","1":"The frontend IP of Standard Load Balancer is zone-redundant and remains available during zone failures.","3":"No manual intervention is required. The load balancer automatically handles zone failures through health probes and traffic distribution."}}', '{"title":"Standard Load Balancer and Availability Zones","url":"https://docs.microsoft.com/en-us/azure/load-balancer/load-balancer-standard-availability-zones"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6040, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Service Endpoints', 'single', 'difficult', 'You enabled Azure Storage service endpoints on a subnet, but VMs in the subnet cannot access the storage account. The storage account firewall allows the virtual network. What is the most likely cause?', '["Service endpoints are not enabled on the storage account","The subnet needs a route table pointing to the storage account","NSG rules are blocking port 443","The storage account is in a different region"]', '[0]', 'Service endpoints require configuration on both the subnet (enable service endpoint) and the Azure service (configure service to accept traffic from the VNet). Both configurations must be in place.', '{"correct":"Service endpoints require a two-part configuration: enabling the service endpoint on the subnet redirects traffic to the Azure service over Microsoft''s backbone network, but the Azure service (storage account) must also be configured to accept traffic from that virtual network. Without both configurations, the connection will fail.","why_others_wrong":{"1":"Service endpoints don''t require custom route tables. They work by redirecting traffic at the Azure platform level.","2":"While NSG rules could block traffic, the question states the storage account firewall allows the virtual network, suggesting the network path is correct but the service endpoint configuration is incomplete.","3":"Service endpoints work across regions. The storage account doesn''t need to be in the same region as the virtual network."}}', '{"title":"Virtual Network service endpoints","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-service-endpoints-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6041, 'az-104', NULL, 'Azure AD', 'Conditional Access', 'multiple', 'medium', 'You are configuring Conditional Access policies for your organization. Which conditions can trigger a Conditional Access policy? (Select all that apply)', '["User location (IP address ranges)","Device platform (iOS, Android, Windows)","Application being accessed","Time of day","Sign-in risk level"]', '[0,1,2,4]', 'Conditional Access supports location, device platform, applications, and risk-based conditions. Time of day is not a built-in condition but can be achieved through other means.', '{"correct":"Azure AD Conditional Access policies can be triggered based on user/location conditions (trusted IP ranges, named locations), device platform conditions (iOS, Android, Windows, macOS), application conditions (specific cloud apps), and risk-based conditions from Azure AD Identity Protection (sign-in risk, user risk). These conditions enable fine-grained access control.","why_others_wrong":{"3":"Time of day is not a direct built-in condition in Conditional Access policies. However, similar functionality can be achieved using trusted locations that change based on business hours or through custom solutions."}}', '{"title":"Azure AD Conditional Access conditions","url":"https://docs.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-conditions"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6042, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'Point-to-Site VPN', 'single', 'medium', 'You need to configure Point-to-Site VPN for 500 remote users using certificate authentication. What is the maximum number of concurrent P2S connections supported by different VPN Gateway SKUs?', '["Basic: 128, VpnGw1: 128, VpnGw2: 128","Basic: 128, VpnGw1: 250, VpnGw2: 500","Basic: 0, VpnGw1: 128, VpnGw2: 250","Basic: 128, VpnGw1: 500, VpnGw2: 1000"]', '[2]', 'Basic SKU doesn''t support P2S VPN. VpnGw1 supports up to 128 concurrent connections, VpnGw2 supports up to 250. For 500 users, you need VpnGw3 or higher.', '{"correct":"Basic VPN Gateway SKU does not support Point-to-Site VPN connections. VpnGw1 supports up to 128 concurrent P2S connections, VpnGw2 supports up to 250 concurrent connections. For 500 concurrent users, you would need VpnGw3 (which supports 500) or VpnGw4/VpnGw5 (which support 1000+ connections).","why_others_wrong":{"0":"Basic SKU supports P2S VPN, but the connection limits for VpnGw2 are incorrect.","1":"Basic SKU does not support P2S VPN connections at all.","3":"The connection limits for VpnGw1 and VpnGw2 are higher than their actual capacity."}}', '{"title":"VPN Gateway SKUs and P2S connections","url":"https://docs.microsoft.com/en-us/azure/vpn-gateway/vpn-gateway-about-vpngateways"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6043, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'DDoS Protection', 'single', 'difficult', 'Your web application is experiencing a DDoS attack. You have DDoS Protection Standard enabled. What should you do to analyze the attack and improve protection?', '["Enable diagnostic logs and configure attack metrics alerts","Increase the bandwidth of your virtual network","Add more public IP addresses to distribute the load","Implement Azure Firewall rules to block the attack"]', '[0]', 'DDoS Protection Standard provides detailed telemetry through diagnostic logs and metrics. Enabling these allows you to analyze attack patterns and configure proactive alerts for future attacks.', '{"correct":"DDoS Protection Standard includes comprehensive monitoring and analytics capabilities. Diagnostic logs provide detailed information about attacks including attack vectors, mitigation flow logs, and attack reports. Setting up metrics alerts enables proactive monitoring and notification of ongoing attacks, allowing for better incident response and analysis of attack patterns.","why_others_wrong":{"1":"DDoS Protection Standard automatically scales to absorb attacks. Simply increasing bandwidth doesn''t address the attack mitigation and doesn''t provide the analytical insights needed.","2":"Adding more public IPs doesn''t mitigate DDoS attacks and may actually increase the attack surface. DDoS Protection works at the platform level regardless of the number of IPs.","3":"Azure Firewall operates at the application layer and cannot effectively mitigate volumetric DDoS attacks, which occur at the network/transport layers and are handled by DDoS Protection."}}', '{"title":"Azure DDoS Protection Standard monitoring","url":"https://docs.microsoft.com/en-us/azure/ddos-protection/ddos-attack-telemetry"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6044, 'az-104', NULL, 'Azure Monitor', 'Log Analytics', 'single', 'medium', 'You need to query Azure Monitor logs to find all virtual machines that had CPU usage above 80% in the last 24 hours. Which KQL query should you use?', '["Perf | where CounterName == \"% Processor Time\" | where CounterValue > 80 | where TimeGenerated > ago(24h)","AzureMetrics | where MetricName == \"Percentage CPU\" | where Average > 80 | where TimeGenerated > ago(1d)","Perf | where ObjectName == \"Processor\" and CounterName == \"% Processor Time\" and CounterValue > 80 | where TimeGenerated > ago(1d)","VMInsights | where CPUUtilization > 80 | where TimeGenerated > ago(24h)"]', '[2]', 'The correct query uses the Perf table with proper ObjectName and CounterName filters for CPU performance counters, checks for values > 80%, and filters for the last 24 hours.', '{"correct":"The Perf table contains performance counter data from VMs. For CPU usage, you need to filter by ObjectName ''Processor'' and CounterName ''% Processor Time''. The CounterValue > 80 filters for high CPU usage, and TimeGenerated > ago(1d) filters for the last 24 hours. Using ''and'' operators ensures all conditions are met.","why_others_wrong":{"0":"Missing the ObjectName filter, which could return incorrect performance counters that happen to have the same CounterName.","1":"AzureMetrics table contains Azure service metrics, not VM performance counter data. The MetricName and Average fields are not correct for VM CPU data.","3":"VMInsights is not a standard table name in Azure Monitor logs, and CPUUtilization is not a standard field name for CPU performance data."}}', '{"title":"Kusto Query Language (KQL) overview","url":"https://docs.microsoft.com/en-us/azure/azure-monitor/logs/get-started-queries"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6045, 'az-104', 'az-104-configure-manage-networking', 'Application Gateway', 'Web Application Firewall', 'multiple', 'difficult', 'You are configuring Web Application Firewall (WAF) on Application Gateway. Which features are available? (Select all that apply)', '["OWASP rule sets","Custom rules based on IP addresses","Rate limiting per client IP","Geo-filtering by country","SSL/TLS certificate inspection"]', '[0,1,2,3]', 'WAF supports OWASP rule sets, custom rules including IP-based rules, rate limiting, and geo-filtering. SSL/TLS certificate inspection is not a WAF feature.', '{"correct":"Azure WAF provides comprehensive web application protection including OWASP Core Rule Set for common web vulnerabilities, custom rules for specific security requirements including IP address filtering, rate limiting to prevent abuse and DDoS attacks, and geo-filtering to block or allow traffic from specific countries/regions.","why_others_wrong":{"4":"SSL/TLS certificate inspection is not a feature of Web Application Firewall. WAF operates at the application layer (Layer 7) after SSL termination, focusing on HTTP/HTTPS content inspection rather than certificate validation."}}', '{"title":"Azure Web Application Firewall features","url":"https://docs.microsoft.com/en-us/azure/web-application-firewall/ag/ag-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6046, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Network Connectivity', 'single', 'easy', 'You have a hub-and-spoke topology with Azure Firewall in the hub. Spoke VNets contain development, testing, and production environments. You need to ensure that development VMs cannot communicate with production VMs, but all spokes can access the internet. What should you configure?', '["Configure NSG rules on each spoke subnet","Implement Azure Firewall network rules with explicit deny","Use Azure Virtual WAN for traffic isolation","Configure separate route tables for each spoke"]', '[1]', 'Azure Firewall network rules should be configured to explicitly deny traffic between development and production networks while allowing internet access.', '{"correct":"Azure Firewall network rules provide the centralized control needed in a hub-and-spoke topology. You can create rules that explicitly deny traffic between development (source) and production (destination) subnets while maintaining default allow rules for internet access. This approach provides centralized policy management and logging.","why_others_wrong":{"0":"NSG rules would need to be configured on multiple subnets across different VNets, creating management complexity and potential for misconfigurations.","2":"Azure Virtual WAN is a networking service that provides optimized routing but doesn''t inherently provide the granular traffic isolation needed between specific environments.","3":"Route tables control routing paths but don''t provide the security filtering needed to block communication between specific environments."}}', '{"title":"Azure Firewall network rules","url":"https://docs.microsoft.com/en-us/azure/firewall/rule-processing"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6047, 'az-104', 'az-104-configure-manage-networking', 'Load Balancer', 'High Availability', 'multiple', 'easy', 'You are designing a load balancing solution for a mission-critical application that requires 99.99% availability. Which features should you implement? (Select all that apply)', '["Use Standard Load Balancer instead of Basic","Deploy backend VMs across multiple Availability Zones","Configure health probes with appropriate intervals","Implement connection draining during maintenance","Use multiple frontend IP configurations"]', '[0,1,2,3]', 'Standard Load Balancer with zone redundancy, proper health probes, and connection draining are essential for high availability.', '{"correct":"Standard Load Balancer provides zone redundancy and better SLA compared to Basic. Deploying across Availability Zones ensures tolerance to zone failures. Health probes detect unhealthy instances for automatic failover. Connection draining gracefully handles maintenance by completing existing connections before taking instances offline.","why_others_wrong":{"4":"Multiple frontend IP configurations are useful for hosting multiple services but don''t directly contribute to achieving 99.99% availability for a single application."}}', '{"title":"Standard Load Balancer overview","url":"https://docs.microsoft.com/en-us/azure/load-balancer/load-balancer-standard-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6048, 'az-104', 'az-104-configure-manage-networking', 'ExpressRoute', 'Hybrid Connectivity', 'single', 'easy', 'Your company has two ExpressRoute circuits: one in East US (primary) and one in West US (backup). You want to ensure that all traffic normally flows through East US, with West US used only when East US is unavailable. How should you configure BGP routing?', '["Use the same AS-PATH length for both circuits","Configure shorter AS-PATH on the East US circuit","Configure longer AS-PATH on the East US circuit","Use different Local Preference values"]', '[1]', 'BGP prefers routes with shorter AS-PATH length, so configuring a shorter AS-PATH on the primary circuit ensures it''s preferred.', '{"correct":"BGP route selection algorithm prioritizes routes with shorter AS-PATH length (fewer autonomous systems in the path). By configuring AS-PATH prepending on the backup circuit (West US) to make it longer, or ensuring the primary circuit (East US) has a shorter AS-PATH, traffic will prefer the primary circuit under normal conditions.","why_others_wrong":{"0":"Same AS-PATH length would result in load balancing or unpredictable routing behavior rather than clear primary/backup preference.","2":"Longer AS-PATH on the primary circuit would make it less preferred, causing traffic to prefer the backup circuit instead.","3":"Local Preference is used within an AS for internal routing decisions, but ExpressRoute circuits are typically in different locations with different AS numbers from the service provider perspective."}}', '{"title":"ExpressRoute routing optimization","url":"https://docs.microsoft.com/en-us/azure/expressroute/expressroute-optimize-routing"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6049, 'az-104', 'az-104-configure-manage-networking', 'Azure DNS', 'Name Resolution', 'multiple', 'easy', 'You are configuring Azure Private DNS for your multi-region deployment. Which scenarios require careful consideration? (Select all that apply)', '["Cross-region name resolution between peered VNets","Automatic VM registration in private DNS zones","DNS resolution from on-premises through VPN","Using the same private DNS zone across multiple subscriptions","Conditional forwarders for hybrid DNS"]', '[0,1,2,4]', 'Cross-region resolution, auto-registration, on-premises resolution, and conditional forwarding all require specific configuration in Azure Private DNS.', '{"correct":"Cross-region name resolution requires proper VNet linking to private DNS zones. Auto-registration needs to be enabled per VNet link. On-premises DNS resolution requires DNS forwarders or custom DNS servers. Conditional forwarders enable hybrid scenarios where some domains are resolved on-premises and others in Azure.","why_others_wrong":{"3":"Private DNS zones can be easily shared across subscriptions through proper linking - this is a standard supported scenario that doesn''t require special consideration."}}', '{"title":"Azure Private DNS scenarios","url":"https://docs.microsoft.com/en-us/azure/dns/private-dns-scenarios"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6050, 'az-104', 'az-104-configure-manage-networking', 'Network Security Groups', 'Microsegmentation', 'single', 'easy', 'You have a web application with database backend. The web tier is in subnet 10.0.1.0/24 and database tier in subnet 10.0.2.0/24. You need to allow web servers to connect to database port 1433, but block all other traffic between subnets. What is the most secure NSG configuration?', '["Allow 10.0.1.0/24 to 10.0.2.0/24 on port 1433, implicit deny handles the rest","Allow 10.0.1.0/24 to 10.0.2.0/24 on port 1433, then explicit deny 10.0.1.0/24 to 10.0.2.0/24 on any port","Create Application Security Groups for web and database tiers, allow ASG-Web to ASG-DB on port 1433","Allow source service tag ''VirtualNetwork'' to destination 10.0.2.0/24 on port 1433"]', '[2]', 'Application Security Groups provide the most granular and manageable approach for microsegmentation between application tiers.', '{"correct":"Application Security Groups (ASGs) provide application-centric security by allowing you to group VMs by their application role rather than by IP addresses. This approach is more maintainable as VMs can be added/removed from ASGs without updating NSG rules, and it provides clearer intent in security policies.","why_others_wrong":{"0":"While functionally correct, using IP subnets directly is less flexible and harder to maintain when VMs are added or moved.","1":"The explicit deny rule is redundant since NSGs have an implicit deny at the end of the rule list, and this approach still suffers from IP-based limitations.","3":"Using ''VirtualNetwork'' service tag is too broad and would allow access from any subnet in the VNet, not just the web tier."}}', '{"title":"Application Security Groups","url":"https://docs.microsoft.com/en-us/azure/virtual-network/application-security-groups"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6051, 'az-104', 'az-104-implement-manage-storage', 'Blob Storage', 'Data Management', 'single', 'difficult', 'You have a storage account with hot, cool, and archive tiers enabled. A blob in the archive tier was rehydrated to hot tier 3 hours ago. You now need to move it to cool tier to optimize costs. What happens when you attempt this operation?', '["The operation succeeds immediately","The operation is queued and completes within 1 hour","The operation fails because the blob is still in early deletion period","The operation fails because the blob must remain in hot tier for 30 days after rehydration"]', '[0]', 'Once a blob is rehydrated from archive tier, it can be immediately moved to any other tier without restrictions.', '{"correct":"After rehydration from archive tier, a blob behaves like any other blob in the target tier (hot in this case). There are no restrictions preventing immediate movement to cool tier after rehydration. The early deletion charges apply based on the original tier''s minimum duration, not movement restrictions.","why_others_wrong":{"1":"Tier changes between hot and cool are immediate, not queued operations.","2":"Early deletion periods apply to pricing (you''re charged for minimum duration) but don''t prevent tier changes.","3":"There is no requirement to keep blobs in hot tier for 30 days after rehydration - this is not an Azure Storage limitation."}}', '{"title":"Archive tier rehydration","url":"https://docs.microsoft.com/en-us/azure/storage/blobs/archive-rehydrate-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6052, 'az-104', 'az-104-implement-manage-storage', 'File Storage', 'Hybrid Integration', 'multiple', 'easy', 'You are implementing Azure File Sync for a branch office scenario. Which components are required? (Select all that apply)', '["Storage Sync Service","Azure File Share","Windows Server with Azure File Sync agent","Azure File Sync cloud endpoint","VPN or ExpressRoute connection"]', '[0,1,2,3]', 'Azure File Sync requires Storage Sync Service, Azure File Share, Windows Server with agent, and cloud endpoint configuration. VPN is not required.', '{"correct":"Storage Sync Service is the Azure resource that orchestrates sync. Azure File Share is the cloud storage target. Windows Server with the Azure File Sync agent provides the on-premises component. Cloud endpoint connects the Azure File Share to the sync group for synchronization.","why_others_wrong":{"4":"VPN or ExpressRoute is not required for Azure File Sync - it works over the public internet with HTTPS encryption. While private connectivity can be used for performance or compliance reasons, it''s not a requirement."}}', '{"title":"Azure File Sync deployment","url":"https://docs.microsoft.com/en-us/azure/storage/file-sync/file-sync-deployment-guide"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6053, 'az-104', 'az-104-deploy-manage-compute', 'Virtual Machines', 'Performance Optimization', 'single', 'difficult', 'You have a compute-intensive application running on Standard_D4s_v3 VMs that occasionally experiences performance bottlenecks. Azure Advisor recommends resizing to Standard_D8s_v3. The application cannot tolerate downtime. What is the best approach to implement this change?', '["Stop the VM, resize to Standard_D8s_v3, then start the VM","Use Azure Site Recovery to replicate to new VM size, then failover","Create a new VM with Standard_D8s_v3, migrate the application, then deallocate the old VM","Use VM scale sets with rolling upgrade to gradually replace instances"]', '[2]', 'Creating a new VM and migrating the application provides zero downtime if properly orchestrated with load balancing or application-level failover.', '{"correct":"Creating a new VM with the desired size and migrating the application allows for zero downtime when combined with proper load balancing or application-level routing. You can test the new VM, migrate traffic gradually, and only deallocate the old VM once everything is working correctly.","why_others_wrong":{"0":"Stopping and resizing a VM requires downtime during the resize operation, which violates the no-downtime requirement.","1":"Azure Site Recovery is designed for disaster recovery, not for VM resizing, and would be overly complex for this scenario.","3":"VM scale sets are designed for multi-instance applications and wouldn''t apply to resizing a single VM instance."}}', '{"title":"Resize Azure VMs","url":"https://docs.microsoft.com/en-us/azure/virtual-machines/resize-vm"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6054, 'az-104', 'az-104-configure-manage-networking', 'Azure Bastion', 'Secure Access', 'single', 'easy', 'You need to provide secure RDP/SSH access to VMs in multiple VNets across different regions. The solution should minimize cost and management overhead while maintaining security. What should you implement?', '["Deploy Azure Bastion in each VNet","Deploy Azure Bastion in a hub VNet and peer all spoke VNets","Use Azure Bastion Standard SKU with IP-based connection","Configure point-to-site VPN with certificate authentication"]', '[1]', 'Hub-and-spoke topology with Azure Bastion in the hub VNet provides centralized management and cost optimization while maintaining security.', '{"correct":"Deploying Azure Bastion in a hub VNet and peering spoke VNets provides centralized secure access management, reduces costs (single Bastion instance), and simplifies administration. VNet peering allows Bastion to reach VMs in spoke VNets while maintaining network security.","why_others_wrong":{"0":"Deploying Bastion in each VNet increases costs significantly and creates management overhead with multiple Bastion instances to maintain.","2":"IP-based connection is a feature for connecting to on-premises VMs, not for multi-VNet scenarios in Azure.","3":"Point-to-site VPN requires client configuration on each device and doesn''t provide the browser-based access simplicity of Bastion."}}', '{"title":"Azure Bastion hub-spoke topology","url":"https://docs.microsoft.com/en-us/azure/bastion/vnet-peering"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6055, 'az-104', NULL, 'Azure AD', 'Conditional Access', 'multiple', 'difficult', 'You are configuring Conditional Access policies for a hybrid environment. Which conditions can be used to create adaptive policies? (Select all that apply)', '["User risk level from Azure AD Identity Protection","Sign-in risk level from Azure AD Identity Protection","Device compliance status from Microsoft Intune","Geographic location based on IP address","Time of day and day of week"]', '[0,1,2,3]', 'User risk, sign-in risk, device compliance, and location are all supported Conditional Access conditions. Time-based conditions are not directly supported.', '{"correct":"Azure AD Conditional Access supports user risk and sign-in risk from Identity Protection for detecting compromised accounts and suspicious sign-ins. Device compliance from Intune ensures only managed/compliant devices can access resources. Named locations allow geographic restrictions based on IP ranges.","why_others_wrong":{"4":"Time-based conditions (time of day, day of week) are not natively supported in Conditional Access policies. You would need to implement this through custom solutions or third-party tools."}}', '{"title":"Conditional Access conditions","url":"https://docs.microsoft.com/en-us/azure/active-directory/conditional-access/concept-conditional-access-conditions"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6056, 'az-104', NULL, 'Azure Monitor', 'Log Analytics', 'single', 'difficult', 'You need to create a KQL query to find all VMs that had CPU usage above 90% for more than 10 consecutive minutes in the last 24 hours. Which query approach is most efficient?', '["Use Perf table with bin() function and count aggregation","Use Perf table with prev() function to compare consecutive values","Use InsightsMetrics table with series_decompose() function","Use Perf table with sliding window and avg() aggregation"]', '[3]', 'Using sliding window aggregation with avg() function provides the most efficient way to identify sustained high CPU usage over a specific time period.', '{"correct":"A sliding window approach using bin() for time bucketing and avg() aggregation can efficiently identify periods where CPU usage remained consistently high. You can use row_window_session() or range operators to find consecutive high-usage periods exceeding the 10-minute threshold.","why_others_wrong":{"0":"Simple bin() and count aggregation doesn''t address the ''consecutive minutes'' requirement effectively.","1":"prev() function is less efficient for analyzing extended time periods and doesn''t directly solve the sliding window requirement.","2":"series_decompose() is used for time series analysis and anomaly detection, not for simple threshold monitoring over consecutive periods."}}', '{"title":"KQL time series analysis","url":"https://docs.microsoft.com/en-us/azure/azure-monitor/logs/aggregations"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6057, 'az-104', NULL, 'Azure Backup', 'VM Protection', 'multiple', 'easy', 'You need to implement backup for Azure VMs with the following requirements: application-consistent backups, cross-region restore capability, and encryption at rest. Which features should you enable? (Select all that apply)', '["Azure Backup with VSS (Volume Shadow Copy Service)","Geo-redundant storage (GRS) for Recovery Services vault","Azure Disk Encryption on the VMs","Cross Region Restore feature","Soft delete for backup data"]', '[0,1,3]', 'VSS enables application-consistent backups, GRS provides cross-region capability, and Cross Region Restore enables the restore functionality.', '{"correct":"VSS integration ensures application-consistent backups by coordinating with applications to flush data and create consistent snapshots. GRS replicates backup data to a secondary region. Cross Region Restore specifically enables the ability to restore VMs in the secondary region from GRS backup data.","why_others_wrong":{"2":"Azure Disk Encryption encrypts VM disks but doesn''t provide encryption at rest for backup data - Azure Backup provides its own encryption.","4":"Soft delete protects against accidental deletion but doesn''t address the specific requirements of application consistency, cross-region restore, or encryption at rest."}}', '{"title":"Azure Backup features","url":"https://docs.microsoft.com/en-us/azure/backup/backup-azure-vms-introduction"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6058, 'az-104', 'az-104-configure-manage-networking', 'Azure Front Door', 'Global Load Balancing', 'single', 'easy', 'You have a global web application with backends in East US, West Europe, and Southeast Asia. Users are experiencing slow response times from the Southeast Asia region. Azure Front Door is configured with default routing. What should you investigate first?', '["Backend health probe configuration and intervals","Session affinity settings in Front Door","SSL certificate configuration on backends","Network latency between Front Door edge locations and backends"]', '[0]', 'Backend health probe issues can cause Front Door to route traffic away from the closest (Southeast Asia) backend, resulting in increased latency.', '{"correct":"If the Southeast Asia backend is failing health probes, Front Door will route user traffic to the next available backend (likely West Europe or East US), causing increased latency for Southeast Asia users. Health probe configuration including probe path, interval, and timeout settings should be investigated first.","why_others_wrong":{"1":"Session affinity would cause users to stick to their initially assigned backend but wouldn''t specifically cause poor performance for a geographic region.","2":"SSL certificate issues would typically cause connection errors rather than slow response times.","3":"While network latency could be a factor, it''s less likely to suddenly change. Health probe failures are a more common cause of routing suboptimal traffic."}}', '{"title":"Azure Front Door health probes","url":"https://docs.microsoft.com/en-us/azure/frontdoor/front-door-health-probes"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6059, 'az-104', 'az-104-configure-manage-networking', 'Virtual WAN', 'SD-WAN Integration', 'multiple', 'easy', 'Your company is implementing Azure Virtual WAN for global connectivity. Which scenarios are best suited for Virtual WAN? (Select all that apply)', '["Connecting multiple branch offices to Azure and each other","Optimizing ExpressRoute circuits across multiple locations","Implementing site-to-site VPN with BGP routing","Providing user VPN (point-to-site) at scale","Simple hub-and-spoke topology with 3 spoke VNets"]', '[0,1,2,3]', 'Virtual WAN excels at complex multi-site connectivity, ExpressRoute optimization, large-scale VPN, and user VPN scenarios, but is overkill for simple topologies.', '{"correct":"Virtual WAN provides optimized routing for branch-to-branch and branch-to-Azure connectivity. It can optimize ExpressRoute by providing global reach and interconnection. It supports large-scale site-to-site VPN with BGP. User VPN service can scale to thousands of concurrent connections.","why_others_wrong":{"4":"A simple hub-and-spoke with only 3 spokes is better served by traditional VNet peering or standard VPN gateways. Virtual WAN adds unnecessary complexity and cost for small, simple topologies."}}', '{"title":"Azure Virtual WAN overview","url":"https://docs.microsoft.com/en-us/azure/virtual-wan/virtual-wan-about"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6060, 'az-104', 'az-104-deploy-manage-compute', 'App Service', 'Scaling and Performance', 'single', 'easy', 'Your App Service application experiences predictable traffic spikes every weekday from 9 AM to 5 PM. The application should scale out during these hours and scale in during off-hours to optimize costs. What scaling approach should you implement?', '["Configure manual scaling with performance counters","Use autoscale with schedule-based rules","Implement autoscale with metric-based rules using CPU percentage","Use Azure Functions consumption plan instead"]', '[1]', 'Schedule-based autoscale rules are perfect for predictable traffic patterns, allowing proactive scaling before traffic spikes occur.', '{"correct":"Schedule-based autoscale rules allow you to define specific times and days when scaling should occur. This is ideal for predictable patterns like business hours traffic. You can configure rules to scale out before 9 AM and scale in after 5 PM on weekdays, providing better performance and cost optimization.","why_others_wrong":{"0":"Manual scaling requires human intervention and doesn''t automatically respond to the predictable pattern.","2":"Metric-based rules are reactive - they scale after performance issues occur. For predictable patterns, proactive schedule-based scaling provides better user experience.","3":"Azure Functions consumption plan is for serverless scenarios and wouldn''t be appropriate for migrating an existing App Service application."}}', '{"title":"App Service autoscale","url":"https://docs.microsoft.com/en-us/azure/azure-monitor/autoscale/autoscale-get-started"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6061, 'az-104', 'az-104-configure-manage-networking', 'Private Link', 'Secure Connectivity', 'single', 'easy', 'You need to securely connect to Azure SQL Database from VMs in your VNet without traffic going over the public internet. The solution should prevent any public IP access to the database. What should you implement?', '["Configure service endpoints for Azure SQL Database on the VNet","Implement Private Link for Azure SQL Database","Use VNet-to-VNet peering with Azure SQL Database VNet","Configure an Application Gateway with backend pool pointing to SQL Database"]', '[1]', 'Private Link creates a private endpoint in your VNet, providing completely private connectivity to Azure SQL Database without any public internet exposure.', '{"correct":"Azure Private Link creates a private endpoint within your VNet that has a private IP address. This allows secure communication to Azure SQL Database over the Microsoft backbone network without any public internet exposure. You can also disable public network access on the SQL Database for complete isolation.","why_others_wrong":{"0":"Service endpoints still require the service to have a public IP and rely on service-level firewall rules. Traffic still goes over the Azure backbone but the service remains publicly accessible.","2":"Azure SQL Database is a PaaS service and doesn''t reside in a VNet that can be peered.","3":"Application Gateway cannot be used as a proxy for database connections - it''s designed for HTTP/HTTPS traffic, not database protocols."}}', '{"title":"Azure Private Link for SQL Database","url":"https://docs.microsoft.com/en-us/azure/azure-sql/database/private-endpoint-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6062, 'az-104', NULL, 'Azure Policy', 'Governance', 'multiple', 'easy', 'You need to implement governance policies that ensure all storage accounts are created with specific security configurations. Which Azure Policy effects should you consider? (Select all that apply)', '["Audit - to identify non-compliant storage accounts","Deny - to prevent creation of non-compliant storage accounts","DeployIfNotExists - to automatically apply security configurations","Modify - to change properties of existing storage accounts","Append - to add required tags to storage accounts"]', '[0,1,2,3,4]', 'All these policy effects can be used for storage account governance: Audit for monitoring, Deny for prevention, DeployIfNotExists for automatic configuration, Modify for remediation, and Append for tagging.', '{"correct":"Audit effect monitors compliance without blocking operations. Deny effect prevents non-compliant resource creation. DeployIfNotExists can automatically deploy related resources like diagnostic settings or backup configurations. Modify effect can change resource properties like enabling secure transfer. Append effect can add required tags or security configurations.","why_others_wrong":{"all_applicable":"This is a select-all scenario where all options are valid policy effects for storage account governance."}}', '{"title":"Azure Policy effects","url":"https://docs.microsoft.com/en-us/azure/governance/policy/concepts/effects"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6063, 'az-104', 'az-104-configure-manage-networking', 'Azure Firewall', 'Threat Intelligence', 'single', 'easy', 'You have Azure Firewall Premium deployed with threat intelligence enabled. A user reports they cannot access a legitimate website that was previously accessible. You suspect the site might be blocked by threat intelligence. What should you check first?', '["Azure Firewall application rules for explicit deny rules","Azure Firewall threat intelligence alerts and logs","Network security group rules on the user''s subnet","DNS resolution issues with Azure DNS"]', '[1]', 'Threat intelligence can dynamically block access to websites flagged as malicious. Checking threat intelligence alerts and logs will show if the site was blocked due to threat intelligence.', '{"correct":"Azure Firewall Premium with threat intelligence automatically blocks traffic to known malicious IP addresses and domains based on Microsoft''s threat intelligence feeds. These blocks are logged and can be reviewed in Azure Monitor logs. Sometimes legitimate sites may be temporarily flagged, requiring investigation of threat intelligence decisions.","why_others_wrong":{"0":"Application rules are static configurations, but threat intelligence blocks are dynamic and would show up in logs differently.","2":"NSG rules would affect connectivity but wouldn''t explain why a previously accessible site is now blocked.","3":"DNS resolution issues would typically result in different error messages than threat intelligence blocking."}}', '{"title":"Azure Firewall threat intelligence","url":"https://docs.microsoft.com/en-us/azure/firewall/threat-intel"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6064, 'az-104', 'az-104-configure-manage-networking', 'VPN Gateway', 'Site-to-Site Connectivity', 'single', 'easy', 'Your organization has a site-to-site VPN connection to Azure with BGP enabled. You notice that only some on-premises subnets can communicate with Azure VMs, while others cannot. On-premises routing appears correct. What is the most likely issue in Azure?', '["The VPN Gateway local network gateway configuration is missing subnet ranges","BGP peer IP configuration is incorrect on the VPN Gateway","Virtual network gateway subnet is too small","User-defined routes are overriding BGP routes"]', '[3]', 'When BGP is enabled, user-defined routes (UDRs) with the same or more specific prefixes can override BGP-learned routes, causing connectivity issues.', '{"correct":"In Azure, user-defined routes have higher priority than BGP routes. If there are UDRs configured with the same prefixes as on-premises subnets but pointing to different next hops (like a network virtual appliance), they will override the BGP-learned routes from the VPN Gateway, causing connectivity issues for those specific subnets.","why_others_wrong":{"0":"When BGP is enabled, the local network gateway''s address space is not used for routing - BGP advertisements handle route learning dynamically.","1":"If BGP peer IP was incorrect, no routes would be learned via BGP, affecting all subnets, not just some.","2":"Gateway subnet size affects deployment and scalability but wouldn''t cause selective routing issues."}}', '{"title":"Azure VPN Gateway BGP","url":"https://docs.microsoft.com/en-us/azure/vpn-gateway/vpn-gateway-bgp-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6065, 'az-104', 'az-104-implement-manage-storage', 'Azure Files', 'Access Control', 'multiple', 'easy', 'You are implementing Azure Files with Active Directory authentication for a hybrid environment. Which authentication methods are supported? (Select all that apply)', '["On-premises Active Directory Domain Services (AD DS)","Azure Active Directory Domain Services (Azure AD DS)","Azure Active Directory Kerberos for hybrid users","Storage account key authentication","Shared Access Signature (SAS) tokens"]', '[0,1,2,3,4]', 'Azure Files supports multiple authentication methods: on-premises AD DS, Azure AD DS, Azure AD Kerberos, storage account keys, and SAS tokens.', '{"correct":"Azure Files provides comprehensive authentication options. On-premises AD DS enables seamless integration with existing domain environments. Azure AD DS provides managed domain services in the cloud. Azure AD Kerberos allows hybrid users to authenticate using their Azure AD credentials. Storage account keys and SAS tokens provide programmatic access options.","why_others_wrong":{"all_applicable":"This is a select-all scenario where all options represent valid authentication methods for Azure Files."}}', '{"title":"Azure Files authentication","url":"https://docs.microsoft.com/en-us/azure/storage/files/storage-files-active-directory-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6066, 'az-104', 'az-104-configure-manage-networking', 'Network Watcher', 'Troubleshooting', 'single', 'easy', 'A user cannot connect to a VM in Azure from their on-premises location. You need to troubleshoot the connectivity issue systematically. Which Network Watcher tool should you use first?', '["IP flow verify to check if traffic is allowed by NSG rules","Connection troubleshoot to test end-to-end connectivity","Next hop to verify routing configuration","Security group view to see all applied security rules"]', '[1]', 'Connection troubleshoot provides comprehensive end-to-end connectivity testing and identifies where the connection is failing in the path.', '{"correct":"Connection troubleshoot performs comprehensive testing from source to destination, checking connectivity through all network components including NSGs, route tables, and network appliances. It provides detailed results showing exactly where connectivity fails and why, making it the best starting point for systematic troubleshooting.","why_others_wrong":{"0":"IP flow verify only checks NSG rules for a specific flow but doesn''t verify end-to-end connectivity or identify routing issues.","2":"Next hop helps verify routing but doesn''t check if traffic is actually allowed by security rules or if the destination is reachable.","3":"Security group view shows applied rules but doesn''t test actual connectivity or identify which rule might be blocking traffic."}}', '{"title":"Azure Network Watcher connection troubleshoot","url":"https://docs.microsoft.com/en-us/azure/network-watcher/network-watcher-connectivity-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6067, 'az-104', 'az-104-configure-manage-networking', 'Azure CDN', 'Performance Optimization', 'multiple', 'easy', 'You are configuring Azure CDN for a global e-commerce website. Which caching behaviors should you implement? (Select all that apply)', '["Cache static assets (images, CSS, JS) with long expiration times","Bypass cache for user authentication endpoints","Enable compression for text-based content","Cache product catalog pages with short expiration times","Use query string caching for personalized content"]', '[0,1,2,3]', 'Static assets should have long cache times, authentication should bypass cache, compression improves performance, and product pages need short expiration for freshness. Query string caching is not ideal for personalized content.', '{"correct":"Static assets rarely change and can be cached for long periods. Authentication endpoints must bypass cache to ensure security and user experience. Compression reduces bandwidth and improves load times. Product catalog pages need short expiration to balance performance with content freshness for pricing/inventory updates.","why_others_wrong":{"4":"Query string caching for personalized content defeats the purpose of CDN caching since personalized content should be unique per user and not cached at edge locations."}}', '{"title":"Azure CDN caching rules","url":"https://docs.microsoft.com/en-us/azure/cdn/cdn-caching-rules"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6068, 'az-104', 'az-104-configure-manage-networking', 'Azure Firewall', 'Network Address Translation', 'single', 'medium', 'You have Azure Firewall configured in a hub VNet with DNAT rules to allow external access to internal servers. Users report intermittent connectivity issues. You notice that the firewall has multiple public IP addresses. What is the most likely cause?', '["DNAT rules are conflicting with network rules","Source Network Address Translation (SNAT) port exhaustion","Health probe failures on backend servers","BGP routing issues with ExpressRoute"]', '[1]', 'With multiple public IPs and intermittent issues, SNAT port exhaustion is likely as the firewall runs out of available ports for outbound connections.', '{"correct":"SNAT port exhaustion occurs when there are many simultaneous outbound connections from internal servers through the firewall. Each public IP provides 64K ports, but with high connection volumes, ports can be exhausted. Intermittent connectivity is a classic symptom as connections succeed when ports are available but fail during peak usage.","why_others_wrong":{"0":"DNAT rule conflicts would cause consistent failures for specific services, not intermittent issues across all services.","2":"Health probe failures would affect inbound DNAT connections but wouldn''t explain intermittent outbound connectivity issues.","3":"BGP routing issues would affect routing decisions but wouldn''t cause intermittent connectivity - routes are either working or not."}}', '{"title":"Azure Firewall SNAT","url":"https://docs.microsoft.com/en-us/azure/firewall/snat-private-range"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6069, 'az-104', NULL, 'Managed Identity', 'Service Authentication', 'single', 'easy', 'You have an App Service that needs to access Azure Key Vault. You want to use managed identity for authentication. The App Service will be deployed across multiple environments (dev, test, prod) with different Key Vaults. What type of managed identity should you use?', '["System-assigned managed identity","User-assigned managed identity","Service principal with certificate authentication","Shared access signature from Key Vault"]', '[1]', 'User-assigned managed identity allows the same identity to be used across multiple environments and resources, providing better manageability for multi-environment scenarios.', '{"correct":"User-assigned managed identity can be created independently and assigned to multiple resources across different environments. This allows you to use the same identity across dev, test, and prod App Services while granting appropriate permissions to different Key Vaults. It provides better lifecycle management and consistency across environments.","why_others_wrong":{"0":"System-assigned managed identity is tied to the specific App Service instance and cannot be shared across multiple environments or resources.","2":"Service principal with certificate requires managing certificates and secrets, adding complexity compared to managed identity.","3":"SAS tokens are not the proper authentication method for applications to access Key Vault - they''re used for specific blob/queue access scenarios."}}', '{"title":"User-assigned managed identity","url":"https://docs.microsoft.com/en-us/azure/active-directory/managed-identities-azure-resources/overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6070, 'az-104', 'az-104-configure-manage-networking', 'Azure Load Balancer', 'Session Persistence', 'single', 'easy', 'You have a web application behind a Standard Load Balancer that maintains user session state locally. Users report being logged out randomly. The application requires users to stay connected to the same backend server. What should you configure?', '["Configure session persistence (affinity) to Client IP","Configure session persistence to Client IP and Protocol","Implement sticky sessions using Application Gateway instead","Configure health probes to detect session state"]', '[1]', 'Session persistence set to ''Client IP and Protocol'' ensures that requests from the same client IP using the same protocol always go to the same backend server.', '{"correct":"''Client IP and Protocol'' session persistence creates a hash based on both client IP address and protocol (TCP/UDP), ensuring that all requests from the same client using the same protocol are consistently routed to the same backend server. This maintains session affinity for stateful applications.","why_others_wrong":{"0":"''Client IP'' only considers IP address but not protocol, which might not provide sufficient granularity for applications using multiple protocols.","2":"While Application Gateway supports cookie-based session affinity, migrating to a different load balancing solution is more complex than configuring existing Load Balancer settings.","3":"Health probes detect server health, not session state. They wouldn''t solve the session persistence requirement."}}', '{"title":"Load Balancer session persistence","url":"https://docs.microsoft.com/en-us/azure/load-balancer/load-balancer-distribution-mode"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6071, 'az-104', 'az-104-configure-manage-networking', 'Network Security Groups', 'Traffic Analysis', 'multiple', 'medium', 'You need to analyze network traffic patterns and security threats in your Azure environment. Which NSG features should you enable? (Select all that apply)', '["NSG Flow Logs to capture traffic information","Traffic Analytics for flow log analysis and insights","Azure Security Center integration for threat detection","Diagnostic logs for NSG rule evaluation","Network Watcher packet capture for detailed analysis"]', '[0,1,3]', 'NSG Flow Logs capture traffic data, Traffic Analytics provides insights and visualization, and diagnostic logs show rule evaluation. Security Center and packet capture are separate tools.', '{"correct":"NSG Flow Logs capture detailed information about traffic allowed or denied by NSG rules. Traffic Analytics processes flow logs to provide insights, visualizations, and anomaly detection. Diagnostic logs provide information about NSG rule evaluation and processing.","why_others_wrong":{"2":"Azure Security Center (now Microsoft Defender for Cloud) provides security recommendations and threat detection but is not specifically an NSG feature - it''s a separate security service.","4":"Network Watcher packet capture is a separate troubleshooting tool, not an NSG feature. It captures packets for detailed analysis but is not part of NSG logging capabilities."}}', '{"title":"NSG Flow Logs overview","url":"https://docs.microsoft.com/en-us/azure/network-watcher/network-watcher-nsg-flow-logging-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6072, 'az-104', 'az-104-configure-manage-networking', 'ExpressRoute', 'Monitoring and Troubleshooting', 'single', 'medium', 'Your ExpressRoute circuit shows ''Enabled'' status but VMs in Azure cannot communicate with on-premises resources. BGP sessions are established. What should you check first?', '["ExpressRoute gateway configuration and routing tables","On-premises BGP route advertisements","Azure virtual network gateway subnet size","ExpressRoute circuit bandwidth utilization"]', '[1]', 'If BGP sessions are established but there''s no connectivity, the most likely issue is that on-premises routes are not being properly advertised to Azure.', '{"correct":"When BGP sessions are established but connectivity fails, the issue is typically with route advertisements. On-premises networks need to advertise their subnets via BGP for Azure VMs to know how to reach them. Check if the on-premises BGP router is properly advertising the required network prefixes.","why_others_wrong":{"0":"ExpressRoute gateway configuration issues would typically prevent BGP session establishment, not just connectivity after sessions are up.","2":"Gateway subnet size affects deployment and scalability but wouldn''t cause connectivity issues after successful BGP establishment.","3":"Bandwidth utilization would affect performance but not prevent basic connectivity when BGP sessions are working."}}', '{"title":"ExpressRoute BGP requirements","url":"https://docs.microsoft.com/en-us/azure/expressroute/expressroute-routing"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6073, 'az-104', 'az-104-deploy-manage-compute', 'Virtual Machine Scale Sets', 'Auto Scaling', 'single', 'easy', 'You have a VM Scale Set with autoscale configured based on CPU percentage. During a traffic spike, new instances are created but the application still performs poorly. What is the most likely cause?', '["The scale-out threshold is set too high","The cool-down period is too long","Application startup time is longer than the scale-out interval","Maximum instance count is reached"]', '[2]', 'If new instances are being created but performance remains poor, the application likely takes longer to start and become ready than the autoscale system expects.', '{"correct":"When autoscale creates new instances quickly but performance doesn''t improve, it usually indicates that the application has a long startup time or initialization period. The new VMs are running but the application isn''t yet ready to serve traffic effectively. This creates a lag between scaling events and actual capacity improvement.","why_others_wrong":{"0":"If the threshold was too high, new instances wouldn''t be created at all during the traffic spike.","1":"Cool-down period affects how frequently scaling can occur, but wouldn''t prevent performance improvement once new instances are created.","3":"If maximum instance count was reached, no new instances would be created, contradicting the scenario."}}', '{"title":"Virtual Machine Scale Sets autoscale","url":"https://docs.microsoft.com/en-us/azure/virtual-machine-scale-sets/virtual-machine-scale-sets-autoscale-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6074, 'az-104', 'az-104-configure-manage-networking', 'Azure VPN Gateway', 'Performance Optimization', 'multiple', 'easy', 'You need to optimize VPN Gateway performance for a high-bandwidth application. Which configurations should you consider? (Select all that apply)', '["Use VpnGw2 or higher SKU for better throughput","Configure multiple tunnels with ECMP (Equal-Cost Multi-Path)","Enable BGP for dynamic routing and redundancy","Use Route-based VPN instead of Policy-based","Configure custom IPsec/IKE policies for optimal encryption"]', '[0,1,2,3,4]', 'All these configurations contribute to VPN Gateway performance optimization: higher SKUs provide more throughput, ECMP enables load distribution, BGP improves routing, route-based VPN is more flexible, and custom policies can optimize encryption overhead.', '{"correct":"Higher SKUs (VpnGw2+) provide increased bandwidth and connection limits. ECMP allows traffic distribution across multiple tunnels for better throughput. BGP provides dynamic routing and automatic failover. Route-based VPN supports multiple tunnels and better routing flexibility. Custom IPsec/IKE policies allow optimization of encryption algorithms for the best balance of security and performance.","why_others_wrong":{"all_applicable":"This is a comprehensive optimization scenario where all options contribute to improved VPN Gateway performance."}}', '{"title":"VPN Gateway performance optimization","url":"https://docs.microsoft.com/en-us/azure/vpn-gateway/vpn-gateway-about-vpngateways"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6075, 'az-104', 'az-104-implement-manage-storage', 'Managed Disks', 'Performance Tuning', 'single', 'easy', 'You have a database server that requires consistent high IOPS performance. The workload shows spiky patterns with periods of very high I/O demand. Which disk type should you choose?', '["Standard SSD with disk caching enabled","Premium SSD with disk caching enabled","Ultra Disk with provisioned IOPS","Premium SSD v2 with adjustable IOPS"]', '[2]', 'Ultra Disk provides consistent, predictable performance with provisioned IOPS that can handle spiky workloads without performance degradation.', '{"correct":"Ultra Disk offers the highest and most consistent performance with provisioned IOPS and throughput. It provides sub-millisecond latency and can handle spiky workloads without the performance variability that comes with credit-based systems. For database workloads requiring consistent high IOPS, Ultra Disk is the optimal choice.","why_others_wrong":{"0":"Standard SSD has lower IOPS limits and uses a credit system that may not sustain high performance during spiky workloads.","1":"Premium SSD uses a credit-based system for bursting, which may not provide consistent performance during sustained high I/O periods.","3":"Premium SSD v2 offers good performance but Ultra Disk provides even higher IOPS limits and more consistent latency for extreme database workloads."}}', '{"title":"Azure disk types comparison","url":"https://docs.microsoft.com/en-us/azure/virtual-machines/disks-types"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6076, 'az-104', 'az-104-configure-manage-networking', 'Azure DNS', 'Hybrid DNS', 'single', 'medium', 'You have a hybrid environment where Azure VMs need to resolve both Azure-hosted services and on-premises DNS names. On-premises systems also need to resolve Azure private DNS zones. What is the recommended DNS architecture?', '["Use Azure DNS forwarders in both directions","Configure conditional forwarding on on-premises DNS servers","Deploy custom DNS servers in Azure with forwarder configuration","Use Azure Private DNS zones with VNet links only"]', '[2]', 'Custom DNS servers in Azure with proper forwarder configuration provide the most flexible and reliable solution for bidirectional DNS resolution in hybrid environments.', '{"correct":"Custom DNS servers in Azure can be configured with conditional forwarders to send Azure-specific queries to Azure DNS (168.63.129.16) and on-premises queries to on-premises DNS servers. This provides centralized DNS management for Azure VMs while enabling bidirectional resolution between Azure and on-premises environments.","why_others_wrong":{"0":"Azure DNS forwarders alone cannot handle the complexity of bidirectional resolution and custom DNS zones effectively.","1":"Conditional forwarding on on-premises DNS servers helps on-premises resolution but doesn''t solve Azure VM DNS requirements for hybrid scenarios.","3":"Azure Private DNS zones with VNet links don''t provide resolution for on-premises names and don''t enable on-premises systems to resolve Azure private zones."}}', '{"title":"Hybrid DNS solutions","url":"https://docs.microsoft.com/en-us/azure/dns/private-dns-scenarios"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6077, 'az-104', NULL, 'Azure RBAC', 'Custom Roles', 'multiple', 'easy', 'You need to create a custom role for database administrators who should be able to manage SQL databases but not modify networking or security configurations. Which permissions should be included? (Select all that apply)', '["Microsoft.Sql/servers/databases/*","Microsoft.Sql/servers/databases/read","Microsoft.Sql/servers/firewallRules/read","Microsoft.Sql/servers/firewallRules/*","Microsoft.Network/*/read"]', '[0,2,4]', 'Database administrators need full database management permissions, read access to firewall rules for troubleshooting, and network read permissions for monitoring, but not write access to security configurations.', '{"correct":"Microsoft.Sql/servers/databases/* provides complete database management capabilities. Microsoft.Sql/servers/firewallRules/read allows viewing firewall configurations for troubleshooting without modification rights. Microsoft.Network/*/read provides visibility into network configurations affecting database connectivity.","why_others_wrong":{"1":"Microsoft.Sql/servers/databases/read is redundant when Microsoft.Sql/servers/databases/* is included, as the latter includes read permissions.","3":"Microsoft.Sql/servers/firewallRules/* would allow modifying firewall rules, which violates the requirement to not modify security configurations."}}', '{"title":"Azure custom roles","url":"https://docs.microsoft.com/en-us/azure/role-based-access-control/custom-roles"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6078, 'az-104', 'az-104-configure-manage-networking', 'Application Gateway', 'SSL/TLS Management', 'single', 'easy', 'You have Application Gateway configured with end-to-end SSL encryption. Backend servers use self-signed certificates. Users report SSL/TLS errors. What should you configure to resolve this?', '["Upload the backend server certificates to Application Gateway","Configure HTTP health probes instead of HTTPS","Enable SSL certificate validation bypass","Use Azure Key Vault integration for certificate management"]', '[0]', 'For end-to-end SSL with self-signed certificates, Application Gateway needs the backend certificates uploaded as trusted root certificates to validate the backend SSL connections.', '{"correct":"When using end-to-end SSL encryption with self-signed certificates on backend servers, Application Gateway must validate these certificates. Since self-signed certificates aren''t trusted by default, you need to upload the backend server certificates (or their root CA) to Application Gateway as authentication certificates or trusted root certificates.","why_others_wrong":{"1":"Changing to HTTP health probes doesn''t solve the SSL/TLS connection issues for actual traffic and reduces security.","2":"SSL certificate validation bypass is not a standard Application Gateway feature and would compromise security.","3":"Key Vault integration helps with frontend certificate management but doesn''t resolve backend certificate validation issues."}}', '{"title":"Application Gateway end-to-end SSL","url":"https://docs.microsoft.com/en-us/azure/application-gateway/ssl-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6079, 'az-104', NULL, 'Azure Monitor', 'Custom Metrics', 'single', 'easy', 'You need to create custom alerts based on application-specific metrics that are not available in Azure Monitor by default. Your application is running on Azure VMs. What is the most efficient approach?', '["Use Azure Monitor REST API to send custom metrics","Install Azure Monitor Agent and configure custom performance counters","Use Application Insights SDK to send custom telemetry","Configure Log Analytics workspace with custom logs"]', '[1]', 'Azure Monitor Agent with custom performance counters provides the most efficient and integrated way to collect application-specific metrics from VMs and use them for alerting.', '{"correct":"Azure Monitor Agent (AMA) can be configured to collect custom performance counters from Windows or custom metrics from Linux applications. These metrics are automatically integrated into Azure Monitor metrics store, allowing for standard metric alerts, dashboards, and analysis. This provides the most seamless integration with Azure Monitor''s alerting capabilities.","why_others_wrong":{"0":"REST API works but requires more development effort and doesn''t provide the same level of integration as native agent-based collection.","2":"Application Insights is primarily for web applications and provides different telemetry types, not VM-based custom metrics for infrastructure alerting.","3":"Log Analytics custom logs are for log-based data, not metrics, and would require log-based alerts which are less efficient than metric alerts."}}', '{"title":"Azure Monitor Agent overview","url":"https://docs.microsoft.com/en-us/azure/azure-monitor/agents/azure-monitor-agent-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6080, 'az-104', 'az-104-configure-manage-networking', 'Azure Firewall', 'High Availability', 'multiple', 'difficult', 'You are designing a highly available Azure Firewall deployment for a mission-critical application. Which configurations should you implement? (Select all that apply)', '["Deploy Azure Firewall across multiple Availability Zones","Configure multiple public IP addresses for SNAT scaling","Implement Azure Firewall Manager for centralized policy management","Use multiple Azure Firewall instances with load balancer","Configure forced tunneling for hybrid connectivity"]', '[0,1,2]', 'Availability Zones provide zone redundancy, multiple public IPs prevent SNAT exhaustion, and Firewall Manager enables centralized management. Multiple instances with load balancer is not a supported pattern.', '{"correct":"Deploying across Availability Zones ensures the firewall survives zone failures. Multiple public IP addresses prevent SNAT port exhaustion and provide better outbound connectivity scaling. Azure Firewall Manager provides centralized policy management across multiple firewalls and enables easier maintenance and consistency.","why_others_wrong":{"3":"Azure Firewall doesn''t support deployment behind a load balancer - it''s designed to be zone-redundant natively. Multiple firewall instances would be in different VNets or regions, not load-balanced.","4":"Forced tunneling is a specific configuration for routing internet traffic through on-premises, not a high availability feature."}}', '{"title":"Azure Firewall availability zones","url":"https://docs.microsoft.com/en-us/azure/firewall/deploy-availability-zone-powershell"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6081, 'az-104', 'az-104-configure-manage-networking', 'Virtual Network', 'IP Address Management', 'single', 'easy', 'You need to implement a solution where multiple VNets can share a common set of IP addresses for outbound internet connectivity, but each VNet should maintain its own private IP space. What should you implement?', '["VNet peering with shared NAT Gateway","Hub-and-spoke topology with Azure Firewall","Azure Virtual WAN with shared services","Virtual Network NAT with multiple VNets"]', '[1]', 'Hub-and-spoke topology with Azure Firewall allows multiple spoke VNets to share common outbound IP addresses while maintaining separate private IP spaces.', '{"correct":"In a hub-and-spoke topology with Azure Firewall, each spoke VNet maintains its own private IP address space but routes outbound traffic through the hub VNet where Azure Firewall provides NAT functionality using shared public IP addresses. This centralizes outbound connectivity while preserving network isolation.","why_others_wrong":{"0":"NAT Gateway cannot be directly shared across multiple VNets - each NAT Gateway is associated with specific subnets within a single VNet.","2":"Virtual WAN provides optimized connectivity but doesn''t specifically address the requirement for shared outbound IP addresses.","3":"Virtual Network NAT is configured per VNet/subnet and doesn''t provide cross-VNet IP sharing capabilities."}}', '{"title":"Hub-spoke network topology","url":"https://docs.microsoft.com/en-us/azure/architecture/reference-architectures/hybrid-networking/hub-spoke"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6082, 'az-104', 'az-104-implement-manage-storage', 'Backup and Recovery', 'Cross-Region Recovery', 'multiple', 'easy', 'Your organization requires the ability to recover critical data in a different Azure region in case of a regional disaster. Which storage replication and backup strategies should you implement? (Select all that apply)', '["Geo-redundant storage (GRS) for automatic cross-region replication","Azure Backup with cross-region restore enabled","Azure Site Recovery for VM replication","Read-access geo-redundant storage (RA-GRS) for read access to secondary region","Zone-redundant storage (ZRS) for local high availability"]', '[0,1,2,3]', 'GRS provides cross-region replication, Azure Backup with cross-region restore enables recovery in secondary regions, Site Recovery replicates VMs, and RA-GRS provides read access. ZRS only provides local redundancy.', '{"correct":"GRS automatically replicates data to a secondary region for disaster recovery. Azure Backup with cross-region restore allows restoring backups in the secondary region. Azure Site Recovery provides VM replication and orchestrated failover to secondary regions. RA-GRS provides the same cross-region protection as GRS plus read access to the secondary region during normal operations.","why_others_wrong":{"4":"ZRS provides high availability within a single region across availability zones but doesn''t provide cross-region disaster recovery capabilities."}}', '{"title":"Azure storage redundancy","url":"https://docs.microsoft.com/en-us/azure/storage/common/storage-redundancy"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6083, 'az-104', 'az-104-configure-manage-networking', 'Private Endpoints', 'DNS Integration', 'single', 'easy', 'You have deployed private endpoints for Azure Storage in your VNet. Applications can connect using the private IP, but DNS resolution still returns the public IP address. What is the most likely cause?', '["Private endpoint is not properly linked to the storage account","Private DNS zone is not linked to the VNet","Network security group is blocking DNS traffic","Azure DNS is caching the old public IP address"]', '[1]', 'When private endpoints work with IP addresses but DNS resolution returns public IPs, the private DNS zone is typically not linked to the VNet or the A record is missing.', '{"correct":"Private endpoints automatically create private DNS zones (like privatelink.blob.core.windows.net) with A records pointing to the private endpoint''s IP address. However, for VMs in the VNet to resolve these private DNS records, the private DNS zone must be linked to the VNet. Without this link, DNS queries will resolve to the public IP address.","why_others_wrong":{"0":"If the private endpoint wasn''t properly linked, applications wouldn''t be able to connect using the private IP address at all.","2":"NSG rules affect network connectivity but don''t typically block DNS resolution unless specifically configured to do so.","3":"DNS caching would eventually expire and refresh, and this is more likely a configuration issue than a caching problem."}}', '{"title":"Private endpoint DNS configuration","url":"https://docs.microsoft.com/en-us/azure/private-link/private-endpoint-dns"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6084, 'az-104', 'az-104-deploy-manage-compute', 'Container Instances', 'Networking', 'single', 'easy', 'You need to deploy Azure Container Instances that can communicate with resources in your existing VNet while also having outbound internet access. The containers should not be directly accessible from the internet. What should you configure?', '["Deploy ACI with VNet integration and public IP assignment","Deploy ACI with VNet integration and NAT Gateway for outbound access","Use Azure Container Apps with private networking","Deploy ACI in a subnet with Network Security Group restrictions"]', '[1]', 'VNet integration places ACI in your private network, while NAT Gateway provides secure outbound internet access without exposing containers to inbound traffic.', '{"correct":"VNet integration allows Azure Container Instances to be deployed into a subnet in your VNet, enabling private communication with other resources. NAT Gateway provides outbound internet access for the subnet without requiring public IP addresses on the containers, maintaining security while enabling required connectivity.","why_others_wrong":{"0":"Public IP assignment would make containers directly accessible from the internet, violating the security requirement.","2":"Container Apps is a different service and wouldn''t address the specific ACI requirement in this scenario.","3":"NSG restrictions alone don''t provide outbound internet access - they only filter traffic but don''t enable connectivity that doesn''t exist."}}', '{"title":"Azure Container Instances VNet integration","url":"https://docs.microsoft.com/en-us/azure/container-instances/container-instances-vnet"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6085, 'az-104', 'az-104-configure-manage-networking', 'Azure Front Door', 'Security', 'multiple', 'medium', 'You are implementing Azure Front Door with Web Application Firewall for a global web application. Which security features should you configure? (Select all that apply)', '["Rate limiting rules to prevent abuse","Geo-filtering to block traffic from specific countries","Custom rules based on IP addresses and HTTP headers","OWASP rule sets for common web vulnerabilities","DDoS protection for backend servers"]', '[0,1,2,3]', 'Rate limiting, geo-filtering, custom rules, and OWASP rule sets are all WAF features. DDoS protection is automatically provided by Azure platform, not a WAF configuration.', '{"correct":"Azure Front Door WAF supports rate limiting to prevent abuse and bot attacks, geo-filtering to allow or block traffic from specific countries, custom rules for application-specific security logic, and OWASP Core Rule Set for protection against common web vulnerabilities like SQL injection and XSS.","why_others_wrong":{"4":"DDoS protection is automatically provided by the Azure platform for all Front Door deployments and is not a configurable WAF feature. Backend servers are protected by Front Door''s inherent DDoS protection."}}', '{"title":"Azure Front Door WAF","url":"https://docs.microsoft.com/en-us/azure/web-application-firewall/afds/afds-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6086, 'az-104', NULL, 'Azure AD Connect', 'Hybrid Identity', 'single', 'easy', 'Your organization has multiple on-premises Active Directory forests that need to synchronize with Azure AD. Some users exist in multiple forests with different attributes. What Azure AD Connect configuration should you implement?', '["Single Azure AD Connect instance with multiple forest connectors","Multiple Azure AD Connect instances, one per forest","Azure AD Connect cloud sync for each forest","Federated identity with ADFS for each forest"]', '[0]', 'A single Azure AD Connect instance can connect to multiple forests and handle attribute merging for users that exist across forests, providing centralized identity management.', '{"correct":"Azure AD Connect supports multi-forest topologies through a single instance with multiple forest connectors. It can handle complex scenarios where users exist in multiple forests by merging attributes and maintaining a single identity in Azure AD. This approach provides centralized management and consistent synchronization rules.","why_others_wrong":{"1":"Multiple Azure AD Connect instances would create conflicts when trying to synchronize the same users from different forests to the same Azure AD tenant.","2":"Azure AD Connect cloud sync is simpler but doesn''t handle complex multi-forest scenarios with overlapping users as effectively as the full Azure AD Connect.","3":"ADFS provides federation but doesn''t address the synchronization and attribute merging requirements for users across multiple forests."}}', '{"title":"Azure AD Connect multi-forest","url":"https://docs.microsoft.com/en-us/azure/active-directory/hybrid/plan-connect-topologies"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6087, 'az-104', 'az-104-configure-manage-networking', 'Service Endpoints', 'Security Configuration', 'single', 'easy', 'You have enabled service endpoints for Azure Storage on a subnet, but VMs in that subnet still cannot access the storage account. The storage account firewall is configured to allow the VNet. What additional configuration is required?', '["Add the specific subnet to the storage account firewall rules","Configure route tables to direct storage traffic through service endpoints","Enable service endpoint policy on the subnet","Add service endpoint delegation to the subnet"]', '[0]', 'When using service endpoints, you must explicitly add the subnet (not just the VNet) to the storage account firewall rules to allow access from that specific subnet.', '{"correct":"Service endpoints require specific subnet-level configuration in the storage account firewall. Even if service endpoints are enabled on the subnet, the storage account firewall must explicitly allow that specific subnet. VNet-level permission is not sufficient - you need to add the individual subnet to the storage account''s network access rules.","why_others_wrong":{"1":"Service endpoints handle routing automatically - no manual route table configuration is needed.","2":"Service endpoint policies are used to restrict which storage accounts can be accessed, not to enable basic access.","3":"Service endpoint delegation is for different scenarios (like SQL Managed Instance) and not required for storage service endpoints."}}', '{"title":"Storage account service endpoints","url":"https://docs.microsoft.com/en-us/azure/storage/common/storage-network-security"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6088, 'az-104', NULL, 'Azure Monitor', 'Workbooks', 'single', 'medium', 'You need to create a custom dashboard that combines metrics from multiple Azure services, includes interactive parameters, and supports drill-down capabilities. Which Azure Monitor feature should you use?', '["Azure Dashboards with metric charts","Azure Monitor Workbooks","Log Analytics dashboard","Application Insights dashboard"]', '[1]', 'Azure Monitor Workbooks provide interactive, customizable reports that can combine multiple data sources with parameters and drill-down capabilities.', '{"correct":"Azure Monitor Workbooks are designed for interactive reporting and analysis. They support combining metrics and logs from multiple services, interactive parameters that can filter data dynamically, drill-down capabilities through linked charts and queries, and rich visualization options. They''re perfect for complex, interactive dashboards.","why_others_wrong":{"0":"Azure Dashboards provide basic metric visualization but lack the interactive parameters and advanced drill-down capabilities.","1":"Log Analytics dashboards are primarily for log-based data and don''t integrate metrics as seamlessly as Workbooks.","3":"Application Insights dashboards are specific to Application Insights data and don''t support multi-service scenarios as comprehensively."}}', '{"title":"Azure Monitor Workbooks","url":"https://docs.microsoft.com/en-us/azure/azure-monitor/visualize/workbooks-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6089, 'az-104', 'az-104-configure-manage-networking', 'Network Virtual Appliance', 'Routing and Connectivity', 'single', 'easy', 'You deployed a network virtual appliance (NVA) in your hub VNet to inspect traffic between spoke VNets. Traffic between spokes is not flowing through the NVA despite correct route table configurations. What is the most likely missing configuration?', '["IP forwarding is not enabled on the NVA network interface","Network security groups are blocking traffic to the NVA","The NVA subnet does not have a route to the spokes","BGP is not configured on the NVA"]', '[0]', 'IP forwarding must be enabled on the NVA''s network interface for it to route traffic between different subnets that it''s not directly connected to.', '{"correct":"Azure network interfaces have IP forwarding disabled by default for security reasons. When deploying an NVA that needs to route traffic between different networks (like spoke VNets), you must explicitly enable IP forwarding on the NVA''s network interface. Without this, the NVA will receive traffic but cannot forward it to other destinations.","why_others_wrong":{"1":"NSG blocking would typically generate logs and cause connectivity failures rather than traffic simply not flowing through the NVA.","2":"If route tables are configured correctly, the NVA subnet routing should be working. This is more likely an IP forwarding issue.","3":"BGP is not required for basic NVA routing functionality in hub-spoke topologies - static routes via route tables are sufficient."}}', '{"title":"Enable IP forwarding","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-network-interface#enable-or-disable-ip-forwarding"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6090, 'az-104', NULL, 'Azure Site Recovery', 'Disaster Recovery Planning', 'multiple', 'easy', 'You are implementing Azure Site Recovery for disaster recovery of on-premises VMware VMs to Azure. Which components are required? (Select all that apply)', '["Configuration server on-premises","Process server for data replication","Master target server in Azure","Mobility service on protected VMs","Recovery Services vault in Azure"]', '[0,1,3,4]', 'VMware to Azure replication requires configuration server, process server, mobility service, and Recovery Services vault. Master target server is not needed for Azure as the target.', '{"correct":"Configuration server coordinates replication and manages communication with Azure. Process server handles replication data, caching, compression, and encryption. Mobility service must be installed on each VM to capture and send replication data. Recovery Services vault stores replication policies and manages recovery points in Azure.","why_others_wrong":{"2":"Master target server is used for VMware-to-VMware replication scenarios. When replicating to Azure, Azure storage acts as the target, eliminating the need for a separate master target server."}}', '{"title":"VMware to Azure Site Recovery","url":"https://docs.microsoft.com/en-us/azure/site-recovery/vmware-azure-architecture"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6091, 'az-104', 'az-104-configure-manage-networking', 'Azure Bastion', 'Advanced Configuration', 'single', 'medium', 'You need to enable file transfer capabilities and support for native RDP/SSH clients when using Azure Bastion. Which Bastion SKU and configuration should you implement?', '["Basic SKU with custom port configuration","Standard SKU with native client support enabled","Premium SKU with file transfer extensions","Standard SKU with file upload/download feature enabled"]', '[1]', 'Standard SKU supports native client connections and file transfers, while Basic SKU only supports browser-based connections.', '{"correct":"Azure Bastion Standard SKU provides advanced features including support for native RDP and SSH clients, file upload/download capabilities, and other enhanced features. The native client support allows users to connect using their local RDP or SSH clients while still benefiting from Bastion''s security.","why_others_wrong":{"0":"Basic SKU only supports browser-based connections and doesn''t provide file transfer or native client capabilities.","2":"There is no Premium SKU for Azure Bastion - Standard is the highest tier available.","3":"While Standard SKU does support file upload/download, the key differentiator mentioned in the question is native client support, which is the primary feature that enables both file transfer and native client connectivity."}}', '{"title":"Azure Bastion SKUs and features","url":"https://docs.microsoft.com/en-us/azure/bastion/bastion-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6092, 'az-104', 'az-104-implement-manage-storage', 'Azure Files', 'Performance Optimization', 'multiple', 'medium', 'You have an Azure Files share that experiences performance issues during peak usage. Which optimization strategies should you consider? (Select all that apply)', '["Upgrade to Premium Files for higher IOPS and throughput","Enable large file shares for increased capacity and performance","Implement Azure File Sync for local caching","Configure multiple storage accounts for load distribution","Use SMB Multichannel for improved bandwidth utilization"]', '[0,1,2,4]', 'Premium Files, large file shares, File Sync caching, and SMB Multichannel all improve performance. Multiple storage accounts don''t directly improve single share performance.', '{"correct":"Premium Files provides significantly higher IOPS and throughput with SSD-based storage. Large file shares increase both capacity and performance limits. Azure File Sync provides local caching to reduce latency for frequently accessed files. SMB Multichannel uses multiple network connections to improve bandwidth utilization and performance.","why_others_wrong":{"3":"Multiple storage accounts can help with overall scalability but don''t improve the performance of a single Azure Files share. This approach adds complexity without directly addressing the performance issue of the specific share."}}', '{"title":"Azure Files performance optimization","url":"https://docs.microsoft.com/en-us/azure/storage/files/storage-files-scale-targets"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6093, 'az-104', 'az-104-configure-manage-networking', 'Load Balancer', 'Troubleshooting', 'single', 'medium', 'Your Standard Load Balancer health probes are failing, but you can manually connect to the backend VMs on the probe port. The VMs are in different Availability Zones. What is the most likely cause?', '["Health probe interval is too frequent","Backend VMs are not responding to health probe requests correctly","Load balancer is experiencing cross-zone latency issues","Network security group is blocking the health probe source IP"]', '[3]', 'Health probes originate from specific Azure infrastructure IP addresses that must be allowed in NSG rules for probes to succeed.', '{"correct":"Azure Load Balancer health probes originate from the IP address 168.63.129.16 (Azure metadata service). If NSG rules don''t explicitly allow traffic from this IP address to the health probe port, probes will fail even if manual connections to the VMs work from other sources. This is a common configuration oversight.","why_others_wrong":{"0":"Probe interval frequency doesn''t cause probe failures - it only affects how quickly failures are detected.","1":"If manual connections work on the same port, the VMs are likely responding correctly. The issue is more likely network-level blocking.","2":"Standard Load Balancer is designed to work across Availability Zones and cross-zone latency shouldn''t cause health probe failures."}}', '{"title":"Load Balancer health probes","url":"https://docs.microsoft.com/en-us/azure/load-balancer/load-balancer-custom-probe-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6094, 'az-104', 'az-104-deploy-manage-compute', 'Azure Batch', 'Scaling and Cost Optimization', 'single', 'easy', 'You need to run large-scale parallel workloads that have variable compute requirements throughout the day. The workload can tolerate interruptions. What Azure Batch configuration provides the best cost optimization?', '["Dedicated pools with auto-scale enabled","Low-priority pools with auto-scale enabled","Spot VMs with manual scaling","User subscription pools with reserved instances"]', '[1]', 'Low-priority pools use Azure''s excess capacity at significantly reduced cost and support auto-scaling, making them ideal for interruptible parallel workloads.', '{"correct":"Low-priority VMs in Azure Batch can provide up to 80% cost savings compared to dedicated VMs by using Azure''s excess capacity. Since the workload can tolerate interruptions and has variable requirements, auto-scaling with low-priority pools provides the optimal combination of cost savings and automatic resource management.","why_others_wrong":{"0":"Dedicated pools provide guaranteed capacity but at full price, missing the cost optimization opportunity for interruptible workloads.","2":"Manual scaling requires human intervention and doesn''t automatically adjust to variable workload demands.","3":"Reserved instances require long-term commitments and are better for predictable workloads, not variable parallel processing jobs."}}', '{"title":"Azure Batch low-priority VMs","url":"https://docs.microsoft.com/en-us/azure/batch/batch-low-pri-vms"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6095, 'az-104', 'az-104-configure-manage-networking', 'Azure Firewall', 'Rule Processing', 'single', 'easy', 'You have Azure Firewall with the following rule collections configured:
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6096, 'az-104', NULL, 'Privileged Identity Management', 'Just-in-Time Access', 'multiple', 'easy', 'You are implementing Azure AD Privileged Identity Management (PIM) for administrative roles. Which features should you configure for enhanced security? (Select all that apply)', '["Just-in-time activation with time-limited access","Multi-factor authentication requirement for role activation","Approval workflow for sensitive role activations","Regular access reviews for permanent assignments","Conditional Access policies for privileged accounts"]', '[0,1,2,3,4]', 'All these features enhance PIM security: JIT activation reduces exposure time, MFA adds authentication security, approval workflows add oversight, access reviews ensure ongoing appropriateness, and Conditional Access adds policy-based controls.', '{"correct":"Just-in-time activation minimizes the window of exposure for privileged access. MFA ensures strong authentication when activating roles. Approval workflows provide additional oversight for sensitive roles. Regular access reviews ensure that permanent assignments remain appropriate. Conditional Access policies can enforce additional security requirements for privileged accounts like device compliance or location restrictions.","why_others_wrong":{"all_applicable":"This is a comprehensive security scenario where all options represent valid and recommended PIM security features."}}', '{"title":"Azure AD Privileged Identity Management","url":"https://docs.microsoft.com/en-us/azure/active-directory/privileged-identity-management/pim-configure"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6097, 'az-104', 'az-104-configure-manage-networking', 'Network Security Groups', 'Advanced Filtering', 'single', 'difficult', 'You need to create an NSG rule that allows HTTPS traffic from any source but only to VMs that have a specific tag value. The environment has hundreds of VMs across multiple subnets. What is the most efficient approach?', '["Create separate NSG rules for each VM''s IP address","Use Application Security Groups to group tagged VMs","Create subnet-level NSG rules with IP address ranges","Use service tags to identify the target VMs"]', '[1]', 'Application Security Groups allow logical grouping of VMs based on their role or characteristics, making it easy to apply security rules to tagged VMs regardless of their IP addresses or subnets.', '{"correct":"Application Security Groups (ASGs) provide application-centric security by allowing you to group VMs logically rather than by IP address. You can assign VMs with specific tags to an ASG and then create NSG rules that reference the ASG as the destination. This approach scales well and is maintainable as VMs can be added/removed from ASGs without updating NSG rules.","why_others_wrong":{"0":"Creating separate rules for each VM''s IP address is not scalable and becomes unmanageable with hundreds of VMs.","2":"Subnet-level rules with IP ranges don''t address the requirement to filter based on VM tags - they would apply to all VMs in those ranges.","3":"Service tags are predefined by Azure for Azure services and cannot be customized to identify VMs based on custom tags."}}', '{"title":"Application Security Groups","url":"https://docs.microsoft.com/en-us/azure/virtual-network/application-security-groups"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6098, 'az-104', 'az-104-implement-manage-storage', 'Azure Data Lake Storage', 'Access Control', 'single', 'easy', 'You have Azure Data Lake Storage Gen2 with hierarchical namespace enabled. You need to provide different levels of access to various teams: data engineers need full access, analysts need read access to specific folders, and auditors need read access to everything. What access control method should you implement?', '["Azure RBAC roles only","POSIX ACLs only","Combination of Azure RBAC and POSIX ACLs","Shared access signatures for each team"]', '[2]', 'Azure Data Lake Storage Gen2 with hierarchical namespace supports both Azure RBAC for broad permissions and POSIX ACLs for fine-grained, folder-level access control.', '{"correct":"The optimal approach combines Azure RBAC for broad permissions (like Storage Blob Data Reader for auditors) with POSIX ACLs for fine-grained control (specific folder access for analysts). Azure RBAC provides efficient management of broad access patterns, while POSIX ACLs enable precise control over files and folders in the hierarchical namespace.","why_others_wrong":{"0":"Azure RBAC alone cannot provide the fine-grained, folder-level access control needed for analysts who need access to specific folders only.","1":"POSIX ACLs alone would require managing permissions at the file/folder level for all users, which is complex for broad access patterns like ''read everything'' for auditors.","3":"SAS tokens provide time-limited access but don''t integrate with identity management and are harder to manage for ongoing team access requirements."}}', '{"title":"Data Lake Storage Gen2 access control","url":"https://docs.microsoft.com/en-us/azure/storage/blobs/data-lake-storage-access-control"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6099, 'az-104', 'az-104-configure-manage-networking', 'Azure Traffic Manager', 'Failover Configuration', 'single', 'easy', 'You have a global application with primary deployment in East US and backup in West Europe. You want all traffic to go to East US normally, but automatically failover to West Europe if East US becomes unhealthy. Which Traffic Manager routing method should you use?', '["Performance routing with priority configuration","Priority routing with East US as priority 1","Geographic routing with fallback to West Europe","Weighted routing with 100% weight to East US"]', '[1]', 'Priority routing method sends all traffic to the highest priority (lowest number) healthy endpoint, with automatic failover to lower priority endpoints when the primary fails.', '{"correct":"Priority routing method is designed exactly for this scenario. You assign priority 1 to East US (highest priority) and priority 2 to West Europe. All traffic flows to East US while it''s healthy. When East US fails health checks, Traffic Manager automatically redirects all traffic to West Europe. When East US recovers, traffic automatically returns to it.","why_others_wrong":{"0":"Performance routing directs users to the closest endpoint based on latency, not based on a primary/backup preference.","2":"Geographic routing distributes traffic based on user location, not health-based failover patterns.","3":"Weighted routing with 100% weight doesn''t provide automatic failover - if the primary endpoint fails, there''s no traffic distribution to the backup."}}', '{"title":"Traffic Manager routing methods","url":"https://docs.microsoft.com/en-us/azure/traffic-manager/traffic-manager-routing-methods"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6100, 'az-104', NULL, 'Log Analytics', 'Cost Optimization', 'multiple', 'easy', 'You have a Log Analytics workspace that''s generating high ingestion costs. Which strategies can help optimize costs? (Select all that apply)', '["Configure data retention policies based on data type importance","Use sampling to reduce ingestion volume for high-volume data sources","Implement commitment tiers for predictable ingestion volumes","Archive old logs to cheaper storage tiers","Filter data at the source before sending to Log Analytics"]', '[0,1,2,3,4]', 'All these strategies help optimize Log Analytics costs: retention policies reduce storage costs, sampling reduces ingestion, commitment tiers provide discounts, archiving moves old data to cheaper storage, and source filtering prevents unnecessary ingestion.', '{"correct":"Data retention policies allow you to set different retention periods based on log importance. Sampling reduces the volume of ingested data while maintaining statistical relevance. Commitment tiers provide significant discounts for predictable workloads. Archive feature moves old logs to cheaper storage while maintaining query capability. Source-side filtering prevents unnecessary data from being ingested, reducing both ingestion and storage costs.","why_others_wrong":{"all_applicable":"This is a comprehensive cost optimization scenario where all options represent valid strategies for reducing Log Analytics expenses."}}', '{"title":"Log Analytics cost optimization","url":"https://docs.microsoft.com/en-us/azure/azure-monitor/logs/cost-logs"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6101, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Virtual Networks', 'single', 'medium', 'You are planning a virtual network that must support approximately 3737 virtual machines across multiple subnets with room for growth. Which address space should you choose to minimize waste while allowing subnetting?', '["10.0.0.0/21 (2046 addresses)","10.0.0.0/20 (4094 addresses)","10.0.0.0/19 (8190 addresses)","10.0.0.0/18 (16382 addresses)"]', '[3]', 'A /18 provides 16382 usable IPs, providing headroom for ~3737 VMs and future growth.', '{"correct":"Choose the smallest prefix that satisfies current and near-term capacity while allowing subnet segmentation. /19 ≈ 8190 usable, /18 ≈ 16382 usable.","why_others_wrong":{"0":"/21 is too small for the requirement and leaves no room for subnetting or growth.","1":"/20 may be tight for multi-subnet growth and could constrain future scaling.","2":"/19 may be insufficient for the upper end of the requirement."}}', '{"title":"Plan virtual networks - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-vnet-plan-design-arm"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6102, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Network Security Groups', 'single', 'easy', 'You have an NSG with an allow rule for HTTPS (443) from Internet at priority 200. You must block HTTPS from 203.0.170.149 without affecting other sources. What should you do?', '["Create a deny HTTPS rule for the IP with priority 100","Create a deny HTTPS rule for the IP with priority 300","Edit the existing rule to exclude the IP","Add a deny rule at priority 4096"]', '[0]', 'NSG rules are processed by ascending priority. A lower-number (higher priority) deny must precede the general allow rule to be effective.', '{"correct":"Place a specific deny with a lower priority number (e.g., 100) so it is evaluated before the broad allow at 200.","why_others_wrong":{"1":"A rule at 300 would be evaluated after the allow at 200 and would never match.","2":"NSG rules cannot exclude specific IPs within a single rule; you need a separate rule.","3":"Priority 4096 runs after most custom rules and would not override an earlier allow."}}', '{"title":"Network security groups - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6103, 'az-104', 'az-104-configure-manage-networking', 'Load Balancing', 'Azure Load Balancer', 'multiple', 'medium', 'Which features are supported by Standard Load Balancer? (Select all that apply)', '["Availability Zone support","Multiple frontend IPs","HTTPS health probes","Port 0 wildcard rules","Outbound rules configuration"]', '[0,1,2,4]', 'Standard Load Balancer supports AZs, multiple frontends, HTTPS probes, and outbound rules. Port 0 wildcard is not supported.', '{"correct":"Premium SKU capabilities include zone redundancy, multiple frontends, layer-7 compatible probe protocol HTTPS, and egress control via outbound rules.","why_others_wrong":{"3":"Port 0 is not a valid wildcard in Azure Load Balancer; explicit ports or ranges are required."}}', '{"title":"Standard Load Balancer overview - Azure Load Balancer","url":"https://docs.microsoft.com/en-us/azure/load-balancer/load-balancer-standard-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6104, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'VPN Gateway', 'single', 'difficult', 'Your on-premises device supports IKEv2 and BGP. Which Azure VPN Gateway configuration provides flexibility and performance?', '["Basic SKU with policy-based VPN","VpnGw1 route-based with BGP","Standard SKU with policy-based VPN","VpnGw2 policy-based with BGP"]', '[1]', 'Route-based with BGP provides dynamic routing, multiple tunnels, and best flexibility. Basic lacks BGP.', '{"correct":"Route-based VPN with BGP enables dynamic routing, active-active, and multi-tunnel topologies.","why_others_wrong":{"0":"Basic does not support BGP and has lower throughput.","2":"Policy-based VPN is less flexible than route-based and lacks certain scenarios.","3":"Combining policy-based with BGP is not a valid approach for Azure; BGP requires route-based."}}', '{"title":"VPN Gateway design - Azure VPN Gateway","url":"https://docs.microsoft.com/en-us/azure/vpn-gateway/design"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6105, 'az-104', 'az-104-configure-manage-networking', 'DNS', 'App Service Custom Domain', 'single', 'difficult', 'What is the correct sequence to map a custom domain to Azure App Service managed by Azure DNS?', '["Create TXT for verification → Add domain → Create CNAME","Add domain → Create CNAME → Create TXT","Create CNAME → Add domain → Create TXT","Create TXT → Create CNAME → Add domain"]', '[0]', 'Verify ownership first with TXT, then add domain, then route with CNAME.', '{"correct":"Ownership verification via TXT must precede adding the domain to App Service; traffic routing via CNAME comes last.","why_others_wrong":{"1":"Adding the domain fails if verification is not in place.","2":"CNAME without verified ownership will not complete the mapping.","3":"CNAME before adding the domain is premature."}}', '{"title":"Map an existing custom DNS name to Azure App Service","url":"https://docs.microsoft.com/en-us/azure/app-service/app-service-web-tutorial-custom-domain"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6106, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'VNet Peering', 'multiple', 'difficult', 'Which statements about VNet peering are correct? (Select all that apply)', '["Peering is not transitive","NSG rules apply to peered traffic","Global VNet peering enables cross-region peering","Traffic is encrypted by default between peers","VNets must be in the same subscription"]', '[0,1,2]', 'Peering is non-transitive; NSGs apply; global peering enables cross-region. Traffic is private but not encrypted; cross-subscription peering is supported.', '{"correct":"VNet peering is private, non-transitive, with NSG enforcement; global peering supports cross-region.","why_others_wrong":{"3":"Traffic uses Microsoft backbone but is not encrypted by default.","4":"Cross-subscription peering is supported with proper permissions."}}', '{"title":"Virtual network peering - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-peering-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6107, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Azure Firewall', 'single', 'medium', 'Azure Firewall has DNAT (prio 100), Network (200), and Application (300) rule collections. A packet matches all three. Which is applied?', '["DNAT rule only","Network rule only","Application rule only","All are evaluated and combined"]', '[0]', 'DNAT is processed first; once matched, processing stops.', '{"correct":"Rule processing is hierarchical: DNAT → Network → Application; first match wins.","why_others_wrong":{"1":"Network rules are evaluated after DNAT.","2":"Application rules are last.","3":"Azure Firewall does not combine multiple rule types per packet."}}', '{"title":"Azure Firewall rule processing logic","url":"https://docs.microsoft.com/en-us/azure/firewall/rule-processing"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6108, 'az-104', 'az-104-configure-manage-networking', 'Application Gateway', 'Routing', 'multiple', 'medium', 'Which Application Gateway capabilities support advanced routing? (Select all that apply)', '["Path-based routing","Multi-site hosting","URL rewrite","Header-based routing (arbitrary headers)","IP-based routing"]', '[0,1,2]', 'Path-based, multi-site, and URL rewrite are supported. Arbitrary header or IP-based routing are not standard.', '{"correct":"App Gateway operates at L7 with host/path-based rules and rewrite; arbitrary header or IP-based routing is not provided as a first-class routing criterion.","why_others_wrong":{"3":"Header inspection exists but routing on arbitrary headers is not a native capability.","4":"App Gateway routes on HTTP/S properties, not source IP."}}', '{"title":"Application Gateway features - Azure Application Gateway","url":"https://docs.microsoft.com/en-us/azure/application-gateway/features"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6109, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Routing', 'single', 'easy', 'A subnet has system 0.0.0.0/0 → Internet, UDR 10.1.1.0/24 → VNet Gateway, and BGP 10.1.1.0/25 → ExpressRoute. Where is 10.1.1.10 routed?', '["Internet","VNet Gateway","ExpressRoute","Virtual Appliance"]', '[2]', 'Among overlapping routes of same/higher precedence, the longest prefix wins. BGP 10.1.1.0/25 is more specific than UDR 10.1.1.0/24.', '{"correct":"Precedence: UDR > BGP > System; within same precedence, longest prefix match. Here, /25 beats /24.","why_others_wrong":{"0":"Default route is lowest precedence and least specific.","1":"UDR /24 is less specific than BGP /25.","3":"No UDR points to a virtual appliance in this scenario."}}', '{"title":"Virtual network traffic routing - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-networks-udr-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6110, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'ExpressRoute', 'single', 'easy', 'With Microsoft peering, which Azure services are reachable?', '["Only VNet resources","PaaS services via public endpoints (Storage, SQL, Cosmos DB)","Only services in same region","All services including private endpoints"]', '[1]', 'Microsoft peering exposes Microsoft public services; private endpoints use private peering.', '{"correct":"Microsoft peering is for public IP-based services (Azure public services) over private connectivity.","why_others_wrong":{"0":"VNet resources use private peering.","2":"Scope is global for Microsoft public services.","3":"Private endpoints are reachable via private peering, not Microsoft peering."}}', '{"title":"ExpressRoute routing requirements - Azure ExpressRoute","url":"https://docs.microsoft.com/en-us/azure/expressroute/expressroute-routing"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6111, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Application Security Groups', 'multiple', 'difficult', 'Which are true about Application Security Groups (ASGs)? (Select all that apply)', '["VMs can be in multiple ASGs","ASGs can be used in NSG rules as source/destination","ASGs span multiple VNets","ASGs reduce NSG rule complexity","ASGs can include on-premises IPs"]', '[0,1,3]', 'ASGs are per-VNet constructs used within NSGs and reduce rule sprawl. They do not span VNets or include on-prem IPs.', '{"correct":"ASGs enable application-centric rule targeting within a VNet; membership is per-VM and can be multiple.","why_others_wrong":{"2":"ASGs are scoped to a single VNet.","4":"ASGs cannot include external/on-prem IP addresses."}}', '{"title":"Application security groups - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/application-security-groups"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6112, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Service Endpoints', 'single', 'medium', 'Service endpoints are enabled on a subnet. Access to a Storage account that allows only that subnet fails. What is most likely missing?', '["Allow the subnet on the storage firewall rules","Enable service endpoints on the storage account","Public IP on the VM","Custom route to the storage account"]', '[0]', 'You must add the specific subnet to the service firewall allowlist on the service side.', '{"correct":"Service endpoints require subnet enablement and service firewall configuration to permit that subnet.","why_others_wrong":{"1":"Endpoints are configured on subnets, not on the service resource.","2":"Service endpoints work with private IPs; no public IP needed.","3":"Routing changes are not required for service endpoints."}}', '{"title":"Virtual Network service endpoints","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-service-endpoints-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6113, 'az-104', 'az-104-configure-manage-networking', 'Load Balancing', 'Traffic Manager', 'single', 'difficult', 'Users should be directed to the closest healthy endpoint globally. Which Traffic Manager method?', '["Performance","Geographic","Weighted","Priority"]', '[0]', 'Performance routing directs to the lowest-latency endpoint based on measurements.', '{"correct":"Performance uses latency tables to route to the best-performing endpoint for the user.","why_others_wrong":{"1":"Geographic maps regions to endpoints manually, not based on latency.","2":"Weighted disregards location/latency.","3":"Priority is for failover, not proximity."}}', '{"title":"Traffic Manager routing methods - Azure Traffic Manager","url":"https://docs.microsoft.com/en-us/azure/traffic-manager/traffic-manager-routing-methods"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6114, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'Point-to-Site', 'multiple', 'medium', 'Which authentication methods are supported for Point-to-Site VPN? (Select all that apply)', '["Certificate-based authentication","Azure AD authentication (OpenVPN)","RADIUS authentication","Username/password only","Smart card native support"]', '[0,1,2]', 'Certificate, Azure AD (OpenVPN), and RADIUS are supported. Plain username/password and native smart card support are not direct options.', '{"correct":"P2S supports certs, Azure AD with OpenVPN, and RADIUS integration.","why_others_wrong":{"3":"Direct username/password is not supported without Azure AD or RADIUS.","4":"Smart cards can be part of RADIUS but are not a native P2S method."}}', '{"title":"About Point-to-Site VPN - Azure VPN Gateway","url":"https://docs.microsoft.com/en-us/azure/vpn-gateway/point-to-site-about"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6115, 'az-104', 'az-104-configure-manage-networking', 'DNS', 'Private DNS Zones', 'single', 'easy', 'A VM does not auto-register in a linked private DNS zone with auto-registration enabled. Most likely cause?', '["DNS resolution not enabled on the VNet link","VM uses static private IP","Private zone conflicts with public zone","Subnet does not support auto-registration"]', '[0]', 'Both auto-registration and DNS resolution must be enabled on the VNet link.', '{"correct":"Without resolution enabled, auto-registration will not function properly.","why_others_wrong":{"1":"Static IPs can still auto-register.","2":"Private zones can have same names without conflict in VNet scope.","3":"Auto-registration is VNet-wide, not subnet-restricted."}}', '{"title":"Azure Private DNS zones - Azure DNS","url":"https://docs.microsoft.com/en-us/azure/dns/private-dns-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6116, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'DDoS Protection', 'single', 'easy', 'To obtain detailed attack metrics and mitigation reports with DDoS Protection Standard, what should you configure?', '["DDoS diagnostic logs in Azure Monitor","NSG flow logs only","Azure Firewall logs","Azure Security Center alerts only"]', '[0]', 'DDoS Protection emits detailed telemetry via diagnostic logs and metrics in Azure Monitor.', '{"correct":"Enable DDoSProtectionNotifications, MitigationReports, and FlowLogs for detailed insights.","why_others_wrong":{"1":"NSG flow logs do not include DDoS mitigation metrics.","2":"Firewall logs do not cover platform DDoS telemetry.","3":"Defender for Cloud alerts are complementary, not the primary telemetry source."}}', '{"title":"Azure DDoS Protection Standard - Azure DDoS Protection","url":"https://docs.microsoft.com/en-us/azure/ddos-protection/ddos-protection-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6117, 'az-104', 'az-104-configure-manage-networking', 'Application Gateway', 'SSL/TLS', 'single', 'difficult', 'You need SSL termination at Application Gateway and re-encryption to backends that use different certificates. What should you configure?', '["SSL passthrough only","End-to-end SSL with multiple backend HTTP settings","SSL termination only","HTTP to HTTPS redirect"]', '[1]', 'Use end-to-end SSL and separate backend HTTP settings to validate different backend certs.', '{"correct":"Multiple backend HTTP settings allow associating distinct trusted root certificates per backend pool.","why_others_wrong":{"0":"Passthrough disables inspection and termination at the gateway.","2":"Termination only sends HTTP to backends, which is not secure.","3":"Redirect does not address end-to-end encryption."}}', '{"title":"Application Gateway SSL termination and end-to-end SSL","url":"https://docs.microsoft.com/en-us/azure/application-gateway/ssl-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6118, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Network Virtual Appliances', 'single', 'difficult', 'Traffic is not flowing through an NVA deployed in a hub VNet. What is typically missing?', '["IP forwarding on the NVA NIC and UDRs to direct traffic","Public IP on the NVA","VPN Gateway BGP configuration","DNS forwarders"]', '[0]', 'Enable IP forwarding and route traffic to the NVA with UDRs; public IP is not required for east-west.', '{"correct":"Azure drops packets not destined for the VM unless IP forwarding is enabled; UDRs steer traffic via the NVA.","why_others_wrong":{"1":"Public IP is not needed for intra-Azure inspection.","2":"BGP is not necessary for basic hub-spoke inspection.","3":"DNS settings do not affect L3 forwarding."}}', '{"title":"Network virtual appliances in Azure","url":"https://docs.microsoft.com/en-us/azure/architecture/reference-architectures/dmz/nva-ha"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6119, 'az-104', 'az-104-configure-manage-networking', 'Load Balancing', 'Azure Front Door', 'single', 'easy', 'You require the fastest global failover with health probes. Which service should you use?', '["Azure Traffic Manager","Azure Front Door","Cross-region Load Balancer","Application Gateway v2"]', '[1]', 'Front Door operates at the edge with anycast and fast health-based failover (<30s).', '{"correct":"Edge-based anycast plus health probes yield rapid failover to healthy backends globally.","why_others_wrong":{"0":"Traffic Manager is DNS-based and subject to TTL delays.","2":"Cross-region LB does not provide global HTTP routing semantics like Front Door.","3":"App Gateway is regional only."}}', '{"title":"Azure Front Door overview","url":"https://docs.microsoft.com/en-us/azure/frontdoor/front-door-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6120, 'az-104', 'az-104-configure-manage-networking', 'VPN & ExpressRoute', 'ExpressRoute Global Reach', 'single', 'difficult', 'You want on-prem locations connected by different ExpressRoute circuits to communicate via Microsoft backbone. What should you enable?', '["ExpressRoute Premium","ExpressRoute Global Reach","VNet peering between regions","Site-to-Site VPN between circuits"]', '[1]', 'Global Reach connects ER circuits to enable private on-prem to on-prem connectivity through Microsoft network.', '{"correct":"Global Reach stitches ER circuits for branch-to-branch via Microsoft backbone.","why_others_wrong":{"0":"Premium increases limits but does not provide branch-to-branch.","2":"VNet peering is for Azure VNets, not on-prem interconnect.","3":"VPN uses internet, not the Microsoft backbone."}}', '{"title":"ExpressRoute Global Reach overview","url":"https://docs.microsoft.com/en-us/azure/expressroute/expressroute-global-reach"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6121, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'NAT Gateway', 'single', 'easy', 'Multiple VMs need outbound internet with stable public IP and no inbound exposure. What should you deploy?', '["Public IP on each VM","Azure Load Balancer outbound rules","Azure NAT Gateway associated to the subnet","Azure Firewall"]', '[2]', 'NAT Gateway provides scalable outbound SNAT with stable public IPs and no inbound.', '{"correct":"Designed for outbound-only scenarios, simpler and cheaper than Firewall.","why_others_wrong":{"0":"Public IPs expose VMs to inbound traffic.","1":"Outbound rules work but are more complex and not as scalable as NAT GW.","3":"Firewall is overkill and more expensive for simple outbound."}}', '{"title":"Azure NAT Gateway overview","url":"https://docs.microsoft.com/en-us/azure/virtual-network/nat-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6122, 'az-104', 'az-104-configure-manage-networking', 'Private Link', 'Secure Connectivity', 'single', 'medium', 'You must eliminate public access to Azure SQL Database and connect privately from a VNet. What should you use?', '["Service Endpoints for SQL","Private Link (private endpoint)","VNet peering with SQL region","Application Gateway as proxy"]', '[1]', 'Private Link provides a private endpoint and allows disabling public network access entirely.', '{"correct":"Private endpoint places a NIC with private IP in your subnet for SQL Database.","why_others_wrong":{"0":"Service endpoints still require public endpoint on the service.","2":"SQL Database is a PaaS service, not a VNet resource to peer.","3":"App Gateway is L7 HTTP/S, not for database protocols."}}', '{"title":"Azure Private Link for SQL Database","url":"https://docs.microsoft.com/en-us/azure/azure-sql/database/private-endpoint-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6123, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Virtual Networks', 'single', 'medium', 'You are planning a virtual network that must support approximately 1609 virtual machines across multiple subnets with room for growth. Which address space should you choose to minimize waste while allowing subnetting?', '["10.0.0.0/21 (2046 addresses)","10.0.0.0/20 (4094 addresses)","10.0.0.0/19 (8190 addresses)","10.0.0.0/18 (16382 addresses)"]', '[2]', 'A /19 provides 8190 usable IPs, which covers ~1609 VMs and allows subnetting.', '{"correct":"Choose the smallest prefix that satisfies current and near-term capacity while allowing subnet segmentation. /19 ≈ 8190 usable, /18 ≈ 16382 usable.","why_others_wrong":{"0":"/21 is too small for the requirement and leaves no room for subnetting or growth.","1":"/20 may be tight for multi-subnet growth and could constrain future scaling.","3":"/18 is significantly larger than needed, causing unnecessary waste."}}', '{"title":"Plan virtual networks - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-vnet-plan-design-arm"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6124, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Network Security Groups', 'single', 'medium', 'You have an NSG with an allow rule for HTTPS (443) from Internet at priority 200. You must block HTTPS from 203.0.170.187 without affecting other sources. What should you do?', '["Create a deny HTTPS rule for the IP with priority 100","Create a deny HTTPS rule for the IP with priority 300","Edit the existing rule to exclude the IP","Add a deny rule at priority 4096"]', '[0]', 'NSG rules are processed by ascending priority. A lower-number (higher priority) deny must precede the general allow rule to be effective.', '{"correct":"Place a specific deny with a lower priority number (e.g., 100) so it is evaluated before the broad allow at 200.","why_others_wrong":{"1":"A rule at 300 would be evaluated after the allow at 200 and would never match.","2":"NSG rules cannot exclude specific IPs within a single rule; you need a separate rule.","3":"Priority 4096 runs after most custom rules and would not override an earlier allow."}}', '{"title":"Network security groups - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6145, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Virtual Networks', 'single', 'medium', 'You are planning a virtual network that must support approximately 1433 virtual machines across multiple subnets with room for growth. Which address space should you choose to minimize waste while allowing subnetting?', '["10.0.0.0/21 (2046 addresses)","10.0.0.0/20 (4094 addresses)","10.0.0.0/19 (8190 addresses)","10.0.0.0/18 (16382 addresses)"]', '[2]', 'A /19 provides 8190 usable IPs, which covers ~1433 VMs and allows subnetting.', '{"correct":"Choose the smallest prefix that satisfies current and near-term capacity while allowing subnet segmentation. /19 ≈ 8190 usable, /18 ≈ 16382 usable.","why_others_wrong":{"0":"/21 is too small for the requirement and leaves no room for subnetting or growth.","1":"/20 may be tight for multi-subnet growth and could constrain future scaling.","3":"/18 is significantly larger than needed, causing unnecessary waste."}}', '{"title":"Plan virtual networks - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-vnet-plan-design-arm"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
