INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6278, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Network Security Groups', 'single', 'difficult', 'You have an NSG with an allow rule for HTTPS (443) from Internet at priority 200. You must block HTTPS from 203.0.235.162 without affecting other sources. What should you do?', '["Create a deny HTTPS rule for the IP with priority 100","Create a deny HTTPS rule for the IP with priority 300","Edit the existing rule to exclude the IP","Add a deny rule at priority 4096"]', '[0]', 'NSG rules are processed by ascending priority. A lower-number (higher priority) deny must precede the general allow rule to be effective.', '{"correct":"Place a specific deny with a lower priority number (e.g., 100) so it is evaluated before the broad allow at 200.","why_others_wrong":{"1":"A rule at 300 would be evaluated after the allow at 200 and would never match.","2":"NSG rules cannot exclude specific IPs within a single rule; you need a separate rule.","3":"Priority 4096 runs after most custom rules and would not override an earlier allow."}}', '{"title":"Network security groups - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7867, 'az-305', NULL, 'General', 'AZ-305 Fundamentals', 'single', 'medium', 'This is a sample AZ-305 question 8 for topic data-storage. Which option is correct?', '["Option A - First choice","Option B - Second choice","Option C - Third choice","Option D - Fourth choice"]', '[0]', 'This is a sample explanation for AZ-305 question 8.', '{"correct":"Option A is correct for this sample AZ-305 question.","why_others_wrong":{"1":"Option B is incorrect for demonstration purposes.","2":"Option C is incorrect for demonstration purposes.","3":"Option D is incorrect for demonstration purposes."}}', '{"title":"AZ-305 Reference","url":"https://learn.microsoft.com/en-us/credentials/certifications/resources/study-guides/az-305"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6299, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Virtual Networks', 'single', 'medium', 'You are planning a virtual network that must support approximately 1679 virtual machines across multiple subnets with room for growth. Which address space should you choose to minimize waste while allowing subnetting?', '["10.0.0.0/21 (2046 addresses)","10.0.0.0/20 (4094 addresses)","10.0.0.0/19 (8190 addresses)","10.0.0.0/18 (16382 addresses)"]', '[2]', 'A /19 provides 8190 usable IPs, which covers ~1679 VMs and allows subnetting.', '{"correct":"Choose the smallest prefix that satisfies current and near-term capacity while allowing subnet segmentation. /19 ≈ 8190 usable, /18 ≈ 16382 usable.","why_others_wrong":{"0":"/21 is too small for the requirement and leaves no room for subnetting or growth.","1":"/20 may be tight for multi-subnet growth and could constrain future scaling.","3":"/18 is significantly larger than needed, causing unnecessary waste."}}', '{"title":"Plan virtual networks - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-vnet-plan-design-arm"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6300, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Network Security Groups', 'single', 'easy', 'You have an NSG with an allow rule for HTTPS (443) from Internet at priority 200. You must block HTTPS from 203.0.54.226 without affecting other sources. What should you do?', '["Create a deny HTTPS rule for the IP with priority 100","Create a deny HTTPS rule for the IP with priority 300","Edit the existing rule to exclude the IP","Add a deny rule at priority 4096"]', '[0]', 'NSG rules are processed by ascending priority. A lower-number (higher priority) deny must precede the general allow rule to be effective.', '{"correct":"Place a specific deny with a lower priority number (e.g., 100) so it is evaluated before the broad allow at 200.","why_others_wrong":{"1":"A rule at 300 would be evaluated after the allow at 200 and would never match.","2":"NSG rules cannot exclude specific IPs within a single rule; you need a separate rule.","3":"Priority 4096 runs after most custom rules and would not override an earlier allow."}}', '{"title":"Network security groups - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
