INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7873, 'az-305', NULL, 'General', 'AZ-305 Fundamentals', 'single', 'medium', 'This is a sample AZ-305 question 14 for topic data-storage. Which option is correct?', '["Option A - First choice","Option B - Second choice","Option C - Third choice","Option D - Fourth choice"]', '[0]', 'This is a sample explanation for AZ-305 question 14.', '{"correct":"Option A is correct for this sample AZ-305 question.","why_others_wrong":{"1":"Option B is incorrect for demonstration purposes.","2":"Option C is incorrect for demonstration purposes.","3":"Option D is incorrect for demonstration purposes."}}', '{"title":"AZ-305 Reference","url":"https://learn.microsoft.com/en-us/credentials/certifications/resources/study-guides/az-305"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
