INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6761, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Virtual Networks', 'single', 'medium', 'You are planning a virtual network that must support approximately 3636 virtual machines across multiple subnets with room for growth. Which address space should you choose to minimize waste while allowing subnetting?', '["10.0.0.0/21 (2046 addresses)","10.0.0.0/20 (4094 addresses)","10.0.0.0/19 (8190 addresses)","10.0.0.0/18 (16382 addresses)"]', '[3]', 'A /18 provides 16382 usable IPs, providing headroom for ~3636 VMs and future growth.', '{"correct":"Choose the smallest prefix that satisfies current and near-term capacity while allowing subnet segmentation. /19 ≈ 8190 usable, /18 ≈ 16382 usable.","why_others_wrong":{"0":"/21 is too small for the requirement and leaves no room for subnetting or growth.","1":"/20 may be tight for multi-subnet growth and could constrain future scaling.","2":"/19 may be insufficient for the upper end of the requirement."}}', '{"title":"Plan virtual networks - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-vnet-plan-design-arm"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6762, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Network Security Groups', 'single', 'easy', 'You have an NSG with an allow rule for HTTPS (443) from Internet at priority 200. You must block HTTPS from 203.0.174.91 without affecting other sources. What should you do?', '["Create a deny HTTPS rule for the IP with priority 100","Create a deny HTTPS rule for the IP with priority 300","Edit the existing rule to exclude the IP","Add a deny rule at priority 4096"]', '[0]', 'NSG rules are processed by ascending priority. A lower-number (higher priority) deny must precede the general allow rule to be effective.', '{"correct":"Place a specific deny with a lower priority number (e.g., 100) so it is evaluated before the broad allow at 200.","why_others_wrong":{"1":"A rule at 300 would be evaluated after the allow at 200 and would never match.","2":"NSG rules cannot exclude specific IPs within a single rule; you need a separate rule.","3":"Priority 4096 runs after most custom rules and would not override an earlier allow."}}', '{"title":"Network security groups - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6783, 'az-104', 'az-104-configure-manage-networking', 'Virtual Networks', 'Virtual Networks', 'single', 'medium', 'You are planning a virtual network that must support approximately 1994 virtual machines across multiple subnets with room for growth. Which address space should you choose to minimize waste while allowing subnetting?', '["10.0.0.0/21 (2046 addresses)","10.0.0.0/20 (4094 addresses)","10.0.0.0/19 (8190 addresses)","10.0.0.0/18 (16382 addresses)"]', '[2]', 'A /19 provides 8190 usable IPs, which covers ~1994 VMs and allows subnetting.', '{"correct":"Choose the smallest prefix that satisfies current and near-term capacity while allowing subnet segmentation. /19 ≈ 8190 usable, /18 ≈ 16382 usable.","why_others_wrong":{"0":"/21 is too small for the requirement and leaves no room for subnetting or growth.","1":"/20 may be tight for multi-subnet growth and could constrain future scaling.","3":"/18 is significantly larger than needed, causing unnecessary waste."}}', '{"title":"Plan virtual networks - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/virtual-network-vnet-plan-design-arm"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6784, 'az-104', 'az-104-configure-manage-networking', 'Network Security', 'Network Security Groups', 'single', 'medium', 'You have an NSG with an allow rule for HTTPS (443) from Internet at priority 200. You must block HTTPS from 203.0.95.164 without affecting other sources. What should you do?', '["Create a deny HTTPS rule for the IP with priority 100","Create a deny HTTPS rule for the IP with priority 300","Edit the existing rule to exclude the IP","Add a deny rule at priority 4096"]', '[0]', 'NSG rules are processed by ascending priority. A lower-number (higher priority) deny must precede the general allow rule to be effective.', '{"correct":"Place a specific deny with a lower priority number (e.g., 100) so it is evaluated before the broad allow at 200.","why_others_wrong":{"1":"A rule at 300 would be evaluated after the allow at 200 and would never match.","2":"NSG rules cannot exclude specific IPs within a single rule; you need a separate rule.","3":"Priority 4096 runs after most custom rules and would not override an earlier allow."}}', '{"title":"Network security groups - Azure Virtual Network","url":"https://docs.microsoft.com/en-us/azure/virtual-network/network-security-groups-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6801, 'az-104', NULL, 'Virtual Networks', 'Networking', 'single', 'medium', 'You have a virtual network with address space 10.0.0.0/16. You need to create a subnet that can accommodate 500 IP addresses while leaving room for future subnets. What subnet mask should you use?', '["/22 (1022 usable IPs)","/23 (510 usable IPs)","/24 (254 usable IPs)","/21 (2046 usable IPs)"]', '[0]', 'A /22 subnet provides 1022 usable IP addresses, which accommodates the 500 required IPs while leaving room for future growth and additional subnets.', '{"correct":"/22 provides sufficient IP addresses (1022) for current needs (500) while being efficient with address space, allowing for additional subnets in the /16 space.","why_others_wrong":{"1":"/23 provides only 510 IPs, barely meeting requirements with no room for growth.","2":"/24 provides only 254 IPs, insufficient for the 500 requirement.","3":"/21 provides too many IPs (2046), wasting address space that could be used for other subnets."}}', '{"title":"Virtual network planning","url":"https://learn.microsoft.com/en-us/azure/virtual-network/virtual-networks-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (6802, 'az-104', 'az-104-implement-manage-storage', 'Storage Accounts', 'Storage', 'case-study', 'difficult', 'Case Study: Fabrikam needs to store 10TB of infrequently accessed compliance data for 7 years. The data must be available within 15 hours if needed for audits. Cost optimization is critical. Which storage solution should you recommend?', '["Premium SSD with Cool access tier","Standard HDD with Hot access tier","Standard LRS with Archive access tier","Premium Files with Standard access tier"]', '[2]', 'Archive access tier provides the lowest cost for long-term storage of infrequently accessed data, with retrieval times that meet the 15-hour requirement.', '{"correct":"Archive tier offers the lowest storage costs for rarely accessed data and provides retrieval within hours, meeting both cost and compliance requirements.","why_others_wrong":{"0":"Premium SSD with Cool tier is expensive for long-term archival storage.","1":"Hot tier is designed for frequently accessed data and is more expensive for archival scenarios.","3":"Premium Files is the most expensive option and unnecessary for archival data."}}', '{"title":"Azure Blob storage access tiers","url":"https://learn.microsoft.com/en-us/azure/storage/blobs/access-tiers-overview"}', '2025-08-17T02:46:25.562325+00:00', '2025-08-17T02:46:25.562325+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7001, 'az-305', 'az-305-design-infrastructure', 'Compute', 'Architecture Design', 'single', 'easy', 'You are designing a multi-tier application architecture for Azure. The application requires high availability, scalability, and cost optimization. Which compute service combination would you recommend?', '["Azure Virtual Machines with Availability Sets","Azure App Service with Azure Functions for background processing","Azure Container Instances with Azure Kubernetes Service","Azure Virtual Machine Scale Sets with Azure Load Balancer"]', '[1]', 'Azure App Service provides built-in high availability, auto-scaling, and cost optimization through consumption-based pricing for Azure Functions, making it ideal for multi-tier applications.', '{"correct":"Azure App Service provides built-in high availability across zones, automatic scaling based on demand, and managed platform services that reduce operational overhead. Combined with Azure Functions for background processing, this offers consumption-based pricing where you only pay for actual execution time, providing excellent cost optimization. The platform handles infrastructure management, patching, and scaling automatically.","why_others_wrong":{"0":"Azure VMs with Availability Sets provide high availability but require manual scaling configuration and constant compute costs regardless of actual usage, making them less cost-effective for variable workloads.","2":"While containerized, Azure Container Instances don''t provide built-in high availability and auto-scaling like App Service. AKS adds complexity and management overhead that may not be necessary for a multi-tier application.","3":"VMSS with Load Balancer provides good availability and scaling but still requires infrastructure management and doesn''t offer the cost optimization of consumption-based pricing."}}', '{"title":"Azure App Service overview","url":"https://docs.microsoft.com/en-us/azure/app-service/overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7002, 'az-305', 'az-305-design-infrastructure', 'Compute', 'Architecture Design', 'single', 'medium', 'Design a multi-tier web application with managed scaling and minimal ops. Which is best?', '["VMs in Availability Sets","App Service for web + Functions for background jobs","AKS for web + ACI for jobs","VM Scale Sets only"]', '[1]', 'App Service provides PaaS features; Functions provide serverless background processing with consumption pricing.', '{"correct":"Managed platform, auto-scale, and lower operational burden suit solution architecture goals.","why_others_wrong":{"0":"VMs require higher ops overhead.","2":"AKS adds complexity not required for this scenario.","3":"VMSS still requires VM management and lacks PaaS features."}}', '{"title":"Azure App Service overview","url":"https://docs.microsoft.com/en-us/azure/app-service/overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7003, 'az-305', 'az-305-design-infrastructure', 'Networking', 'Global Routing', 'single', 'easy', 'For a global app requiring fast failover and WAF, which fronting service should you choose?', '["Traffic Manager","Azure Front Door","Application Gateway","Basic Load Balancer"]', '[1]', 'Front Door offers global anycast, fast failover, and integrated WAF.', '{"correct":"Edge presence and health probes reduce failover times and improve global performance.","why_others_wrong":{"0":"DNS-based and slower failover.","2":"Regional-only and not global POP-based.","3":"Basic LB lacks global routing and WAF features."}}', '{"title":"Azure Front Door overview","url":"https://docs.microsoft.com/en-us/azure/frontdoor/front-door-overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7004, 'az-305', 'az-305-design-identity-governance-monitoring', 'Governance', 'Azure Policy', 'multiple', 'easy', 'Which Azure Policy effects are useful to enforce storage security baselines? (Select all that apply)', '["Audit","Deny","DeployIfNotExists","Modify","Append"]', '[0,1,2,3,4]', 'All listed effects can participate in governance for storage baseline compliance.', '{"correct":"Audit monitors, Deny blocks, DeployIfNotExists configures, Modify remediates, Append adds required settings/tags.","why_others_wrong":{}}', '{"title":"Azure Policy effects","url":"https://docs.microsoft.com/en-us/azure/governance/policy/concepts/effects"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7005, 'az-305', NULL, 'Disaster Recovery', 'DR Strategy', 'single', 'easy', 'For VM workload requiring orchestrated region failover with minimal RPO/RTO, what should you choose?', '["Azure Backup only","Azure Site Recovery","Zone-Redundant Storage","GEO-redundant backups only"]', '[1]', 'ASR provides replication, runbooks, and orchestrated failover with low RPO/RTO.', '{"correct":"ASR replicates VMs and supports planned/unplanned failover and test failover.","why_others_wrong":{"0":"Backup provides recovery, not continuous replication.","2":"ZRS is storage redundancy, not a DR orchestration solution.","3":"Backups alone do not meet low RPO/RTO or orchestration requirements."}}', '{"title":"Azure Backup and Site Recovery overview","url":"https://docs.microsoft.com/en-us/azure/backup/backup-overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7006, 'az-305', NULL, 'Databases', 'Cosmos DB', 'single', 'easy', 'You need globally distributed, multi-region write database with millisecond latency SLA. Which service?', '["Azure SQL Database","Azure Cosmos DB","Azure Database for PostgreSQL Single Server","Azure Table Storage"]', '[1]', 'Cosmos DB offers turnkey multi-master, multi-region writes with SLAs on latency/availability.', '{"correct":"Cosmos DB provides tunable consistency and multi-region, multi-master replication.","why_others_wrong":{"0":"SQL DB supports geo-replication but not multi-master writes.","2":"Single Server is regional and not designed for global multi-master.","3":"Table Storage lacks global multi-master features and enterprise SLAs."}}', '{"title":"Azure data storage guidance","url":"https://docs.microsoft.com/en-us/azure/architecture/guide/technology-choices/data-store-overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7007, 'az-305', 'az-305-design-infrastructure', 'Networking', 'Security', 'single', 'medium', 'You must block public access to Storage while enabling private access from VNets. Choose:', '["Service endpoints only","Private Link","UDRs to storage public IPs","Application Gateway"]', '[1]', 'Private Link creates private endpoints and allows disabling public network access.', '{"correct":"Private endpoints provide private IPs and isolation for PaaS services.","why_others_wrong":{"0":"Service endpoints still expose a public endpoint.","2":"UDRs cannot make public services private.","3":"App Gateway is HTTP/S proxy, not for storage endpoints."}}', '{"title":"Azure Private Link and service endpoints","url":"https://docs.microsoft.com/en-us/azure/private-link/private-link-overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7008, 'az-305', 'az-305-design-identity-governance-monitoring', 'Monitoring', 'Visualization', 'single', 'easy', 'You need an interactive dashboard combining metrics and logs with parameters and drill-down. Use:', '["Azure Dashboard basic charts","Azure Monitor Workbooks","Log Analytics legacy dashboards","Application Insights classic charts"]', '[1]', 'Workbooks provide parameterized, interactive visualizations across data sources.', '{"correct":"Workbooks unify metrics/logs with templates, parameters, and drill-down.","why_others_wrong":{"0":"Basic dashboards lack interactivity and parameters.","2":"Legacy dashboards are log-only focused.","3":"App Insights charts are app-centric and less flexible for multi-service views."}}', '{"title":"Azure Monitor Workbooks","url":"https://docs.microsoft.com/en-us/azure/azure-monitor/visualize/workbooks-overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7009, 'az-305', 'az-305-design-infrastructure', 'Networking', 'Hybrid Networking', 'single', 'difficult', 'A steady 5 Gbps private WAN connection to Azure with SLA is required. Which option?', '["Site-to-Site VPN with multiple tunnels","ExpressRoute","Point-to-Site VPN","Azure Virtual WAN user VPN"]', '[1]', 'ExpressRoute provides private connectivity with higher throughput and SLAs.', '{"correct":"ER uses Microsoft backbone and supports higher bandwidth options with enterprise SLAs.","why_others_wrong":{"0":"IPsec VPN over internet cannot guarantee bandwidth or SLA.","2":"P2S is for users, not site connectivity.","3":"User VPN is for remote users, not WAN-scale connectivity."}}', '{"title":"Hybrid network connectivity options","url":"https://docs.microsoft.com/en-us/azure/architecture/reference-architectures/hybrid-networking"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7010, 'az-305', NULL, 'Storage Accounts', 'Redundancy', 'single', 'easy', 'Highest durability with ability to read from secondary region during normal operations?', '["LRS","ZRS","GRS","RA-GRS"]', '[3]', 'RA-GRS provides cross-region replication with read access to secondary.', '{"correct":"RA-GRS = GRS + read access for secondary endpoint.","why_others_wrong":{"0":"LRS is single datacenter.","1":"ZRS is zonal within a region.","2":"GRS lacks read access to secondary in normal operation."}}', '{"title":"Azure data storage guidance","url":"https://docs.microsoft.com/en-us/azure/architecture/guide/technology-choices/data-store-overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7011, 'az-305', NULL, 'Data Integration', 'Messaging', 'single', 'easy', 'You require FIFO ordering and sessions for transactional messages. Choose:', '["Event Hubs","Service Bus","Storage Queues","Event Grid"]', '[1]', 'Service Bus supports sessions and FIFO semantics for ordered message processing.', '{"correct":"Service Bus queues/topics offer sessions, transactions, and dead-lettering with rich semantics.","why_others_wrong":{"0":"Event Hubs is a big data streaming ingestion service.","2":"Storage Queues lack FIFO and sessions.","3":"Event Grid is for push-based event routing, not queueing."}}', '{"title":"Azure data storage guidance","url":"https://docs.microsoft.com/en-us/azure/architecture/guide/technology-choices/data-store-overview"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7801, 'az-305', 'az-305-design-identity-governance-monitoring', 'Azure AD', 'Privileged Access', 'single', 'medium', 'You need to grant time-bound privileged access to Azure subscriptions with approval workflow and audit trail. What should you implement?', '["Azure AD Privileged Identity Management with eligible role assignments","Azure RBAC permanent assignments with custom roles","Azure Policy to deny privileged operations","Management groups with deny assignments"]', '[0]', 'PIM provides just-in-time elevation, approvals, MFA, and auditing for privileged roles.', '{"correct":"PIM supports eligible roles, activation with approval, MFA, and access reviews for least privilege.","why_others_wrong":{"1":"Permanent assignments do not provide JIT, approval, or time-bound access.","2":"Azure Policy cannot provide on-demand elevation for human identities.","3":"Deny assignments at management groups do not solve JIT elevation needs."}}', '{"title":"What is Azure AD Privileged Identity Management?","url":"https://learn.microsoft.com/azure/active-directory/privileged-identity-management/pim-configure"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7802, 'az-305', 'az-305-design-identity-governance-monitoring', 'Azure AD', 'Conditional Access', 'multiple', 'easy', 'Which risk signals can be used in Conditional Access to require MFA? (Select all that apply)', '["User risk","Sign-in risk","Device compliance state","Named locations"]', '[0,1]', 'Risk-based policies use User risk and Sign-in risk signals from Azure AD Identity Protection.', '{"correct":"Risk signals (user and sign-in risk) are part of Identity Protection and can trigger MFA or block.","why_others_wrong":{"2":"Device compliance is an access condition, not a risk signal.","3":"Named locations are not risk signals; they are location conditions."}}', '{"title":"Conditional Access: Identity Protection integration","url":"https://learn.microsoft.com/azure/active-directory/conditional-access/howto-conditional-access-policy-risk"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7844, 'az-305', 'az-305-design-identity-governance-monitoring', 'General', 'AZ-305 Fundamentals', 'single', 'medium', 'This is a sample AZ-305 question 32 for topic identity. Which option is correct?', '["Option A - First choice","Option B - Second choice","Option C - Third choice","Option D - Fourth choice"]', '[0]', 'This is a sample explanation for AZ-305 question 32.', '{"correct":"Option A is correct for this sample AZ-305 question.","why_others_wrong":{"1":"Option B is incorrect for demonstration purposes.","2":"Option C is incorrect for demonstration purposes.","3":"Option D is incorrect for demonstration purposes."}}', '{"title":"AZ-305 Reference","url":"https://learn.microsoft.com/en-us/credentials/certifications/resources/study-guides/az-305"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7803, 'az-305', 'az-305-design-identity-governance-monitoring', 'Azure AD', 'B2B Collaboration', 'single', 'difficult', 'You must allow contractors from an external Azure AD tenant to access only one internal application using their identities. What is the best approach?', '["Azure AD B2B collaboration with guest users and app assignment","Create new cloud-only user accounts for each contractor","Establish AD DS forest trust between tenants","Use Azure Lighthouse"]', '[0]', 'B2B collaboration brings external users as guests to your tenant and limits access via app assignment.', '{"correct":"Guest users authenticate with their home tenant and receive least-privilege access to specific apps.","why_others_wrong":{"1":"Cloud-only accounts duplicate identities and increase overhead.","2":"Forest trusts do not apply to Azure AD tenants.","3":"Lighthouse is for cross-tenant management, not end-user app access."}}', '{"title":"What is Azure AD B2B collaboration?","url":"https://learn.microsoft.com/azure/active-directory/external-identities/what-is-b2b"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7804, 'az-305', NULL, 'Backup', 'Azure Backup', 'single', 'easy', 'You need app-consistent backups for Azure VMs with daily retention for 35 days. What should you configure?', '["Recovery Services vault with a backup policy using VSS","Snapshots via Azure Automation only","Site Recovery with crash-consistent settings","Blob snapshots of OS disks"]', '[0]', 'Azure Backup in a Recovery Services vault supports app-consistent backups using VSS and retention policies.', '{"correct":"Backup policy in Recovery Services vault enables scheduling, app-consistency, and retention.","why_others_wrong":{"1":"Automation snapshots lack retention governance and app-consistency.","2":"ASR is for replication/DR, not scheduled backups.","3":"Blob snapshots are per-disk and not integrated with VM backup policies."}}', '{"title":"Back up Azure VMs","url":"https://learn.microsoft.com/azure/backup/backup-azure-arm-vms-prepare"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7805, 'az-305', NULL, 'Backup', 'Security', 'single', 'medium', 'How can you protect backups from accidental or malicious deletion in Azure Backup?', '["Enable soft delete and multi-user authorization (MUA) for critical operations","Enable NSG rules on the subnet","Use RBAC Reader role for backup admins","Enable Azure Policy audit only"]', '[0]', 'Soft delete retains deleted backup data for a retention period. MUA requires secondary approval for high-risk operations.', '{"correct":"Soft delete and MUA increase protection against ransomware and malicious deletions.","why_others_wrong":{"1":"NSGs do not protect vault operations.","2":"Reader role does not manage backup or protect deletion.","3":"Audit-only policies do not enforce protective controls."}}', '{"title":"Soft delete for Azure Backup","url":"https://learn.microsoft.com/azure/backup/backup-azure-security-feature-cloud"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7806, 'az-305', NULL, 'Backup', 'Workload Backup', 'single', 'difficult', 'You must back up SQL Server running on Azure VMs with item-level restore and long-term retention. What should you use?', '["Azure Backup for SQL Server in Azure VMs","File-level backup using Azure Files Share snapshots","Database export to BACPAC weekly","Azure Site Recovery"]', '[0]', 'Azure Backup provides application-aware backups for SQL on VMs with PITR and granular restore.', '{"correct":"The SQL workload backup supports full/diff/log backups and granular restore.","why_others_wrong":{"1":"File share snapshots are not database-aware.","2":"BACPAC is for schema/data export, not backup/restore strategy.","3":"ASR is for replication, not backups."}}', '{"title":"Back up SQL Server on Azure VMs","url":"https://learn.microsoft.com/azure/backup/backup-azure-sql-iaas"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7807, 'az-305', NULL, 'High Availability', 'VM Availability', 'single', 'easy', 'Which option provides protection against a full datacenter failure within a region for VMs?', '["Availability Sets","Availability Zones","Proximity Placement Groups","Accelerated Networking"]', '[1]', 'Availability Zones distribute resources across physically separate datacenters within a region.', '{"correct":"Zones provide datacenter-level fault isolation.","why_others_wrong":{"0":"Sets protect only against rack-level failures.","2":"PPGs reduce latency; they do not provide HA.","3":"Accelerated Networking improves throughput/latency."}}', '{"title":"Availability options for VMs","url":"https://learn.microsoft.com/azure/virtual-machines/availability"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7808, 'az-305', NULL, 'High Availability', 'Data Tier', 'single', 'medium', 'You need zone-resilient SQL with 99.99% SLA. What should you deploy?', '["Azure SQL Database General Purpose","Azure SQL Database Business Critical with zone redundancy","SQL on VMs with Availability Set","Single-instance SQL Managed Instance"]', '[1]', 'Business Critical tier supports zone redundancy for high availability.', '{"correct":"BC tier provides multiple replicas and zone redundancy.","why_others_wrong":{"0":"General Purpose uses remote storage and may not be zone redundant.","2":"VM-based solution requires complex setup and lacks PaaS SLA features.","3":"Single-instance MI is not zone redundant by default."}}', '{"title":"High availability for Azure SQL Database","url":"https://learn.microsoft.com/azure/azure-sql/database/high-availability-sla"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7809, 'az-305', NULL, 'High Availability', 'Networking', 'single', 'difficult', 'You require L7 load balancing with zone redundancy and WAF for regional traffic. Which service should you choose?', '["Basic Load Balancer","Traffic Manager","Application Gateway v2 (WAF) with zone redundancy","Azure Front Door Classic only"]', '[2]', 'App Gateway v2 supports zone redundancy and WAF for regional L7 load balancing.', '{"correct":"It provides HTTPS termination, path-based routing, autoscaling, and WAF with zone redundancy.","why_others_wrong":{"0":"Basic LB is L4 and not zone redundant.","1":"Traffic Manager is DNS-based, not L7 LB.","3":"Front Door is global; the requirement is regional."}}', '{"title":"Application Gateway v2 SKU","url":"https://learn.microsoft.com/azure/application-gateway/overview-v2"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7810, 'az-305', 'az-305-design-infrastructure', 'Migration', 'Azure Migrate', 'single', 'easy', 'What is the typical sequence for migrating VMware VMs with Azure Migrate Server Migration?', '["Replicate → Discover → Assess → Migrate","Discover → Assess → Replicate → Test migrate → Migrate","Assess → Discover → Replicate → Migrate","Discover → Replicate → Assess → Migrate"]', '[1]', 'Discovery, assessment, replication, test migration, then production migration is the recommended sequence.', '{"correct":"Assessment informs sizing and readiness before replication and migration.","why_others_wrong":{"0":"Replication should not precede discovery and assessment.","2":"Assessment requires discovery first.","3":"Assessment should precede replication."}}', '{"title":"Migrate VMware VMs to Azure","url":"https://learn.microsoft.com/azure/migrate/migrate-support-matrix-vmware"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7811, 'az-305', 'az-305-design-infrastructure', 'Migration', 'Appliance', 'single', 'medium', 'Which component must you deploy in your environment to collect discovery data for Azure Migrate?', '["Azure Migrate appliance","ExpressRoute circuit","Log Analytics agent only","Azure Site Recovery Mobility service only"]', '[0]', 'The Azure Migrate appliance collects metadata for discovery and assessment.', '{"correct":"Appliance performs discovery of servers and dependencies.","why_others_wrong":{"1":"ExpressRoute is optional connectivity, not required.","2":"Agent alone is insufficient for discovery scope.","3":"Mobility service is used for replication, not discovery."}}', '{"title":"Discover servers with Azure Migrate appliance","url":"https://learn.microsoft.com/azure/migrate/migrate-appliance"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
INSERT INTO questions (id, exam_id, topic_id, module, category, type, difficulty, question_text, options, correct_answers, explanation, reasoning, reference, created_at, updated_at, is_active) VALUES (7812, 'az-305', 'az-305-design-infrastructure', 'Migration', 'Database Migration', 'single', 'difficult', 'You must migrate a mission-critical SQL Server database to Azure SQL Managed Instance with minimal downtime. What should you use?', '["Azure Database Migration Service online migration","BACPAC export/import","Backup and restore to Azure Blob Storage","Transactional replication to Azure SQL Database"]', '[0]', 'DMS online migration supports continuous data sync and cutover with minimal downtime.', '{"correct":"Online migration reduces downtime by syncing changes until cutover.","why_others_wrong":{"1":"BACPAC incurs long downtime and is for small/medium databases.","2":"Backup/restore is not supported for MI without managed backup integration and still incurs downtime.","3":"Transactional replication targets Azure SQL Database, not MI for all scenarios."}}', '{"title":"Use DMS for online migration","url":"https://learn.microsoft.com/azure/dms/tutorial-sql-server-to-managed-instance"}', '2025-08-17T02:46:25.847843+00:00', '2025-08-17T02:46:25.847843+00:00', TRUE) ON CONFLICT DO NOTHING;
