INSERT INTO certification_info (id, exam_id, title, description, exam_code, level, validity, prerequisites, skills_measured, study_resources, exam_details, career_path, created_at, updated_at) VALUES ('d3891ab5-b411-4a32-8883-f8ae44a4816c', 'ai-900', 'Microsoft Certified: Azure AI Fundamentals', 'This certification validates your foundational knowledge of machine learning and artificial intelligence concepts and related Azure services.', 'AI-900', 'Fundamentals', '2 years', '["Basic knowledge of cloud computing concepts","General IT knowledge or experience","No prior experience with AI or machine learning required"]', '[{"category":"Describe Artificial Intelligence workloads and considerations (20-25%)","weightage":23,"skills":["Identify features of common AI workloads","Identify guiding principles for responsible AI","Describe considerations for AI solutions","Identify common AI services and their use cases"]},{"category":"Describe fundamental principles of machine learning on Azure (25-30%)","weightage":28,"skills":["Identify common machine learning types","Describe core machine learning concepts","Describe Azure Machine Learning capabilities","Describe automated machine learning capabilities"]},{"category":"Describe features of computer vision workloads on Azure (15-20%)","weightage":18,"skills":["Identify common computer vision workloads","Identify Azure Computer Vision services","Identify Azure Form Recognizer services","Identify Azure Custom Vision services"]},{"category":"Describe features of Natural Language Processing (NLP) workloads on Azure (15-20%)","weightage":18,"skills":["Identify features of common NLP workloads","Identify Azure Language services","Identify Azure Speech services","Identify Azure Translator services"]},{"category":"Describe features of conversational AI workloads on Azure (10-15%)","weightage":13,"skills":["Identify common use cases for conversational AI","Identify Azure Bot Service capabilities","Identify Azure Cognitive Services for conversational AI","Identify Azure Language Understanding (LUIS) capabilities"]}]', '[{"title":"Microsoft Learn - AI-900 Learning Path","type":"Learning Path","url":"https://docs.microsoft.com/en-us/learn/certifications/exams/ai-900","description":"Official Microsoft learning path for Azure AI Fundamentals"},{"title":"Azure AI Documentation","type":"Documentation","url":"https://docs.microsoft.com/en-us/azure/ai/","description":"Azure AI documentation and best practices"},{"title":"Azure AI Fundamentals Course","type":"Course","url":"https://docs.microsoft.com/en-us/learn/paths/azure-ai-fundamentals/","description":"Comprehensive course covering all AI-900 exam objectives"},{"title":"Azure AI Practice Tests","type":"Practice Tests","url":"https://www.microsoft.com/en-us/learning/exam-AI-900.html","description":"Official Microsoft practice tests for AI-900"}]', '{"duration":"60 minutes","questions":"40-60 questions","passingScore":"700 out of 1000","cost":"$99 USD","languages":["English","Japanese","Korean","German","French","Spanish","Portuguese (Brazil)","Arabic (Saudi Arabia)","Chinese (Simplified)","Chinese (Traditional)","Italian"]}', '["AI Developer","Machine Learning Engineer","Data Scientist","AI Solutions Architect","Cloud Developer","Business Analyst"]', '2025-08-17T02:46:26.120376+00:00', '2025-08-17T02:46:26.120376+00:00') ON CONFLICT DO NOTHING;
INSERT INTO certification_info (id, exam_id, title, description, exam_code, level, validity, prerequisites, skills_measured, study_resources, exam_details, career_path, created_at, updated_at) VALUES ('c981cd53-130b-4703-b721-96e132c2e8a1', 'ai-102', 'Microsoft Certified: Azure AI Engineer Associate', 'This certification validates your expertise in building, managing, and deploying AI solutions that leverage Azure Cognitive Services, Azure Cognitive Search, and Microsoft Bot Framework.', 'AI-102', 'Associate', '2 years', '["Azure AI Fundamentals (AI-900) or equivalent knowledge","Experience with Azure services and workloads","Knowledge of programming languages (C#, Python, JavaScript)","Understanding of machine learning concepts and algorithms"]', '[{"category":"Plan and manage Azure Cognitive Services (15-20%)","weightage":18,"skills":["Plan and configure Azure Cognitive Services","Plan and configure Azure Cognitive Services pricing tiers","Plan and configure Azure Cognitive Services authentication","Plan and configure Azure Cognitive Services networking","Plan and configure Azure Cognitive Services monitoring"]},{"category":"Implement Computer Vision solutions (20-25%)","weightage":23,"skills":["Implement Azure Computer Vision solutions","Implement Azure Custom Vision solutions","Implement Azure Form Recognizer solutions","Implement Azure Video Indexer solutions","Implement Azure Face API solutions"]},{"category":"Implement Natural Language Processing solutions (20-25%)","weightage":23,"skills":["Implement Azure Language Understanding (LUIS) solutions","Implement Azure Language Service solutions","Implement Azure Speech Service solutions","Implement Azure Translator solutions","Implement Azure QnA Maker solutions"]},{"category":"Implement knowledge mining solutions (15-20%)","weightage":18,"skills":["Implement Azure Cognitive Search solutions","Implement Azure Cognitive Search indexing","Implement Azure Cognitive Search skills","Implement Azure Cognitive Search enrichment","Implement Azure Cognitive Search querying"]},{"category":"Implement conversational AI solutions (20-25%)","weightage":18,"skills":["Implement Azure Bot Service solutions","Implement Microsoft Bot Framework solutions","Implement Azure Bot Service authentication","Implement Azure Bot Service channels","Implement Azure Bot Service monitoring"]}]', '[{"title":"Microsoft Learn - AI-102 Learning Path","type":"Learning Path","url":"https://docs.microsoft.com/en-us/learn/certifications/exams/ai-102","description":"Official Microsoft learning path for Azure AI Engineer Associate"},{"title":"Azure AI Engineering Documentation","type":"Documentation","url":"https://docs.microsoft.com/en-us/azure/ai/","description":"Azure AI engineering documentation and best practices"},{"title":"Azure Cognitive Services Documentation","type":"Documentation","url":"https://docs.microsoft.com/en-us/azure/cognitive-services/","description":"Azure Cognitive Services documentation and implementation guides"},{"title":"Microsoft Bot Framework Documentation","type":"Documentation","url":"https://docs.microsoft.com/en-us/azure/bot-service/","description":"Microsoft Bot Framework documentation and development guides"},{"title":"Azure AI Engineer Practice Tests","type":"Practice Tests","url":"https://www.microsoft.com/en-us/learning/exam-AI-102.html","description":"Official Microsoft practice tests for AI-102"},{"title":"Azure AI Engineering Labs","type":"Hands-on Labs","url":"https://docs.microsoft.com/en-us/learn/paths/azure-ai-engineer/","description":"Hands-on labs for Azure AI engineering concepts"}]', '{"duration":"150 minutes","questions":"40-60 questions","passingScore":"700 out of 1000","cost":"$165 USD","languages":["English","Japanese","Korean","German","French","Spanish","Portuguese (Brazil)","Arabic (Saudi Arabia)","Chinese (Simplified)","Chinese (Traditional)","Italian"]}', '["Azure AI Engineer","AI Engineer","Machine Learning Engineer","AI Solutions Architect","Conversational AI Developer","Computer Vision Engineer","NLP Engineer","AI Developer"]', '2025-08-17T02:46:26.120376+00:00', '2025-08-17T02:46:26.120376+00:00') ON CONFLICT DO NOTHING;
INSERT INTO certification_info (id, exam_id, title, description, exam_code, level, validity, prerequisites, skills_measured, study_resources, exam_details, career_path, created_at, updated_at) VALUES ('71b8b0fd-8aac-4290-857d-d45823ea1a8a', 'az-900', 'Microsoft Certified: Azure Fundamentals', 'This certification is designed for candidates who are just beginning to work with cloud-based solutions and services or are new to Azure.', 'AZ-900', 'Fundamentals', '2 years', '["Basic knowledge of cloud computing concepts","General IT knowledge or experience"]', '[{"category":"Cloud Concepts (20-25%)","weightage":23,"skills":["Describe cloud computing","Describe the benefits of using cloud services","Describe cloud service types","Describe cloud deployment models"]},{"category":"Azure Architecture and Services (35-40%)","weightage":38,"skills":["Describe the core architectural components of Azure","Describe Azure compute and networking services","Describe Azure storage services","Describe Azure identity, access, and security"]},{"category":"Azure Management and Governance (30-35%)","weightage":33,"skills":["Describe cost management in Azure","Describe features and tools in Azure for governance and compliance","Describe features and tools for managing and deploying Azure resources","Describe monitoring tools in Azure"]},{"category":"Azure Security, Privacy, Compliance, and Trust (25-30%)","weightage":6,"skills":["Describe security capabilities in Azure","Describe identity governance capabilities in Azure","Describe privacy, compliance, and data protection standards in Azure"]}]', '[{"title":"Microsoft Learn - AZ-900 Learning Path","type":"Learning Path","url":"https://docs.microsoft.com/en-us/learn/certifications/exams/az-900","description":"Official Microsoft learning path for Azure Fundamentals"},{"title":"Azure Fundamentals Documentation","type":"Documentation","url":"https://docs.microsoft.com/en-us/azure/fundamentals/","description":"Azure fundamentals documentation and concepts"}]', '{"duration":"85 minutes","questions":"40-60 questions","passingScore":"700 out of 1000","cost":"$99 USD","languages":["English","Japanese","Korean","German","French","Spanish","Portuguese (Brazil)","Arabic (Saudi Arabia)","Chinese (Simplified)","Chinese (Traditional)","Italian"]}', '["Cloud Developer","Cloud Administrator","Solutions Architect","DevOps Engineer"]', '2025-08-17T02:46:26.120376+00:00', '2025-08-17T02:46:26.120376+00:00') ON CONFLICT DO NOTHING;
INSERT INTO certification_info (id, exam_id, title, description, exam_code, level, validity, prerequisites, skills_measured, study_resources, exam_details, career_path, created_at, updated_at) VALUES ('1166ad1e-fae1-4ace-85a3-ac45658699c7', 'az-204', 'Microsoft Certified: Azure Developer Associate', 'This certification validates your expertise in designing, building, testing, and maintaining cloud applications and services on Microsoft Azure.', 'AZ-204', 'Associate', '2 years', '["1-2 years of professional development experience","Experience with Microsoft Azure","Knowledge of at least one cloud-supported programming language","Understanding of Azure services and workloads, security, and governance"]', '[{"category":"Develop Azure compute solutions (25-30%)","weightage":28,"skills":["Implement IaaS solutions","Create Azure App Service web apps","Implement Azure Functions","Develop for Azure Container Instances","Implement Azure Container Apps"]},{"category":"Develop for Azure storage (15-20%)","weightage":18,"skills":["Develop solutions that use Azure Cosmos DB","Develop solutions that use Azure Blob Storage","Develop solutions that use Azure Files","Develop solutions that use Azure Storage Tables"]},{"category":"Implement Azure security (20-25%)","weightage":23,"skills":["Implement user authentication and authorization","Implement secure cloud solutions","Implement Azure Key Vault","Implement managed identities"]},{"category":"Monitor, troubleshoot, and optimize Azure solutions (15-20%)","weightage":18,"skills":["Implement caching for solutions","Troubleshoot solutions by using Application Insights","Implement code that handles transient faults","Implement monitoring and logging solutions"]},{"category":"Connect to and consume Azure services and third-party services (15-20%)","weightage":13,"skills":["Implement API Management","Develop event-based solutions","Develop message-based solutions","Implement Azure Event Grid"]}]', '[{"title":"Microsoft Learn - AZ-204 Learning Path","type":"Learning Path","url":"https://docs.microsoft.com/en-us/learn/certifications/exams/az-204","description":"Official Microsoft learning path for Azure Developer Associate"},{"title":"Azure Developer Documentation","type":"Documentation","url":"https://docs.microsoft.com/en-us/azure/developer/","description":"Azure development documentation and best practices"},{"title":"Azure Developer Practice Tests","type":"Practice Tests","url":"https://www.microsoft.com/en-us/learning/exam-AZ-204.html","description":"Official Microsoft practice tests for AZ-204"}]', '{"duration":"150 minutes","questions":"40-60 questions","passingScore":"700 out of 1000","cost":"$165 USD","languages":["English","Japanese","Korean","German","French","Spanish","Portuguese (Brazil)","Arabic (Saudi Arabia)","Chinese (Simplified)","Chinese (Traditional)","Italian"]}', '["Azure Developer","Cloud Developer","Full-Stack Developer","DevOps Engineer","Software Engineer"]', '2025-08-17T02:46:26.120376+00:00', '2025-08-17T02:46:26.120376+00:00') ON CONFLICT DO NOTHING;
INSERT INTO certification_info (id, exam_id, title, description, exam_code, level, validity, prerequisites, skills_measured, study_resources, exam_details, career_path, created_at, updated_at) VALUES ('97e1b9e2-b46c-4dae-9967-b0de7291bed7', 'az-400', 'Microsoft Certified: Azure DevOps Engineer Expert', 'This certification validates your expertise in combining people, process, and technologies to continuously deliver valuable products and services that meet end user needs and business objectives.', 'AZ-400', 'Expert', '2 years', '["Azure Administrator Associate (AZ-104) or Azure Developer Associate (AZ-204)","Experience with Azure DevOps or GitHub","Knowledge of Agile practices","Understanding of CI/CD pipelines and automation"]', '[{"category":"Configure processes and communications (10-15%)","weightage":13,"skills":["Configure activity work items","Configure process customization","Configure team collaboration tools","Configure feedback mechanisms"]},{"category":"Design and implement source control (15-20%)","weightage":18,"skills":["Design and implement a source control strategy","Plan and implement branching strategies","Configure and manage repositories","Integrate source control with tools and services"]},{"category":"Design and implement build and release pipelines (40-45%)","weightage":43,"skills":["Design and implement pipeline automation","Design and implement build strategies","Design and implement release strategies","Implement and manage build and release agents","Design and implement dependency management"]},{"category":"Develop a security and compliance plan (10-15%)","weightage":13,"skills":["Design and implement a security strategy","Implement security and compliance in Azure DevOps","Plan and implement compliance policies","Design and implement security policies"]},{"category":"Implement an instrumentation strategy (10-15%)","weightage":13,"skills":["Configure monitoring for a development environment","Configure system monitoring","Configure applica